window.__VANTA_DATA={"services": [{"id": "ai-search-visibility", "cat": "seo", "hero": true, "icon": "🤖", "name": "AI Search Visibility", "oneLiner": "Get recommended when customers ask ChatGPT, Gemini and Perplexity.", "model": "/mo", "value": "$500-2,500/mo", "en": {"headline": "Be the name AI recommends to your buyers", "subhead": "When your customers ask ChatGPT, Gemini or Perplexity who to use, your business should be the answer. We engineer your brand into those recommendations.", "forWho": "For: founders and operators losing buyers to AI assistants that never mention them", "includes": ["AI visibility audit across ChatGPT, Gemini and Perplexity", "The exact buyer prompts that should surface you, mapped", "Authority content rebuilt so models cite you, not competitors", "Structured data and entity signals AI engines actually read", "Monthly tracking of where and how AI names you"], "outcome": "You stop being invisible in the conversations where buying decisions now start. When someone asks an AI who to trust in your space, your name comes up first.", "cta": "See if AI recommends you", "problem": "Your buyers no longer start on Google. They ask an AI who to use, and right now it confidently recommends your competitors while your name never comes up. Every one of those answers is a sale that walked to someone else before you knew the conversation happened.", "howItWorks": [{"t": "Audit the answers", "d": "We run the real buyer prompts in your market across ChatGPT, Gemini and Perplexity to see exactly who gets recommended and where you stand."}, {"t": "Rebuild the signals", "d": "We fix the authority content, structured data and entity signals these models read so they have clear reasons to name you, not your competitors."}, {"t": "Track and tighten", "d": "We monitor how the AIs describe and rank you every month, then keep sharpening the inputs until your name leads the answer."}], "why": "We do not theorize about AI search, we operate in it. The same playbook we use to get our own brand surfaced by these engines is the one we run on yours, so you get the version that already works on a real business, not a slide deck.", "faq": [{"q": "Can you really influence what ChatGPT or Gemini says about me?", "a": "Yes. These models pull from the content, citations and structured signals around your brand. When we strengthen what they read about you, what they say about you changes. It is the inputs we control, and the inputs are what move the answer."}, {"q": "How is this different from regular SEO?", "a": "SEO fights for a blue link a buyer might click. AI visibility fights to be the single name the assistant speaks out loud. Different mechanics, different content, different signals, and the AI answer is increasingly the first one your buyer ever sees."}, {"q": "How fast will I see my name show up?", "a": "It depends on your starting authority and how crowded your space is, so we will not promise a date on a call. What we will do is show you exactly where you stand today and the work that closes the gap."}]}, "fr": {"headline": "Soyez le nom que l'IA recommande à vos clients", "subhead": "Quand vos clients demandent à ChatGPT, Gemini ou Perplexity qui choisir, votre entreprise devrait être la réponse. On vous intègre directement dans ces recommandations.", "forWho": "Pour : les entrepreneurs qui perdent des clients au profit d'IA qui ne les nomment jamais", "includes": ["Audit de votre visibilité sur ChatGPT, Gemini et Perplexity", "Les requêtes d'acheteurs qui devraient vous faire ressortir, identifiées", "Contenu d'autorité refait pour que les IA vous citent, pas vos concurrents", "Données structurées et signaux que les moteurs d'IA lisent vraiment", "Suivi mensuel de quand et comment l'IA vous nomme"], "outcome": "Vous cessez d'être invisible là où les décisions d'achat commencent maintenant. Quand on demande à une IA à qui faire confiance dans votre domaine, votre nom sort en premier.", "cta": "Voir si l'IA vous recommande", "problem": "Vos clients ne commencent plus sur Google. Ils demandent à une IA qui choisir, et en ce moment elle recommande vos concurrents avec assurance pendant que votre nom ne sort jamais. Chacune de ces réponses, c'est une vente partie chez quelqu'un d'autre avant même que vous sachiez que la conversation a eu lieu.", "howItWorks": [{"t": "Auditer les réponses", "d": "On teste les vraies requêtes d'acheteurs de votre marché sur ChatGPT, Gemini et Perplexity pour voir exactement qui est recommandé et où vous vous situez."}, {"t": "Refaire les signaux", "d": "On corrige le contenu d'autorité, les données structurées et les signaux que ces modèles lisent pour leur donner des raisons claires de vous nommer, pas vos concurrents."}, {"t": "Suivre et resserrer", "d": "On surveille chaque mois comment les IA vous décrivent et vous classent, puis on affine les éléments jusqu'à ce que votre nom mène la réponse."}], "why": "On ne théorise pas sur la recherche par IA, on opère dedans. La même méthode qu'on utilise pour faire ressortir notre propre marque dans ces moteurs, c'est celle qu'on applique à la vôtre. Vous obtenez la version qui fonctionne déjà sur une vraie entreprise, pas une présentation.", "faq": [{"q": "Pouvez-vous vraiment influencer ce que ChatGPT ou Gemini dit de moi ?", "a": "Oui. Ces modèles puisent dans le contenu, les citations et les signaux structurés autour de votre marque. Quand on renforce ce qu'ils lisent sur vous, ce qu'ils disent de vous change. Ce sont ces éléments qu'on contrôle, et ce sont eux qui font bouger la réponse."}, {"q": "En quoi est-ce différent du SEO classique ?", "a": "Le SEO se bat pour un lien bleu que l'acheteur pourrait cliquer. La visibilité IA se bat pour être le seul nom que l'assistant prononce à voix haute. Mécaniques différentes, contenu différent, signaux différents, et la réponse de l'IA est de plus en plus la première que votre client voit."}, {"q": "En combien de temps mon nom va-t-il apparaître ?", "a": "Ça dépend de votre autorité de départ et de l'encombrement de votre marché, donc on ne promettra pas de date sur un appel. Ce qu'on fera, c'est vous montrer exactement où vous en êtes aujourd'hui et le travail qui referme l'écart."}]}, "nameFr": "Visibilité dans les recherches IA"}, {"id": "local-seo-blog", "cat": "seo", "hero": true, "icon": "📈", "name": "Local SEO Blog", "oneLiner": "Be found on Google AND AI, for less than one extra sale a month.", "model": "/mo", "value": "$97-297/mo", "flow": "niches", "en": {"headline": "Become the local business Google and AI recommend", "subhead": "We publish search-built blog content month after month so your business shows up when nearby customers search on Google, and when they ask ChatGPT or Gemini who to trust.", "forWho": "For: local service businesses that want steady inbound customers without chasing ads.", "includes": ["Keyword and AI-prompt research for your service area", "Monthly local articles written to rank and convert", "On-page SEO, internal links, and local schema", "Optimized to be cited by ChatGPT, Gemini, and AI search", "Plain monthly report showing rankings and traffic"], "outcome": "You stop depending on ads and word of mouth, and start owning the searches your future customers already make. Every month your visibility compounds, on Google and in the AI tools buyers now trust.", "cta": "See if AI recommends you", "problem": "Right now your future customers are searching for exactly what you sell, and a competitor's page is the one answering them. When buyers ask Google or ChatGPT who to hire near them, your name never comes up, so you stay stuck paying for ads or waiting on referrals.", "howItWorks": [{"t": "Map the searches", "d": "We research the exact Google searches and AI prompts your local buyers use, then build a content plan around the ones most likely to bring you ready-to-buy customers."}, {"t": "Publish every month", "d": "We write and publish local articles tuned to rank and convert, with on-page SEO, internal links, and local schema so Google and AI engines can read and recommend you."}, {"t": "Compound and report", "d": "Each new article stacks on the last, your visibility grows month over month, and you get a plain report showing exactly which rankings and traffic are climbing."}], "why": "This is the same content engine we run on our own properties to win local and AI search, not a theory we read about. We build for both the way Google ranks today and the way ChatGPT and Gemini now answer buyers, so your visibility keeps compounding instead of resetting every month.", "faq": [{"q": "How long until I see results?", "a": "Local SEO compounds rather than spikes. Early articles usually start gaining traction within a few months, and the more we publish, the faster new pieces rank, because authority builds on itself."}, {"q": "How is this different from running ads?", "a": "Ads stop the second you stop paying. Content you own keeps ranking and getting cited by AI long after it is published, so you build an asset instead of renting attention."}, {"q": "Do I have to write or approve anything?", "a": "No writing on your end. We handle research, drafting, and publishing, and you can review before anything goes live if you want. Most owners just read the monthly report."}]}, "fr": {"headline": "Devenez le commerce local que Google et l'IA recommandent", "subhead": "On publie du contenu de blogue pensé pour la recherche, mois après mois, pour que votre entreprise ressorte quand un client du coin cherche sur Google, et quand il demande à ChatGPT ou Gemini à qui faire confiance.", "forWho": "Pour : les entreprises de services locaux qui veulent un flux constant de clients sans courir après la pub.", "includes": ["Recherche de mots-clés et de requêtes IA pour votre secteur", "Des articles locaux chaque mois, écrits pour se classer et convertir", "SEO sur la page, liens internes et données structurées locales", "Optimisé pour être cité par ChatGPT, Gemini et la recherche IA", "Rapport mensuel clair sur vos positions et votre trafic"], "outcome": "Vous arrêtez de dépendre de la pub et du bouche-à-oreille, et vous prenez le contrôle des recherches que vos futurs clients font déjà. Chaque mois, votre visibilité s'accumule, sur Google et dans les outils IA auxquels les acheteurs se fient maintenant.", "cta": "Voir si l'IA vous recommande", "problem": "En ce moment, vos futurs clients cherchent exactement ce que vous offrez, et c'est la page d'un concurrent qui leur répond. Quand un acheteur demande à Google ou à ChatGPT qui engager près de chez lui, votre nom ne sort jamais, alors vous restez coincé à payer de la pub ou à attendre des références.", "howItWorks": [{"t": "Cibler les recherches", "d": "On analyse les recherches Google et les requêtes IA précises que vos clients locaux utilisent, puis on bâtit un plan de contenu autour de celles qui amènent les clients les plus prêts à acheter."}, {"t": "Publier chaque mois", "d": "On rédige et on publie des articles locaux conçus pour se classer et convertir, avec SEO sur la page, liens internes et données structurées locales pour que Google et l'IA puissent vous lire et vous recommander."}, {"t": "Accumuler et mesurer", "d": "Chaque nouvel article s'ajoute au précédent, votre visibilité grandit mois après mois, et vous recevez un rapport clair montrant exactement quelles positions et quel trafic progressent."}], "why": "C'est le même moteur de contenu qu'on fait rouler sur nos propres sites pour gagner la recherche locale et la recherche IA, pas une théorie lue quelque part. On construit à la fois pour la façon dont Google classe aujourd'hui et pour la façon dont ChatGPT et Gemini répondent maintenant aux acheteurs, alors votre visibilité continue de s'accumuler au lieu de repartir à zéro chaque mois.", "faq": [{"q": "Combien de temps avant de voir des résultats ?", "a": "Le SEO local s'accumule, il ne fait pas de pic. Les premiers articles commencent souvent à prendre de la traction en quelques mois, et plus on publie, plus les nouveaux articles se classent vite, parce que l'autorité se construit sur elle-même."}, {"q": "En quoi c'est différent de la pub ?", "a": "La pub s'arrête à la seconde où vous arrêtez de payer. Le contenu qui vous appartient continue de se classer et d'être cité par l'IA longtemps après sa publication, alors vous bâtissez un actif au lieu de louer de l'attention."}, {"q": "Est-ce que je dois écrire ou approuver quelque chose ?", "a": "Aucune rédaction de votre côté. On s'occupe de la recherche, de la rédaction et de la publication, et vous pouvez réviser avant la mise en ligne si vous le voulez. La plupart des propriétaires lisent simplement le rapport mensuel."}]}, "nameFr": "Blogue SEO local"}, {"id": "content-network", "cat": "seo", "hero": false, "icon": "🕸️", "name": "Content Network", "oneLiner": "A network of ranking content sites that funnels traffic to you.", "model": "/mo", "value": "$300-1,500/mo", "en": {"headline": "Own a fleet of sites that feed you traffic", "subhead": "We build and run a network of ranking content sites in your niche, each one engineered to capture search demand and route those buyers straight to your offer. It is the same traffic engine we point at our own money.", "forWho": "For: operators who want a steady, owned traffic source instead of renting clicks from ads.", "includes": ["A cluster of niche content sites built and hosted for you", "Keyword and topic mapping around your buyer's search intent", "Ongoing articles published and optimized to rank", "Internal funnels and links that push visitors to your offer", "Monthly ranking and traffic reporting you can read at a glance"], "outcome": "You stop depending on ad spend for every click and start owning the pipes that bring buyers to you. As the network ages, the traffic compounds and the cost per visitor keeps dropping.", "cta": "Get started", "problem": "Every buyer you have ever gotten came from a click you had to pay for, so the day you pause ads is the day your pipeline goes quiet. You are renting your traffic, and the landlord keeps raising the rent.", "howItWorks": [{"t": "Map the demand", "d": "We research what your buyers are actually searching for and turn that intent into a topic and keyword plan for a cluster of sites."}, {"t": "Build the network", "d": "We stand up and host the content sites, then publish ranking articles on a steady cadence so the network grows real search visibility."}, {"t": "Route to your offer", "d": "We wire internal funnels and links across the network so every visitor we earn gets pushed toward booking or buying from you."}], "why": "This is the exact traffic engine we run for our own offers, not a theory we are testing on you. Owned content compounds while paid clicks reset to zero the moment you stop spending, so the asset only gets stronger as it ages.", "faq": [{"q": "How is this different from just hiring a content agency?", "a": "An agency hands you articles and walks away. We build, host, and operate the whole network as an owned asset and aim it at your offer, so you end up with traffic infrastructure, not a pile of blog posts."}, {"q": "How long until I see real traffic?", "a": "Ranking is a compounding game, so the early weeks are about building and indexing while momentum stacks. We focus on intent-rich topics first so the traffic that does arrive is buyers, not tourists, and it keeps climbing as the network ages."}, {"q": "Do I own the sites or do you?", "a": "You own the network. It is built as your asset so the traffic and the equity stay with you, even though we run the day to day for you."}]}, "fr": {"headline": "Possédez un réseau de sites qui vous alimente en trafic", "subhead": "On bâtit et on opère un réseau de sites de contenu qui se classent dans votre niche, chacun conçu pour capter la demande de recherche et diriger ces acheteurs directement vers votre offre. C'est le même moteur de trafic qu'on pointe vers notre propre argent.", "forWho": "Pour : les opérateurs qui veulent une source de trafic durable et bien à eux au lieu de louer des clics par publicité.", "includes": ["Une grappe de sites de contenu de niche, bâtie et hébergée pour vous", "Cartographie des mots-clés et des sujets selon l'intention de vos acheteurs", "Des articles publiés et optimisés en continu pour se classer", "Tunnels et liens internes qui poussent les visiteurs vers votre offre", "Rapport mensuel de classement et de trafic, clair en un coup d'œil"], "outcome": "Vous arrêtez de dépendre du budget publicitaire pour chaque clic et vous commencez à posséder les conduits qui amènent les acheteurs vers vous. Plus le réseau vieillit, plus le trafic s'accumule et plus le coût par visiteur baisse.", "cta": "Commencer", "problem": "Chaque acheteur que vous avez obtenu vient d'un clic que vous avez dû payer, alors le jour où vous arrêtez la publicité, votre pipeline devient silencieux. Vous louez votre trafic, et le propriétaire continue de monter le loyer.", "howItWorks": [{"t": "Cartographier la demande", "d": "On recherche ce que vos acheteurs tapent réellement et on transforme cette intention en un plan de sujets et de mots-clés pour une grappe de sites."}, {"t": "Bâtir le réseau", "d": "On met en ligne et on héberge les sites de contenu, puis on publie des articles qui se classent à un rythme constant pour que le réseau gagne une vraie visibilité de recherche."}, {"t": "Diriger vers votre offre", "d": "On câble des tunnels et des liens internes dans tout le réseau pour que chaque visiteur gagné soit poussé à réserver ou à acheter chez vous."}], "why": "C'est exactement le moteur de trafic qu'on opère pour nos propres offres, pas une théorie qu'on teste sur vous. Le contenu que vous possédez s'accumule, tandis que les clics payés retombent à zéro dès que vous arrêtez de dépenser, donc l'actif ne fait que se renforcer avec le temps.", "faq": [{"q": "En quoi est-ce différent d'engager une simple agence de contenu ?", "a": "Une agence vous remet des articles et s'en va. Nous, on bâtit, on héberge et on opère tout le réseau comme un actif que vous possédez, pointé vers votre offre, alors vous repartez avec une infrastructure de trafic, pas une pile de billets de blogue."}, {"q": "Combien de temps avant de voir un vrai trafic ?", "a": "Le classement est un jeu qui s'accumule, alors les premières semaines servent à bâtir et à indexer pendant que l'élan se construit. On vise d'abord les sujets à forte intention pour que le trafic qui arrive soit des acheteurs, pas des touristes, et il continue de grimper à mesure que le réseau vieillit."}, {"q": "Est-ce que je possède les sites ou est-ce vous ?", "a": "C'est vous qui possédez le réseau. Il est bâti comme votre actif, alors le trafic et la valeur vous restent, même si on s'occupe du quotidien à votre place."}]}, "nameFr": "Réseau de contenu"}, {"id": "brand-serp", "cat": "seo", "hero": false, "icon": "🛡️", "name": "Brand SERP & Reputation", "oneLiner": "Own your name in Google. Push scrapers and impersonators down.", "model": "/mo", "value": "$500-3,000/mo", "en": {"headline": "Own page one when someone Googles your name", "subhead": "When a buyer searches your brand, they should find you, not scrapers, impersonators, or a fake clone of your store. We take control of your branded results and keep it.", "forWho": "For: brands whose name gets hijacked by knockoff sites, marketplaces, and copycats in Google", "includes": ["Full audit of every result that ranks for your brand name", "Sitelinks, knowledge panel, and rich results set up correctly", "Scraper, impersonator, and copycat listings pushed down and out", "Owned assets built to occupy the top of page one", "Ongoing monitoring so new threats get caught fast"], "outcome": "Your customers land on you instead of a counterfeit, every branded search becomes a closed sale, and your reputation stops leaking to people riding your name.", "cta": "Get started", "problem": "Your hottest buyers already know your name and type it straight into Google, but the results hand them scrapers, marketplaces, and copycat stores sitting right next to you. Every one of those listings is a customer you paid to create getting intercepted and cashed out by someone else.", "howItWorks": [{"t": "Map the battlefield", "d": "We pull every result that currently ranks for your brand name and flag which ones are scrapers, impersonators, copycats, or simply wasted space you should own."}, {"t": "Lock your own real estate", "d": "We set up your sitelinks, knowledge panel, and rich results and build owned assets engineered to occupy the top slots so there is no room left for the impostors."}, {"t": "Hold the line", "d": "We push the bad listings down, keep monitoring your branded results, and catch new threats fast before they ever cost you a sale."}], "why": "We run our own brands through the exact same searches, so we are not theorizing about your branded results, we are defending ours every single day. Owning your own name is the cheapest, highest intent traffic you will ever touch, and we treat it that way.", "faq": [{"q": "Can you actually remove the scraper and copycat sites from Google?", "a": "We do not delete other people's pages, we outrank and outweigh them. By building and optimizing assets you own, the impostors get pushed off the top of page one where almost nobody scrolls, and where they can no longer steal your buyers."}, {"q": "I am a small brand. Is this only for big companies?", "a": "Smaller brands are often the easiest wins, because the people searching your name already want you specifically. The smaller you are, the more every intercepted branded search hurts, so cleaning up that search is one of the fastest returns you can get."}, {"q": "How long before my branded results look clean?", "a": "Setup of your owned assets, sitelinks, and structured results happens fast, and you see the top of page one start to shift as those assets get indexed and ranked. We keep monitoring after that, because brand search is something you hold, not something you fix once."}]}, "fr": {"headline": "Dominez la première page quand on cherche votre nom dans Google", "subhead": "Quand un acheteur cherche votre marque, il doit vous trouver, vous, pas des scrapers, des imitateurs ou un faux clone de votre boutique. On reprend le contrôle de vos résultats de marque et on le garde.", "forWho": "Pour : les marques dont le nom se fait détourner par des sites de contrefaçon, des marketplaces et des copieurs dans Google", "includes": ["Audit complet de chaque résultat qui ressort pour le nom de votre marque", "Liens annexes, panneau de connaissances et résultats enrichis bien configurés", "Scrapers, imitateurs et copieurs repoussés et sortis du haut de la page", "Des actifs qui vous appartiennent, bâtis pour occuper le sommet de la première page", "Surveillance continue pour attraper vite toute nouvelle menace"], "outcome": "Vos clients atterrissent sur vous plutôt que sur une contrefaçon, chaque recherche de marque devient une vente conclue, et votre réputation arrête de fuir vers ceux qui surfent sur votre nom.", "cta": "Commencer", "problem": "Vos meilleurs acheteurs connaissent déjà votre nom et le tapent directement dans Google, mais les résultats leur servent des scrapers, des marketplaces et des boutiques copieuses assises juste à côté de vous. Chacune de ces fiches, c'est un client que vous avez payé pour créer qui se fait intercepter et encaisser par quelqu'un d'autre.", "howItWorks": [{"t": "Cartographier le terrain", "d": "On sort chaque résultat qui ressort actuellement pour le nom de votre marque et on identifie lesquels sont des scrapers, des imitateurs, des copieurs ou simplement de l'espace gaspillé que vous devriez posséder."}, {"t": "Verrouiller votre territoire", "d": "On configure vos liens annexes, votre panneau de connaissances et vos résultats enrichis, et on bâtit des actifs qui vous appartiennent, conçus pour occuper les premières places afin qu'il ne reste plus de place pour les imposteurs."}, {"t": "Tenir la ligne", "d": "On repousse les mauvaises fiches vers le bas, on surveille vos résultats de marque en continu et on attrape vite les nouvelles menaces avant qu'elles vous coûtent une vente."}], "why": "On fait passer nos propres marques par exactement les mêmes recherches, alors on ne théorise pas sur vos résultats de marque, on défend les nôtres chaque jour. Posséder votre propre nom, c'est le trafic le plus intentionnel et le moins cher que vous toucherez jamais, et on le traite comme tel.", "faq": [{"q": "Pouvez-vous vraiment enlever les sites scrapers et copieurs de Google ?", "a": "On ne supprime pas les pages des autres, on les surclasse. En bâtissant et en optimisant des actifs qui vous appartiennent, les imposteurs se font repousser hors du haut de la première page, là où presque personne ne descend, et où ils ne peuvent plus vous voler vos acheteurs."}, {"q": "Je suis une petite marque. Est-ce réservé aux grandes entreprises ?", "a": "Les plus petites marques sont souvent les gains les plus faciles, parce que les gens qui cherchent votre nom vous veulent déjà, vous précisément. Plus vous êtes petit, plus chaque recherche de marque interceptée fait mal, alors nettoyer cette recherche est l'un des retours les plus rapides que vous pouvez obtenir."}, {"q": "Combien de temps avant que mes résultats de marque soient propres ?", "a": "La mise en place de vos actifs, de vos liens annexes et de vos résultats structurés se fait vite, et vous voyez le haut de la première page commencer à bouger à mesure que ces actifs sont indexés et classés. On continue de surveiller ensuite, parce que la recherche de marque, c'est quelque chose qu'on tient, pas quelque chose qu'on règle une seule fois."}]}, "nameFr": "SERP de marque et réputation"}, {"id": "bilingual-seo", "cat": "seo", "hero": false, "icon": "🌐", "name": "Bilingual SEO (FR/EN)", "oneLiner": "Rank in both languages your market actually searches.", "model": "/mo", "value": "$300-1,500/mo", "en": {"headline": "Own page one in French and English at once", "subhead": "Your market searches in two languages, and right now half of them never find you. We make you the answer they land on, in both.", "forWho": "For: businesses serving a bilingual market who only rank in one language and are losing the other half.", "includes": ["Keyword research mapped separately for FR and EN intent", "Properly localized pages, not machine-translated copies", "Hreflang and technical setup so Google serves the right version", "Content built to rank in both languages every month", "Monthly tracking of rankings and traffic per language"], "outcome": "You stop leaving half your market to competitors and start capturing every search, in whichever language your customer types. One business, two doors, both open.", "cta": "Get started", "problem": "You rank fine in one language and almost nowhere in the other, so every search done in the language you neglect quietly hands a customer to a competitor. You are paying to serve a bilingual market while only showing up for half of it.", "howItWorks": [{"t": "Map both intents", "d": "We research how your market actually searches in each language, because the words, questions, and habits are rarely a straight translation."}, {"t": "Build localized pages", "d": "We write and structure real pages in each language with proper hreflang, so Google serves the right version to the right searcher instead of guessing."}, {"t": "Publish and track per language", "d": "We ship content every month and report rankings and traffic separately for FR and EN, so you can see both doors filling up."}], "why": "This is the same bilingual SEO engine we run on our own properties in a French and English market, so you are getting the machine we trust to capture our own traffic, not a translated afterthought bolted on at the end.", "faq": [{"q": "Can't I just translate my existing pages?", "a": "Translation copies your words, not your customer's search behavior. A translated page often misses the actual phrases people type in the second language, so we localize intent and content rather than mirror text word for word."}, {"q": "Will two language versions hurt my rankings or look like duplicate content?", "a": "No, when it is set up correctly. Proper hreflang and technical structure tell Google these are deliberate language versions of the same business, which is exactly what we configure so each version ranks for its own audience."}, {"q": "How long until I see results in the second language?", "a": "SEO compounds, so the second language usually starts moving over a few months as new pages get indexed and earn authority. We report progress per language every month so you always know which door is opening and how fast."}]}, "fr": {"headline": "Dominez la première page en français et en anglais à la fois", "subhead": "Votre marché cherche dans deux langues, et en ce moment la moitié ne vous trouve jamais. On fait de vous la réponse sur laquelle ils tombent, dans les deux.", "forWho": "Pour : les entreprises d'un marché bilingue qui ne ressortent que dans une seule langue et perdent l'autre moitié.", "includes": ["Recherche de mots-clés bâtie séparément selon l'intention FR et EN", "Des pages réellement localisées, pas des copies traduites à la machine", "Configuration hreflang et technique pour que Google serve la bonne version", "Du contenu conçu pour se classer dans les deux langues chaque mois", "Suivi mensuel des positions et du trafic par langue"], "outcome": "Vous arrêtez de laisser la moitié de votre marché à la concurrence et vous captez chaque recherche, peu importe la langue que votre client tape. Une entreprise, deux portes, les deux ouvertes.", "cta": "Commencer", "problem": "Vous ressortez bien dans une langue et presque nulle part dans l'autre, alors chaque recherche faite dans la langue que vous négligez remet discrètement un client à un concurrent. Vous payez pour servir un marché bilingue tout en n'apparaissant que pour la moitié.", "howItWorks": [{"t": "Cartographier les deux intentions", "d": "On analyse comment votre marché cherche réellement dans chaque langue, parce que les mots, les questions et les habitudes sont rarement une simple traduction."}, {"t": "Bâtir des pages localisées", "d": "On rédige et structure de vraies pages dans chaque langue avec le hreflang bien configuré, pour que Google serve la bonne version à la bonne personne au lieu de deviner."}, {"t": "Publier et suivre par langue", "d": "On publie du contenu chaque mois et on rapporte les positions et le trafic séparément en FR et en EN, pour que vous voyiez vos deux portes se remplir."}], "why": "C'est le même moteur de référencement bilingue qu'on fait rouler sur nos propres propriétés dans un marché français et anglais, alors vous obtenez la machine en qui on a confiance pour capter notre propre trafic, pas une traduction ajoutée à la dernière minute.", "faq": [{"q": "Je ne peux pas simplement traduire mes pages existantes ?", "a": "La traduction copie vos mots, pas le comportement de recherche de votre client. Une page traduite manque souvent les vraies expressions que les gens tapent dans la deuxième langue, alors on localise l'intention et le contenu au lieu de calquer le texte mot à mot."}, {"q": "Deux versions linguistiques vont-elles nuire à mes positions ou créer du contenu dupliqué ?", "a": "Non, quand c'est bien configuré. Un hreflang et une structure technique corrects indiquent à Google qu'il s'agit de versions linguistiques voulues de la même entreprise, et c'est exactement ce qu'on met en place pour que chaque version se classe pour son propre public."}, {"q": "Combien de temps avant de voir des résultats dans la deuxième langue ?", "a": "Le référencement s'accumule avec le temps, alors la deuxième langue commence habituellement à bouger sur quelques mois, à mesure que les nouvelles pages sont indexées et gagnent en autorité. On rapporte les progrès par langue chaque mois pour que vous sachiez toujours quelle porte s'ouvre et à quelle vitesse."}]}, "nameFr": "SEO bilingue (FR/EN)"}, {"id": "exclusive-leads", "cat": "leads", "hero": true, "icon": "🎯", "name": "Exclusive Leads (Done-For-You)", "oneLiner": "Exclusive, qualified leads. You only pay for the real ones.", "model": "PPR", "value": "$1,500-3,500/mo or per lead", "en": {"headline": "Qualified leads sent only to you, never shared", "subhead": "We run the same lead machine that fills our own pipeline and route every qualified prospect straight to you. No shared lists, no recycled contacts, no fighting five other companies for the same person.", "forWho": "For: service businesses and contractors who close on the phone and want their calendar full of ready-to-buy prospects.", "includes": ["Done-for-you ad and funnel build, fully managed", "Strict qualification so only real buyers reach you", "Leads delivered exclusively to your business, never resold", "Instant delivery by text and email the moment they convert", "You only count leads that actually fit your criteria"], "outcome": "You stop chasing tire-kickers and start working a steady flow of exclusive prospects who asked to hear from you. We carry the risk of generating them, you focus on closing.", "cta": "Get started", "problem": "You are buying leads that three other companies bought too, so you race to call first and still get ghosted by people who never really wanted you. The list is recycled, half the numbers are dead, and you are paying to compete for strangers instead of talking to buyers.", "howItWorks": [{"t": "We build the machine", "d": "We set up the ads, targeting, and funnel that pull in people actively looking for what you sell, all managed by us."}, {"t": "We qualify hard", "d": "Every prospect passes a strict filter for budget, intent, and fit before they ever count as a lead for you."}, {"t": "You get them first", "d": "The instant someone qualifies, they hit your phone and inbox exclusively, sent to no one else, ready for you to close."}], "why": "This is not a list we resell, it is the same acquisition engine we run to fill our own calendar, pointed at your business. When we have to live or die by the leads ourselves, we build them to actually convert, not just to hit a count.", "faq": [{"q": "How are these different from the leads I already buy?", "a": "Your current leads are shared and recycled, sold to whoever pays. Ours go to your business only, never to a competitor, and they are qualified before they reach you so you talk to buyers instead of dialing dead numbers."}, {"q": "What does exclusive actually mean?", "a": "It means the prospect is sent to you and no one else, ever. We do not resell, rotate, or repackage them. When a qualified lead converts, they land on your phone alone."}, {"q": "What if a lead does not fit my criteria?", "a": "Then it does not count. We set the qualification rules with you up front, and you only count the leads that match what you actually want to close. The risk of generating them sits with us, not you."}]}, "fr": {"headline": "Des leads qualifiés juste pour vous, jamais partagés", "subhead": "On fait rouler la même machine à leads qui remplit notre propre pipeline et on vous envoie chaque prospect qualifié directement. Aucune liste partagée, aucun contact recyclé, personne d'autre qui se bat pour le même client.", "forWho": "Pour : les entreprises de services et les entrepreneurs qui closent au téléphone et veulent un agenda rempli de prospects prêts à acheter.", "includes": ["Publicités et tunnel bâtis et gérés de A à Z pour vous", "Qualification stricte pour que seuls les vrais acheteurs vous parlent", "Leads livrés en exclusivité à votre entreprise, jamais revendus", "Livraison instantanée par texto et courriel dès qu'ils convertissent", "Vous comptez seulement les leads qui collent vraiment à vos critères"], "outcome": "Vous arrêtez de courir après les curieux et vous travaillez un flux constant de prospects exclusifs qui ont demandé à vous parler. On porte le risque de les générer, vous vous concentrez sur le closing.", "cta": "Commencer", "problem": "Vous achetez des leads que trois autres entreprises ont achetés aussi, alors vous courez pour appeler en premier et vous vous faites quand même ignorer par des gens qui ne vous voulaient jamais vraiment. La liste est recyclée, la moitié des numéros sont morts, et vous payez pour vous battre sur des inconnus au lieu de parler à des acheteurs.", "howItWorks": [{"t": "On bâtit la machine", "d": "On monte les publicités, le ciblage et le tunnel qui attirent des gens qui cherchent activement ce que vous vendez, le tout géré par nous."}, {"t": "On qualifie serré", "d": "Chaque prospect passe un filtre strict de budget, d'intention et de compatibilité avant de compter comme un lead pour vous."}, {"t": "Vous les avez en premier", "d": "Dès qu'une personne se qualifie, elle arrive sur votre téléphone et votre courriel en exclusivité, envoyée à personne d'autre, prête à closer."}], "why": "Ce n'est pas une liste qu'on revend, c'est le même moteur d'acquisition qu'on fait rouler pour remplir notre propre agenda, pointé vers votre entreprise. Quand on doit vivre ou mourir par les leads nous-mêmes, on les bâtit pour qu'ils convertissent vraiment, pas juste pour atteindre un chiffre.", "faq": [{"q": "En quoi c'est différent des leads que j'achète déjà ?", "a": "Vos leads actuels sont partagés et recyclés, vendus à quiconque paie. Les nôtres vont à votre entreprise seulement, jamais à un concurrent, et ils sont qualifiés avant de vous arriver, donc vous parlez à des acheteurs au lieu de composer des numéros morts."}, {"q": "Ça veut dire quoi, exclusif, concrètement ?", "a": "Ça veut dire que le prospect vous est envoyé à vous et à personne d'autre, jamais. On ne revend pas, on ne fait pas tourner et on ne reconditionne pas. Quand un lead qualifié convertit, il atterrit sur votre téléphone seulement."}, {"q": "Et si un lead ne colle pas à mes critères ?", "a": "Alors il ne compte pas. On établit les règles de qualification avec vous dès le départ, et vous comptez seulement les leads qui collent à ce que vous voulez vraiment closer. Le risque de les générer est sur nos épaules, pas les vôtres."}]}, "nameFr": "Leads exclusifs (clé en main)"}, {"id": "pay-per-result", "cat": "leads", "hero": false, "icon": "💸", "name": "Pay-Per-Result Lead Gen", "oneLiner": "No leads, no fee. The risk is on us.", "model": "PPR", "value": "$40-200/lead", "en": {"headline": "No leads, no fee. We carry the risk, you keep the bookings.", "subhead": "You only pay when a qualified lead lands in your inbox. We front the ad spend, the funnel, and the work, so the only thing you risk is being too busy.", "forWho": "For: service businesses tired of paying agencies that promise leads and deliver invoices.", "includes": ["Done-for-you ad campaigns we fund and manage", "Custom landing page and lead capture built to convert", "Lead qualification so you only get real buyers", "Real-time lead delivery to your phone or CRM", "Live dashboard tracking every lead and its source"], "outcome": "You wake up to a pipeline of qualified prospects instead of a marketing bill. If we do not produce, you do not pay, which is exactly why we obsess over results.", "cta": "Get started", "problem": "You have paid agencies before and walked away with a stack of invoices and almost nothing to show for it. Every month the retainer comes out whether the phone rings or not, and the risk sits entirely on your side of the table.", "howItWorks": [{"t": "We build and fund", "d": "We design the landing page, build the funnel, and put our own money behind the ad campaigns before you pay anything."}, {"t": "We qualify each lead", "d": "Every inquiry gets screened against your criteria so only real buyers ready to book reach you."}, {"t": "You pay per lead", "d": "Qualified leads hit your phone or CRM in real time, and you are billed only for the ones that count."}], "why": "This works because we run the exact same machine on our own businesses before we ever point it at yours, so we are not testing theories on your dime. When we only get paid for qualified leads, our incentive is welded to yours instead of to a monthly retainer.", "faq": [{"q": "What counts as a qualified lead?", "a": "We agree on the criteria with you up front, things like service requested, location, and intent to buy, and you are only billed for leads that meet them. Tire kickers and wrong numbers are on us, not you."}, {"q": "Who pays for the ad spend?", "a": "We do. We front the entire ad budget along with the funnel and the build, so you carry zero upfront cost and zero media risk."}, {"q": "How fast do leads start coming in?", "a": "Once the funnel and campaigns are live, leads typically begin flowing within the first couple of weeks as the ads gather data and the targeting sharpens. We will be straight with you about timing on the call."}]}, "fr": {"headline": "Pas de prospects, pas de frais. On assume le risque, vous gardez les rendez-vous.", "subhead": "Vous payez seulement quand un prospect qualifié arrive dans votre boîte de réception. On avance le budget publicitaire, l'entonnoir et le travail, donc le seul risque que vous courez, c'est d'être trop occupé.", "forWho": "Pour : les entreprises de services fatiguées de payer des agences qui promettent des prospects et qui livrent des factures.", "includes": ["Campagnes publicitaires clés en main qu'on finance et qu'on gère", "Page d'atterrissage et capture de prospects conçues pour convertir", "Qualification des prospects pour ne recevoir que de vrais acheteurs", "Livraison des prospects en temps réel sur votre téléphone ou votre CRM", "Tableau de bord en direct qui suit chaque prospect et sa source"], "outcome": "Vous vous réveillez avec un pipeline de prospects qualifiés au lieu d'une facture de marketing. Si on ne produit pas, vous ne payez pas, et c'est exactement pour ça qu'on est obsédés par les résultats.", "cta": "Commencer", "problem": "Vous avez déjà payé des agences et vous êtes reparti avec une pile de factures et presque rien d'autre. Chaque mois, le forfait sort de votre compte que le téléphone sonne ou non, et tout le risque repose sur vos épaules.", "howItWorks": [{"t": "On bâtit et on finance", "d": "On conçoit la page d'atterrissage, on construit l'entonnoir et on met notre propre argent derrière les campagnes publicitaires avant que vous payiez quoi que ce soit."}, {"t": "On qualifie chaque prospect", "d": "Chaque demande est filtrée selon vos critères pour que seuls de vrais acheteurs prêts à réserver se rendent jusqu'à vous."}, {"t": "Vous payez par prospect", "d": "Les prospects qualifiés arrivent sur votre téléphone ou votre CRM en temps réel, et vous payez seulement pour ceux qui comptent."}], "why": "Ça fonctionne parce qu'on fait rouler la même machine sur nos propres entreprises avant de la pointer vers la vôtre, alors on ne teste pas des théories à vos dépens. Quand on est payés seulement pour des prospects qualifiés, notre intérêt est soudé au vôtre plutôt qu'à un forfait mensuel.", "faq": [{"q": "Qu'est-ce qui compte comme prospect qualifié ?", "a": "On établit les critères avec vous dès le départ, comme le service demandé, la région et l'intention d'achat, et vous payez seulement pour les prospects qui les respectent. Les curieux et les mauvais numéros, c'est sur nous, pas sur vous."}, {"q": "Qui paie le budget publicitaire ?", "a": "C'est nous. On avance la totalité du budget publicitaire en plus de l'entonnoir et de la construction, donc vous n'avez aucun coût initial et aucun risque média."}, {"q": "En combien de temps les prospects commencent-ils à arriver ?", "a": "Une fois l'entonnoir et les campagnes en ligne, les prospects commencent généralement à entrer dans les premières semaines, le temps que les annonces accumulent des données et que le ciblage s'affine. On sera francs avec vous sur les délais lors de l'appel."}]}, "nameFr": "Génération de leads au résultat"}, {"id": "local-leadgen-network", "cat": "leads", "hero": false, "icon": "📡", "name": "Local Lead-Gen Network", "oneLiner": "A ranking network built only for you, feeding your pipeline.", "model": "/mo", "value": "$2,500-12,000/mo", "en": {"headline": "Your own ranking network, feeding your pipeline", "subhead": "We build and own a local ranking network engineered around your offer, then route every call, form, and booking it produces straight to you. You stop renting attention and start owning the road that leads to your door.", "forWho": "For: local service businesses that live or die by inbound calls and booked jobs.", "includes": ["Geo-targeted ranking sites built around your service area", "Calls, forms, and bookings routed exclusively to you", "Local SEO and map presence tuned for buyer intent", "Tracking on every lead so you see the source", "Ongoing optimization to expand into new zones"], "outcome": "Instead of bidding against everyone for the same clicks, you get a pipeline that compounds: an asset that keeps ranking and keeps sending you ready-to-buy customers month after month.", "cta": "Get started", "problem": "Right now your lead flow depends on ad spend you do not control and a shared map listing every competitor fights over. The day you stop paying, the phone goes quiet, and you are back to hoping referrals fill the gap.", "howItWorks": [{"t": "Map your zones", "d": "We study your service area, your highest-value jobs, and the exact searches buyers use right before they call."}, {"t": "Build the network", "d": "We create and rank geo-targeted sites and map presence engineered to capture that buyer intent across your zones."}, {"t": "Route every lead", "d": "Every call, form, and booking the network produces is sent straight to you, with tracking so you see exactly where it came from."}], "why": "This works because we own and operate the ranking machine ourselves, the same way we run it for our own businesses, so we are optimizing for booked jobs and not vanity clicks. You get the output of an asset we are accountable for, not a rented audience that vanishes the moment the budget does.", "faq": [{"q": "How is this different from running Google Ads?", "a": "Ads stop the second you stop paying. This builds an owned ranking network that keeps producing leads and compounds over time, so your pipeline is an asset instead of a recurring rental."}, {"q": "Are these leads exclusive to me?", "a": "Yes. The network is built around your offer and your service area, and every call, form, and booking it generates is routed only to you, never shared or resold to a competitor."}, {"q": "How will I know the leads are real?", "a": "We put tracking on every lead so you can see the source behind each call and form. You are never guessing whether it is working, you watch the pipeline fill in real time."}]}, "fr": {"headline": "Votre propre réseau de positionnement, qui alimente votre pipeline", "subhead": "On bâtit et on possède un réseau de positionnement local conçu autour de votre offre, puis on dirige chaque appel, formulaire et réservation directement vers vous. Vous arrêtez de louer l'attention et vous devenez propriétaire du chemin qui mène à votre porte.", "forWho": "Pour : les entreprises de services locaux qui vivent au rythme des appels entrants et des contrats réservés.", "includes": ["Sites de positionnement ciblés selon votre zone de service", "Appels, formulaires et réservations dirigés vers vous seulement", "SEO local et présence sur les cartes ajustés à l'intention d'achat", "Suivi de chaque lead pour voir la source exacte", "Optimisation continue pour ouvrir de nouvelles zones"], "outcome": "Au lieu d'enchérir contre tout le monde pour les mêmes clics, vous obtenez un pipeline qui compose : un actif qui continue de se classer et de vous envoyer des clients prêts à acheter, mois après mois.", "cta": "Commencer", "problem": "En ce moment, votre flux de leads dépend d'un budget publicitaire que vous ne contrôlez pas et d'une fiche de carte partagée que tous vos concurrents s'arrachent. Le jour où vous arrêtez de payer, le téléphone se tait, et vous espérez encore que les références comblent le vide.", "howItWorks": [{"t": "Cartographier vos zones", "d": "On étudie votre zone de service, vos contrats les plus payants et les recherches exactes que les clients font juste avant d'appeler."}, {"t": "Bâtir le réseau", "d": "On crée et on positionne des sites ciblés et une présence sur les cartes conçus pour capter cette intention d'achat dans vos zones."}, {"t": "Diriger chaque lead", "d": "Chaque appel, formulaire et réservation produit par le réseau vous est envoyé directement, avec un suivi qui montre exactement d'où il vient."}], "why": "Ça fonctionne parce qu'on possède et on opère nous-mêmes la machine de positionnement, exactement comme on le fait pour nos propres entreprises, donc on optimise pour des contrats réservés et non pour des clics de vanité. Vous obtenez le rendement d'un actif dont on est responsable, pas une audience louée qui disparaît dès que le budget s'arrête.", "faq": [{"q": "En quoi est-ce différent de faire des annonces Google ?", "a": "Les annonces s'arrêtent dès que vous cessez de payer. Ici, on bâtit un réseau de positionnement que vous possédez, qui continue de générer des leads et qui compose avec le temps, donc votre pipeline devient un actif au lieu d'une location récurrente."}, {"q": "Les leads sont-ils exclusifs à moi ?", "a": "Oui. Le réseau est bâti autour de votre offre et de votre zone de service, et chaque appel, formulaire et réservation qu'il génère est dirigé vers vous seulement, jamais partagé ni revendu à un concurrent."}, {"q": "Comment savoir si les leads sont réels ?", "a": "On met un suivi sur chaque lead pour que vous voyiez la source derrière chaque appel et chaque formulaire. Vous ne devinez jamais si ça marche, vous regardez le pipeline se remplir en temps réel."}]}, "nameFr": "Réseau local de génération de leads"}, {"id": "gbp-local", "cat": "leads", "hero": false, "icon": "📍", "name": "Google Business Profile & Map-Pack", "oneLiner": "Land in the local 3-pack and turn map views into calls.", "model": "/mo", "value": "$500-2,500/mo", "en": {"headline": "Own the local 3-pack and book the calls", "subhead": "We turn your Google Business Profile into a lead engine that ranks in the map-pack for the searches that buy. The same playbook we run on our own locations.", "forWho": "For: local service businesses and brick-and-mortar owners who live or die by the phone ringing.", "includes": ["Full profile rebuild: categories, services, attributes, geo-targeted descriptions", "Map-pack ranking plan for your highest-intent local searches", "Review engine that pulls in fresh 5-star reviews on autopilot", "Weekly Google Posts, Q&A seeding, and photo optimization", "Call and direction tracking so you see exactly what the map drives"], "outcome": "You stop being the business nobody scrolls down to find. When someone searches your service near you, you are the pin they tap and the number they call.", "problem": "Right now the three businesses in the map-pack take the calls, and you are stuck below the fold where almost nobody scrolls. Your profile is half-built, your reviews are stale, and Google has no reason to show you first.", "howItWorks": [{"t": "Audit and rebuild", "d": "We tear your profile down and rebuild it with the right categories, services, attributes, and geo-targeted descriptions Google actually rewards."}, {"t": "Rank the searches", "d": "We build a map-pack plan around your highest-intent local searches, then feed it with weekly Posts, Q&A, and optimized photos."}, {"t": "Fill the pipeline", "d": "We switch on the review engine and call tracking so fresh 5-star reviews and booked calls keep compounding month after month."}], "why": "We do not test this on you. This is the exact system we run on our own locations to win the map-pack, so you get a proven machine instead of an experiment.", "faq": [{"q": "How long until I show up in the map-pack?", "a": "Profile fixes can move you within weeks, but durable top-three ranking is a compounding game over a few months. We optimize for calls that last, not a spike that fades."}, {"q": "Do I need a physical storefront to rank?", "a": "No. Service-area businesses rank in the map-pack too. We set up your service areas and signals correctly so you show up for the towns you actually serve."}, {"q": "What if I already have a Google Business Profile?", "a": "Even better. Most profiles are half-built and leaking calls. We audit what you have, keep your history and reviews, and rebuild everything underneath it."}], "cta": "Get started"}, "fr": {"headline": "Dominez le 3-pack local et remplissez votre agenda", "subhead": "On transforme votre fiche Google d'entreprise en machine à appels qui se classe dans le pack de cartes pour les recherches qui achètent. Le même système qu'on applique à nos propres emplacements.", "forWho": "Pour : les entreprises de services locaux et les commerces qui vivent au rythme du téléphone qui sonne.", "includes": ["Refonte complète de la fiche : catégories, services, attributs, descriptions géociblées", "Plan de classement dans le pack de cartes pour vos recherches locales les plus payantes", "Moteur d'avis qui génère de nouvelles évaluations 5 étoiles en continu", "Publications Google hebdomadaires, questions-réponses et photos optimisées", "Suivi des appels et des itinéraires pour voir exactement ce que la carte génère"], "outcome": "Vous cessez d'être l'entreprise que personne ne trouve en descendant la page. Quand on cherche votre service près de chez vous, vous êtes le repère qu'on touche et le numéro qu'on compose.", "problem": "En ce moment, les trois entreprises du pack de cartes prennent les appels, et vous restez coincé plus bas, là où presque personne ne descend. Votre fiche est à moitié remplie, vos avis sont périmés, et Google n'a aucune raison de vous afficher en premier.", "howItWorks": [{"t": "Audit et refonte", "d": "On démonte votre fiche et on la reconstruit avec les bonnes catégories, les bons services, les attributs et les descriptions géociblées que Google récompense vraiment."}, {"t": "Classer les recherches", "d": "On bâtit un plan de pack de cartes autour de vos recherches locales les plus payantes, puis on l'alimente avec des publications, des questions-réponses et des photos optimisées chaque semaine."}, {"t": "Remplir le pipeline", "d": "On active le moteur d'avis et le suivi des appels pour que les nouvelles évaluations 5 étoiles et les appels réservés s'accumulent mois après mois."}], "why": "On ne teste pas ça sur vous. C'est exactement le système qu'on applique à nos propres emplacements pour gagner le pack de cartes, donc vous obtenez une machine éprouvée plutôt qu'une expérience.", "faq": [{"q": "Combien de temps avant d'apparaître dans le pack de cartes ?", "a": "Les corrections de fiche peuvent vous faire bouger en quelques semaines, mais un classement durable dans le top trois se gagne sur quelques mois. On vise des appels qui durent, pas un sommet qui retombe."}, {"q": "Faut-il une vitrine physique pour se classer ?", "a": "Non. Les entreprises de zone de service se classent aussi dans le pack de cartes. On configure vos zones et vos signaux correctement pour que vous apparaissiez dans les villes que vous desservez vraiment."}, {"q": "Et si j'ai déjà une fiche Google d'entreprise ?", "a": "Tant mieux. La plupart des fiches sont à moitié remplies et perdent des appels. On audite ce que vous avez, on garde votre historique et vos avis, et on reconstruit tout en dessous."}], "cta": "Commencer"}, "nameFr": "Google Business Profile et Map Pack"}, {"id": "review-generation", "cat": "leads", "hero": false, "icon": "⭐", "name": "Review Generation", "oneLiner": "More real 5-star reviews from real customers, paced so they stick.", "model": "/mo", "value": "$600-2,500/mo", "en": {"headline": "Turn happy customers into a wall of 5-star reviews", "subhead": "We build the system that asks the right customer at the right moment, so real 5-star reviews land steadily instead of all at once. You become the obvious choice before anyone calls.", "forWho": "For: local and service businesses whose review count is thin, stale, or outpaced by competitors.", "includes": ["Automated review requests by SMS and email, timed to the moment they are happiest", "Smart routing that surfaces happy customers and catches issues privately first", "Direct one-tap links to your Google and key platform profiles", "Steady pacing so reviews look organic and never trigger filters", "A simple dashboard tracking rating, volume, and momentum over time"], "outcome": "More recent, genuine 5-star reviews mean a higher star rating, stronger local ranking, and prospects who trust you before the first conversation. Reviews become a machine, not a favor you have to beg for.", "problem": "You do great work, but your Google profile shows a handful of old reviews while the competitor down the street keeps pulling ahead. Asking customers feels awkward, so you stop asking, and the prospects choosing on star count quietly pick someone else.", "howItWorks": [{"t": "Connect your flow", "d": "We plug into how you already finish jobs and collect contacts, then map the exact moment each customer is happiest with the result."}, {"t": "Trigger the ask", "d": "An automated SMS and email goes out at that peak moment, routing thrilled customers straight to your Google profile and catching anyone unhappy privately first."}, {"t": "Pace and monitor", "d": "Reviews are spaced to look organic and avoid filters, and your dashboard tracks rating, volume, and momentum so you always know where you stand."}], "why": "This is the same review engine we run on our own businesses, not a theory we sell. When the ask is automatic and perfectly timed, a steady stream of customers who were always happy finally leave the review they meant to.", "faq": [{"q": "Will this annoy my customers?", "a": "No. The ask is short, friendly, and sent once at the moment they are most satisfied, so it reads as a natural follow-up rather than a nag. Most customers are glad to help when you make it a single tap."}, {"q": "Is this against Google's rules?", "a": "No. We never buy, fake, or filter out honest reviews. We simply ask real customers at the right time and pace the requests so they land organically, which is exactly how Google wants reviews to come in."}, {"q": "What if I get a bad experience in the mix?", "a": "The system surfaces unhappy customers privately before they post, so you get a chance to make it right offline instead of watching it go public. You protect your rating and fix real problems at the same time."}], "cta": "Get started"}, "fr": {"headline": "Transformez vos clients satisfaits en mur d'avis 5 étoiles", "subhead": "On bâtit le système qui sollicite le bon client au bon moment, pour que de vrais avis 5 étoiles arrivent de façon régulière plutôt que tous d'un coup. Vous devenez le choix évident avant même qu'on vous appelle.", "forWho": "Pour : les commerces locaux et entreprises de services dont les avis sont rares, vieillissants ou dépassés par la concurrence.", "includes": ["Demandes d'avis automatisées par SMS et courriel, envoyées au moment où le client est le plus content", "Tri intelligent qui met de l'avant les clients satisfaits et capte les insatisfaits en privé d'abord", "Liens directs en un clic vers vos profils Google et vos plateformes clés", "Rythme constant pour que les avis paraissent naturels et ne déclenchent aucun filtre", "Un tableau de bord simple qui suit votre note, le volume et la cadence dans le temps"], "outcome": "Plus d'avis 5 étoiles récents et authentiques, c'est une meilleure note, un meilleur classement local et des prospects qui vous font confiance avant le premier échange. Les avis deviennent une machine, et non une faveur à quémander.", "problem": "Vous faites un excellent travail, mais votre fiche Google n'affiche qu'une poignée de vieux avis pendant que le concurrent d'à côté prend de l'avance. Demander un avis vous met mal à l'aise, alors vous arrêtez de demander, et les prospects qui choisissent selon le nombre d'étoiles partent discrètement ailleurs.", "howItWorks": [{"t": "On branche votre flux", "d": "On s'intègre à votre façon de terminer les mandats et de récolter les contacts, puis on cible le moment exact où chaque client est le plus satisfait du résultat."}, {"t": "On déclenche la demande", "d": "Un SMS et un courriel automatisés partent à ce moment clé, dirigeant les clients ravis directement vers votre fiche Google et captant en privé tout client insatisfait d'abord."}, {"t": "On rythme et on suit", "d": "Les avis sont espacés pour paraître naturels et éviter les filtres, et votre tableau de bord suit la note, le volume et la cadence pour que vous sachiez toujours où vous en êtes."}], "why": "C'est le même moteur d'avis qu'on fait rouler sur nos propres entreprises, pas une théorie qu'on vous vend. Quand la demande est automatique et parfaitement synchronisée, un flot régulier de clients qui étaient déjà contents laisse enfin l'avis qu'ils avaient en tête.", "faq": [{"q": "Est-ce que ça va agacer mes clients ?", "a": "Non. La demande est courte, cordiale et envoyée une seule fois au moment où le client est le plus satisfait, donc elle ressemble à un suivi naturel plutôt qu'à du harcèlement. La plupart des clients sont contents d'aider quand il suffit d'un clic."}, {"q": "Est-ce que ça enfreint les règles de Google ?", "a": "Non. On n'achète jamais d'avis, on n'en invente pas et on ne filtre pas les avis honnêtes. On sollicite simplement de vrais clients au bon moment et on espace les demandes pour qu'elles arrivent naturellement, exactement comme Google le souhaite."}, {"q": "Et si un client mécontent se glisse dans le lot ?", "a": "Le système capte les clients insatisfaits en privé avant qu'ils publient, ce qui vous donne la chance de corriger la situation hors ligne au lieu de la voir devenir publique. Vous protégez votre note et réglez les vrais problèmes en même temps."}], "cta": "Commencer"}, "nameFr": "Génération d'avis clients"}, {"id": "lead-tracking", "cat": "leads", "hero": false, "icon": "🧾", "name": "Lead Attribution & Proof Tracking", "oneLiner": "Audit-grade proof of every lead we send you.", "model": "/mo", "value": "$300-1,500/mo", "en": {"headline": "Know exactly which leads we sent you, and what they were worth", "subhead": "Every lead we deliver comes with audit-grade proof: source, timestamp, and call recording. No more guessing whether the work is paying off, you see it line by line.", "forWho": "For: owners who pay for lead gen and want receipts, not vague reports.", "includes": ["Tracked numbers and forms tied to each campaign", "Call recordings and transcripts for every lead", "Source, timestamp, and channel logged per lead", "Live dashboard you can open any time", "Monthly proof report you can defend to anyone"], "outcome": "You stop paying for activity and start paying for outcomes you can verify. When a lead lands, you know where it came from and what it cost you to win it.", "cta": "Get started", "problem": "You are paying for leads but you cannot prove which ones came from where, or whether half of them ever picked up the phone. The reports you get are pretty graphs that conveniently never tie a dollar back to a single conversation.", "howItWorks": [{"t": "Tag every channel", "d": "We assign tracked numbers and forms to each campaign so every inbound lead is stamped with its exact source the moment it comes in."}, {"t": "Record and log", "d": "Each call and form fill is recorded, transcribed, and logged with timestamp and channel, then pushed into one dashboard you control."}, {"t": "Prove the result", "d": "You get a monthly report that ties each lead back to where it came from, so you can see what is working and cut what is not."}], "why": "We track our own lead gen the exact same way, because we refuse to spend on channels we cannot measure. When the people running the campaign are willing to be judged line by line, you know the numbers are real.", "faq": [{"q": "Do I have to switch my phone number or website?", "a": "No. We layer tracked numbers and forms on top of what you already use, so your customers see no difference and you keep every existing setup."}, {"q": "Will recording calls cause legal trouble?", "a": "We set up recording with the proper disclosures for your region so you stay compliant, and you control who can access the recordings."}, {"q": "Can this track leads from a source you do not manage?", "a": "Yes. Even if another agency or your own ads drive the lead, we can attribute and log it so you finally see every channel in one place."}]}, "fr": {"headline": "Sachez exactement quels leads on vous a envoyés, et ce qu'ils valaient", "subhead": "Chaque lead qu'on vous livre arrive avec une preuve à toute épreuve : source, date précise et enregistrement d'appel. Fini de deviner si ça rapporte, vous le voyez ligne par ligne.", "forWho": "Pour : les propriétaires qui paient pour des leads et veulent des preuves, pas des rapports flous.", "includes": ["Numéros et formulaires tracés pour chaque campagne", "Enregistrements et transcriptions de chaque appel", "Source, date et canal notés pour chaque lead", "Tableau de bord en direct, accessible en tout temps", "Rapport de preuve mensuel, défendable devant n'importe qui"], "outcome": "Vous arrêtez de payer pour de l'activité et commencez à payer pour des résultats vérifiables. Quand un lead entre, vous savez d'où il vient et ce qu'il vous a coûté pour le gagner.", "cta": "Commencer", "problem": "Vous payez pour des leads, mais vous ne pouvez pas prouver lesquels viennent d'où, ni si la moitié a même répondu au téléphone. Les rapports que vous recevez sont de beaux graphiques qui, comme par hasard, ne rattachent jamais un dollar à une vraie conversation.", "howItWorks": [{"t": "Tracer chaque canal", "d": "On attribue des numéros et des formulaires tracés à chaque campagne pour que chaque lead entrant soit marqué de sa source exacte dès qu'il arrive."}, {"t": "Enregistrer et noter", "d": "Chaque appel et chaque formulaire est enregistré, transcrit et noté avec sa date et son canal, puis envoyé dans un seul tableau de bord que vous contrôlez."}, {"t": "Prouver le résultat", "d": "Vous recevez un rapport mensuel qui rattache chaque lead à sa provenance, pour voir ce qui fonctionne et couper ce qui ne fonctionne pas."}], "why": "On trace notre propre génération de leads exactement de la même façon, parce qu'on refuse de dépenser sur des canaux qu'on ne peut pas mesurer. Quand les gens qui mènent la campagne acceptent d'être jugés ligne par ligne, vous savez que les chiffres sont vrais.", "faq": [{"q": "Dois-je changer mon numéro de téléphone ou mon site web ?", "a": "Non. On ajoute les numéros et formulaires tracés par-dessus ce que vous utilisez déjà, donc vos clients ne voient aucune différence et vous gardez tout votre setup actuel."}, {"q": "Est-ce que l'enregistrement des appels cause des problèmes légaux ?", "a": "On configure l'enregistrement avec les avis appropriés pour votre région afin que vous restiez conforme, et vous contrôlez qui a accès aux enregistrements."}, {"q": "Pouvez-vous tracer des leads d'une source que vous ne gérez pas ?", "a": "Oui. Même si une autre agence ou vos propres publicités amènent le lead, on peut l'attribuer et le noter pour que vous voyiez enfin tous vos canaux au même endroit."}]}, "nameFr": "Attribution des leads et suivi des preuves"}, {"id": "regulated-content", "cat": "content", "hero": false, "icon": "⚖️", "name": "Regulated-Industry Content", "oneLiner": "Compliant content for health, legal and finance that others will not touch.", "model": "/mo", "value": "$1,500-6,000/mo", "en": {"headline": "Rank in health, legal and finance without the legal risk", "subhead": "We publish compliant, authoritative content for the niches every freelancer is too scared to touch. You get the rankings; your compliance officer stays calm.", "forWho": "For: clinics, law firms, advisors and fintech brands in YMYL niches search engines hold to a higher bar.", "includes": ["Claims reviewed against your industry's advertising and disclosure rules", "Cited, source-backed articles that read as genuine expertise", "Author and credential framing that signals real authority", "Required disclaimers and disclosures built into every piece", "A repeatable monthly publishing cadence, fully managed"], "outcome": "You own the search results in a space your competitors are afraid to enter, while every word stands up to scrutiny from regulators and reviewers alike.", "cta": "Get started", "problem": "In health, legal and finance, one unverified claim or missing disclaimer can trigger a regulator complaint, so most teams either freeze and publish nothing or pay a generalist who quietly exposes them. Meanwhile the search results you should own sit wide open for whoever dares to publish.", "howItWorks": [{"t": "Compliance mapping", "d": "We document the advertising, disclosure and claims rules that govern your specific niche so every article is written inside the lines from the first draft."}, {"t": "Authority drafting", "d": "We produce cited, credential-backed articles with the required disclaimers built in, then route anything sensitive past your reviewer before it goes live."}, {"t": "Managed cadence", "d": "We publish on a steady monthly rhythm and track rankings, so your library compounds without you chasing freelancers or re-checking compliance."}], "why": "This works because we treat your content like our own regulated asset, not a faceless content mill: the same review discipline an operator uses to protect their own brand is what keeps your claims defensible. Compliant authority is the one moat your scared competitors will not copy.", "faq": [{"q": "Do you guarantee the content is legally compliant?", "a": "We write to your industry's advertising and disclosure rules and build in the required disclaimers, and we route sensitive claims to your reviewer or counsel for final sign-off. You stay the legal authority of record; we make that approval fast and painless instead of a fight."}, {"q": "Do you actually understand my niche, or is this generic writing?", "a": "We map the specific rules for your field before we write a word, whether that is medical advertising standards, legal solicitation rules or financial disclosure requirements. Every piece is built around your niche, not dropped from a generic template."}, {"q": "Can the articles really rank in such competitive spaces?", "a": "Yes, and the compliance is the advantage: most competitors avoid YMYL topics entirely or publish thin, risky pages, which leaves the authoritative, well-cited results to you. Search engines reward exactly the credibility we build in."}]}, "fr": {"headline": "Classez-vous en santé, en droit et en finance sans risque légal", "subhead": "On publie du contenu conforme et crédible dans les niches que les autres rédacteurs n'osent pas toucher. Vous obtenez le classement, votre responsable de la conformité reste tranquille.", "forWho": "Pour : cliniques, cabinets d'avocats, conseillers et marques fintech dans les niches que les moteurs de recherche jugent plus sévèrement.", "includes": ["Allégations vérifiées selon les règles de publicité et de divulgation de votre secteur", "Articles cités et appuyés par des sources qui témoignent d'une vraie expertise", "Mise en valeur des auteurs et de leurs titres pour signaler une autorité réelle", "Avis et divulgations obligatoires intégrés dans chaque texte", "Une cadence de publication mensuelle constante, entièrement gérée"], "outcome": "Vous dominez les résultats de recherche dans un domaine que vos concurrents craignent, pendant que chaque mot résiste à l'examen des organismes de réglementation comme des réviseurs.", "cta": "Commencer", "problem": "En santé, en droit et en finance, une seule allégation non vérifiée ou un avis manquant peut déclencher une plainte au régulateur. La plupart des équipes se figent et ne publient rien, ou confient le travail à un généraliste qui les expose sans le dire. Pendant ce temps, les résultats de recherche que vous devriez posséder restent grands ouverts.", "howItWorks": [{"t": "Cartographie de conformité", "d": "On documente les règles de publicité, de divulgation et d'allégations propres à votre niche pour que chaque article respecte les balises dès le premier jet."}, {"t": "Rédaction d'autorité", "d": "On produit des articles cités et appuyés par des titres crédibles, avec les avis obligatoires intégrés, puis on fait valider tout contenu sensible par votre réviseur avant publication."}, {"t": "Cadence gérée", "d": "On publie selon un rythme mensuel constant et on suit le classement, pour que votre bibliothèque grossisse sans que vous couriez après des pigistes ou revérifiiez la conformité."}], "why": "Ça fonctionne parce qu'on traite votre contenu comme notre propre actif réglementé, pas comme une usine à textes anonyme : la même rigueur de révision qu'un opérateur applique pour protéger sa marque est ce qui garde vos allégations défendables. L'autorité conforme est le seul fossé que vos concurrents craintifs ne copieront pas.", "faq": [{"q": "Garantissez-vous que le contenu est conforme sur le plan légal ?", "a": "On rédige selon les règles de publicité et de divulgation de votre secteur et on intègre les avis obligatoires, puis on achemine les allégations sensibles vers votre réviseur ou votre conseiller juridique pour approbation finale. Vous demeurez l'autorité légale officielle ; on rend cette approbation rapide et simple plutôt qu'un combat."}, {"q": "Comprenez-vous vraiment ma niche, ou est-ce de la rédaction générique ?", "a": "On cartographie les règles précises de votre domaine avant d'écrire un seul mot, qu'il s'agisse des normes de publicité médicale, des règles de sollicitation juridique ou des exigences de divulgation financière. Chaque texte est bâti autour de votre niche, pas sorti d'un gabarit générique."}, {"q": "Les articles peuvent-ils vraiment se classer dans des domaines aussi compétitifs ?", "a": "Oui, et la conformité est justement l'avantage : la plupart des concurrents évitent complètement les sujets sensibles ou publient des pages minces et risquées, ce qui vous laisse les résultats crédibles et bien cités. Les moteurs de recherche récompensent exactement la crédibilité qu'on bâtit."}]}, "nameFr": "Contenu pour secteurs réglementés"}, {"id": "content-at-scale", "cat": "content", "hero": false, "icon": "✍️", "name": "Content at Scale", "oneLiner": "On-brand, multilingual content at volume.", "model": "/mo", "value": "$1,000-5,000/mo", "en": {"headline": "Publish like a media company, without the team", "subhead": "We turn your brand into a content machine that ships on-brand articles, posts, and pages in every language your customers buy in. Same voice, every channel, every week.", "forWho": "For: brands that know content drives growth but can't produce enough of it, consistently, in more than one language.", "includes": ["A locked brand voice guide your content is built against every time", "Weekly multilingual output: long-form, social, email, and landing copy", "Native-quality translation and localization, not machine output", "SEO-structured pieces built to rank, not just fill a calendar", "A content calendar and reporting so you always know what shipped"], "outcome": "You stop being the bottleneck and start owning the conversation in your market. More published, more found, more languages, more pipeline, without hiring a single writer.", "cta": "Get started", "problem": "You know content is what moves the market, but you're the bottleneck. Posts ship in fits and starts, one language gets all the attention while the others go silent, and the voice drifts every time someone else writes a line.", "howItWorks": [{"t": "Lock the voice", "d": "We build a brand voice guide from your best assets so every piece sounds like you, no matter who or what produced it."}, {"t": "Build the machine", "d": "We stand up a weekly pipeline that produces long-form, social, email, and landing copy across every language you sell in."}, {"t": "Ship and report", "d": "Content goes out on a calendar you can see, with reporting that shows what published and what it's pulling in."}], "why": "We run this for our own brand first, so the system is tested before it ever touches yours. It's built by operators who need content to convert, not a copy shop billing by the word.", "faq": [{"q": "Is this just AI spitting out generic articles?", "a": "No. Every piece runs against your locked voice guide and gets a human pass, so it reads like your brand and not a template. We use the tooling to move fast, not to dump filler."}, {"q": "How is the translation handled?", "a": "We localize to native quality, not raw machine output. The piece is rebuilt to read naturally in each language and market, so a French reader and an English reader both feel like the content was written for them."}, {"q": "How many languages can you cover?", "a": "Every language your customers actually buy in. We scope it to where your pipeline is, then add languages as you open new markets, all held to the same voice."}]}, "fr": {"headline": "Publiez comme un média, sans bâtir l'équipe", "subhead": "On transforme votre marque en machine à contenu qui livre des articles, des publications et des pages fidèles à votre voix, dans chaque langue où vos clients achètent. Même ton, partout, chaque semaine.", "forWho": "Pour : les marques qui savent que le contenu fait croître les ventes, mais qui n'arrivent pas à en produire assez, de façon constante, dans plus d'une langue.", "includes": ["Un guide de voix de marque verrouillé, respecté à chaque contenu", "Une cadence hebdomadaire multilingue : articles, réseaux sociaux, infolettres, pages", "Une traduction et une localisation de qualité native, pas une sortie machine", "Des contenus structurés pour le référencement, faits pour se classer", "Un calendrier de contenu et des rapports pour toujours savoir ce qui est publié"], "outcome": "Vous cessez d'être le goulot d'étranglement et vous prenez le contrôle de la conversation dans votre marché. Plus de contenu publié, plus de visibilité, plus de langues, plus de prospects, sans embaucher un seul rédacteur.", "cta": "Commencer", "problem": "Vous savez que le contenu fait bouger le marché, mais c'est vous le goulot d'étranglement. Les publications sortent par à-coups, une langue reçoit toute l'attention pendant que les autres restent muettes, et la voix dérive dès que quelqu'un d'autre écrit une ligne.", "howItWorks": [{"t": "Verrouiller la voix", "d": "On bâtit un guide de voix de marque à partir de vos meilleurs contenus, pour que chaque pièce sonne comme vous, peu importe qui ou quoi l'a produite."}, {"t": "Monter la machine", "d": "On met en place une chaîne hebdomadaire qui produit articles, réseaux sociaux, infolettres et pages, dans chaque langue où vous vendez."}, {"t": "Publier et mesurer", "d": "Le contenu sort selon un calendrier que vous voyez, avec des rapports qui montrent ce qui a été publié et ce que ça rapporte."}], "why": "On fait rouler ce système pour notre propre marque d'abord, donc il est testé avant même de toucher la vôtre. Il est conçu par des opérateurs qui ont besoin que le contenu convertisse, pas par un atelier facturé au mot.", "faq": [{"q": "Est-ce juste de l'IA qui pond des articles génériques ?", "a": "Non. Chaque pièce passe par votre guide de voix verrouillé et par une révision humaine, pour qu'elle se lise comme votre marque et non comme un gabarit. On utilise les outils pour aller vite, pas pour remplir avec du vide."}, {"q": "Comment la traduction est-elle gérée ?", "a": "On localise à un niveau de qualité native, pas une sortie machine brute. La pièce est reconstruite pour se lire naturellement dans chaque langue et chaque marché, pour qu'un lecteur francophone et un lecteur anglophone aient tous deux l'impression que le contenu a été écrit pour eux."}, {"q": "Combien de langues pouvez-vous couvrir ?", "a": "Chaque langue où vos clients achètent réellement. On l'ajuste à l'endroit où se trouvent vos prospects, puis on ajoute des langues à mesure que vous ouvrez de nouveaux marchés, le tout fidèle à la même voix."}]}, "nameFr": "Contenu à grande échelle"}, {"id": "keyword-research", "cat": "content", "hero": false, "icon": "🔑", "name": "Keyword Research at Scale", "oneLiner": "Thousands of real, intent-scored keywords, with no fake volumes.", "model": "1x", "value": "$300-2,500", "en": {"headline": "Know Exactly What Your Buyers Are Searching For", "subhead": "We pull thousands of real, intent-scored keywords for your niche, with zero fake volumes. You get a map of every search worth winning, ranked by how close each one is to a sale.", "forWho": "For: operators who refuse to publish content on guesswork and want every page tied to real demand.", "includes": ["Thousands of live keywords pulled from real search data", "Intent scoring on every term, from research to ready-to-buy", "Clusters grouped by topic so you know what to publish next", "Difficulty and opportunity flags to prioritize quick wins", "A clean, sortable sheet your team can act on day one"], "outcome": "You stop guessing and start targeting demand that actually exists. Every article, page, and product gets pointed at searches real buyers are typing today.", "problem": "You are publishing content and chasing terms with no idea whether anyone is actually searching for them. So your team burns weeks on pages that never get a single click, while the keywords that would have printed sales sit untouched.", "howItWorks": [{"t": "Pull live demand", "d": "We extract thousands of real keywords for your niche straight from search data, with no inflated or invented volumes."}, {"t": "Score and cluster", "d": "Every term gets an intent score and lands in a topic cluster, so you can see at a glance what to win first."}, {"t": "Hand off the map", "d": "You get a clean, sortable sheet with difficulty and opportunity flags that your team can build against on day one."}], "why": "We run this same research on our own properties before we ever sell it, because we are operators first. When your money is on the line, you stop trusting guessed volumes and start demanding keywords tied to demand you can prove.", "faq": [{"q": "How is this different from just using a keyword tool myself?", "a": "A tool hands you a raw list. We hand you a prioritized map: every term intent-scored, clustered by topic, and flagged for difficulty, so you know what to publish next instead of drowning in a spreadsheet of noise."}, {"q": "Will this work for my specific niche?", "a": "Yes. We pull from real search data for your exact market, not a generic template. If buyers are typing it, we find it, score it, and tell you whether it is worth chasing."}, {"q": "What do I actually walk away with?", "a": "A clean, sortable sheet of thousands of intent-scored keywords, grouped into topic clusters with difficulty and opportunity flags. Your team can start building content against it the same day you receive it."}], "cta": "Get started"}, "fr": {"headline": "Sachez exactement ce que vos acheteurs recherchent", "subhead": "On sort des milliers de mots-clés réels, notés par intention, pour votre niche, sans aucun volume gonflé. Vous obtenez la carte de chaque recherche qui vaut la peine d'être gagnée, classée selon sa proximité avec une vente.", "forWho": "Pour : les opérateurs qui refusent de publier au hasard et veulent que chaque page soit liée à une vraie demande.", "includes": ["Des milliers de mots-clés tirés de vraies données de recherche", "Une note d'intention sur chaque terme, de la recherche à l'achat imminent", "Des regroupements par sujet pour savoir quoi publier ensuite", "Des indicateurs de difficulté et d'opportunité pour prioriser les gains rapides", "Un fichier propre et triable que votre équipe peut utiliser dès le premier jour"], "outcome": "Vous arrêtez de deviner et commencez à viser une demande qui existe vraiment. Chaque article, page et produit pointe vers des recherches que de vrais acheteurs tapent aujourd'hui.", "problem": "Vous publiez du contenu et visez des termes sans savoir si quelqu'un les recherche vraiment. Votre équipe perd donc des semaines sur des pages qui n'obtiennent jamais un seul clic, pendant que les mots-clés qui auraient généré des ventes restent intacts.", "howItWorks": [{"t": "Sortir la demande réelle", "d": "On extrait des milliers de vrais mots-clés pour votre niche directement à partir des données de recherche, sans volume gonflé ni inventé."}, {"t": "Noter et regrouper", "d": "Chaque terme reçoit une note d'intention et tombe dans un regroupement par sujet, pour voir d'un coup d'œil ce qu'il faut gagner en premier."}, {"t": "Remettre la carte", "d": "Vous recevez un fichier propre et triable avec des indicateurs de difficulté et d'opportunité que votre équipe peut exploiter dès le premier jour."}], "why": "On fait cette même recherche sur nos propres propriétés avant même de la vendre, parce qu'on est d'abord des opérateurs. Quand votre argent est en jeu, vous cessez de faire confiance aux volumes devinés et exigez des mots-clés liés à une demande que vous pouvez prouver.", "faq": [{"q": "En quoi est-ce différent d'utiliser un outil de mots-clés moi-même ?", "a": "Un outil vous donne une liste brute. Nous vous donnons une carte priorisée : chaque terme noté par intention, regroupé par sujet et marqué par difficulté, pour que vous sachiez quoi publier ensuite au lieu de vous noyer dans un fichier rempli de bruit."}, {"q": "Est-ce que ça va fonctionner pour ma niche précise ?", "a": "Oui. On tire de vraies données de recherche pour votre marché exact, pas un modèle générique. Si des acheteurs le tapent, on le trouve, on le note et on vous dit si ça vaut la peine d'être visé."}, {"q": "Qu'est-ce que je reçois concrètement ?", "a": "Un fichier propre et triable de milliers de mots-clés notés par intention, regroupés par sujet avec des indicateurs de difficulté et d'opportunité. Votre équipe peut commencer à bâtir du contenu dès le jour où vous le recevez."}], "cta": "Commencer"}, "nameFr": "Recherche de mots-clés à grande échelle"}, {"id": "content-roadmap", "cat": "content", "hero": false, "icon": "🗺️", "name": "Content Architecture & Roadmap", "oneLiner": "Turn keyword demand into a content plan Google rewards.", "model": "1x", "value": "$1,500-6,000", "en": {"headline": "Stop guessing what to publish next", "subhead": "We map real keyword demand to a publishing plan built around how Google actually ranks. Every article you write earns its spot.", "forWho": "For: operators with a blog or content team publishing on instinct instead of a plan that compounds.", "includes": ["Full keyword and demand map for your niche", "Topic clusters and pillar pages that build authority", "Prioritized publishing calendar ranked by ranking odds", "Search intent and funnel stage for every piece", "Internal linking blueprint that passes ranking signals"], "outcome": "You walk away with a content engine where every post supports the next, traffic compounds instead of leaking, and you finally know exactly what to publish and why.", "cta": "Get started", "problem": "You publish good articles that never rank, and the ones that do feel like luck you can't repeat. Your blog is a pile of disconnected posts instead of a system that builds on itself.", "howItWorks": [{"t": "Map the demand", "d": "We pull the real keywords your buyers search and size each one by volume, intent, and how hard it is to rank for."}, {"t": "Build the clusters", "d": "We group that demand into pillar pages and supporting topics so every article reinforces the authority of the next."}, {"t": "Sequence the calendar", "d": "We hand you a publishing order ranked by ranking odds, so you write the pieces most likely to win first."}], "why": "We run this same machine on our own content before we ever sell it, so the roadmap is built on what actually moves rankings, not theory. You get the plan an operator uses to compound their own traffic.", "faq": [{"q": "Do you write the articles too?", "a": "This is the roadmap: the demand map, clusters, and prioritized calendar your team writes from. If you'd rather hand off the writing entirely, we can talk about that on the call."}, {"q": "How is this different from a list of keywords?", "a": "A keyword list tells you words. A roadmap tells you what to publish, in what order, how it links together, and why each piece earns a ranking. It's a plan, not a spreadsheet."}, {"q": "We already have a lot of old posts. Is that wasted?", "a": "No. We fold your existing content into the map, flag what's worth keeping or merging, and route internal links so your back catalog finally pulls its weight."}]}, "fr": {"headline": "Arrêtez de deviner quoi publier ensuite", "subhead": "On transforme la demande réelle de mots-clés en un plan de publication bâti sur la façon dont Google classe vraiment. Chaque article gagne sa place.", "forWho": "Pour : les opérateurs qui ont un blogue ou une équipe de contenu et qui publient à l'instinct au lieu de suivre un plan qui s'accumule.", "includes": ["Carte complète des mots-clés et de la demande pour votre niche", "Grappes de sujets et pages piliers qui bâtissent l'autorité", "Calendrier de publication priorisé selon les chances de classement", "Intention de recherche et étape de l'entonnoir pour chaque article", "Plan de maillage interne qui transmet les signaux de classement"], "outcome": "Vous repartez avec un moteur de contenu où chaque article appuie le suivant, où le trafic s'accumule au lieu de fuir, et où vous savez enfin exactement quoi publier et pourquoi.", "cta": "Commencer", "problem": "Vous publiez de bons articles qui ne classent jamais, et ceux qui classent ressemblent à de la chance impossible à répéter. Votre blogue est un tas d'articles déconnectés au lieu d'un système qui se construit sur lui-même.", "howItWorks": [{"t": "Cartographier la demande", "d": "On sort les vrais mots-clés que vos clients recherchent et on évalue chacun selon le volume, l'intention et la difficulté de classement."}, {"t": "Bâtir les grappes", "d": "On regroupe cette demande en pages piliers et sujets de soutien pour que chaque article renforce l'autorité du suivant."}, {"t": "Séquencer le calendrier", "d": "On vous remet un ordre de publication priorisé selon les chances de classement, pour écrire d'abord les articles les plus susceptibles de gagner."}], "why": "On fait rouler cette même machine sur notre propre contenu avant même de la vendre, donc le plan est bâti sur ce qui fait vraiment bouger les classements, pas sur de la théorie. Vous obtenez le plan qu'un opérateur utilise pour faire grimper son propre trafic.", "faq": [{"q": "Est-ce que vous rédigez aussi les articles ?", "a": "Ceci est le plan : la carte de la demande, les grappes et le calendrier priorisé que votre équipe utilise pour rédiger. Si vous préférez déléguer la rédaction au complet, on en parle pendant l'appel."}, {"q": "En quoi est-ce différent d'une liste de mots-clés ?", "a": "Une liste de mots-clés vous donne des mots. Un plan vous dit quoi publier, dans quel ordre, comment tout se relie et pourquoi chaque article gagne son classement. C'est un plan, pas un tableur."}, {"q": "On a déjà beaucoup d'anciens articles. Est-ce du gaspillage ?", "a": "Non. On intègre votre contenu existant à la carte, on repère ce qui vaut la peine d'être gardé ou fusionné, et on dirige le maillage interne pour que vos vieux articles travaillent enfin."}]}, "nameFr": "Architecture et feuille de route de contenu"}, {"id": "shopify-build", "cat": "ecom", "hero": false, "icon": "🛍️", "name": "Custom Shopify Builds", "oneLiner": "Stores built and tuned to convert and to be found by AI.", "model": "1x", "value": "$2,800-15,000", "en": {"headline": "A Shopify store built to sell and to get recommended by AI", "subhead": "We design and engineer the same store machinery we run on our own brands, tuned to turn cold traffic into orders. Every page is structured so AI assistants pull your products when shoppers ask for what you sell.", "forWho": "For: brands launching or relaunching a Shopify store that has to convert from day one, not just look good.", "includes": ["Conversion-first store design across home, collection, and product pages", "Buy-flow and checkout tuned to lift add-to-cart and completed orders", "AI-readable product data and structure so assistants surface your catalog", "Speed, mobile, and trust optimization that holds up under paid traffic", "Apps, tracking, and post-purchase flows wired in and tested before launch"], "outcome": "You launch with a store that earns the sale instead of leaking it, and that shows up when AI is doing the recommending. The result is more orders from the traffic you already have and a foundation built to scale.", "cta": "Get started", "problem": "Most Shopify stores look fine but quietly leak sales on every page, so you pay for traffic and watch it bounce. And now buyers are asking AI for recommendations, but your store is invisible to it because the product data was never structured to be read.", "howItWorks": [{"t": "Audit and blueprint", "d": "We map your catalog, margins, and buyer path, then blueprint a store structure built to convert and to be readable by AI."}, {"t": "Design and engineer", "d": "We build the home, collection, and product pages with the conversion mechanics, speed, and clean product data that make shoppers buy and assistants surface you."}, {"t": "Wire up and launch", "d": "We connect the apps, tracking, and post-purchase flows, test the full buy-flow on real devices, and launch the store ready for paid traffic."}], "why": "We do not theorize about what converts, we run this exact store machinery on our own brands every day and ship what already works. You get a store engineered by operators who eat their own cooking, not a template handed off by a freelancer who has never sold a thing.", "faq": [{"q": "I already have a Shopify store. Do you start over or fix what I have?", "a": "We start from your numbers, not a blank page. If the bones are good we rebuild the pages and flows that are leaking sales, and if the foundation is holding you back we say so and rebuild what actually moves orders."}, {"q": "What does this AI recommendation thing actually mean for my store?", "a": "Shoppers increasingly ask AI assistants what to buy, and those assistants pull from stores whose product data is structured to be read. We build your catalog and pages that way so when someone asks for what you sell, your products are in the answer."}, {"q": "How involved do I need to be during the build?", "a": "We handle the heavy lifting and only pull you in for the decisions that need an owner: brand direction, product details, and a few approvals. You stay focused on your business while we build the machine."}]}, "fr": {"headline": "Une boutique Shopify bâtie pour vendre et pour être recommandée par l'IA", "subhead": "On conçoit et on assemble la même mécanique de boutique qu'on roule sur nos propres marques, réglée pour transformer le trafic froid en commandes. Chaque page est structurée pour que les assistants IA proposent vos produits quand les acheteurs cherchent ce que vous vendez.", "forWho": "Pour : les marques qui lancent ou relancent une boutique Shopify qui doit convertir dès le premier jour, pas juste bien paraître.", "includes": ["Design de boutique axé conversion sur l'accueil, les collections et les fiches produits", "Parcours d'achat et paiement réglés pour augmenter l'ajout au panier et les commandes complétées", "Données et structure produits lisibles par l'IA pour que les assistants ressortent votre catalogue", "Optimisation vitesse, mobile et confiance qui tient le coup sous le trafic payant", "Applications, suivi et flux après-achat branchés et testés avant le lancement"], "outcome": "Vous lancez avec une boutique qui vise à gagner la vente au lieu de la laisser filer, et qui a plus de chances de ressortir quand c'est l'IA qui recommande. Le résultat visé : plus de commandes à partir du trafic que vous avez déjà et une base bâtie pour grandir.", "cta": "Commencer", "problem": "La plupart des boutiques Shopify ont l'air correctes, mais elles laissent filer des ventes en silence sur chaque page, alors vous payez pour du trafic et vous le regardez rebondir. Et là, les acheteurs demandent des recommandations à l'IA, mais votre boutique lui reste souvent invisible parce que les données produits n'ont jamais été structurées pour être lues.", "howItWorks": [{"t": "Audit et plan", "d": "On cartographie votre catalogue, vos marges et le parcours d'achat, puis on dessine une structure de boutique bâtie pour convertir et pour être lisible par l'IA."}, {"t": "Design et assemblage", "d": "On bâtit l'accueil, les collections et les fiches produits avec la mécanique de conversion, la vitesse et les données produits propres qui aident vos clients à acheter et votre boutique à ressortir dans l'IA."}, {"t": "Branchement et lancement", "d": "On connecte les applications, le suivi et les flux après-achat, on teste le parcours d'achat complet sur de vrais appareils, et on lance la boutique prête pour le trafic payant."}], "why": "On ne théorise pas sur ce qui convertit : on roule cette mécanique de boutique exacte sur nos propres marques chaque jour et on déploie ce qui marche déjà. Vous obtenez une boutique bâtie par des opérateurs qui mangent leur propre cuisine, pas un gabarit refilé par un pigiste qui n'a jamais rien vendu.", "faq": [{"q": "J'ai déjà une boutique Shopify. Vous repartez de zéro ou vous réparez ce que j'ai ?", "a": "On part de vos chiffres, pas d'une page blanche. Si les bases sont bonnes, on rebâtit les pages et les flux qui laissent filer des ventes, et si la fondation vous freine, on vous le dit et on rebâtit ce qui fait vraiment bouger les commandes."}, {"q": "Ça veut dire quoi concrètement, cette histoire de recommandation par l'IA, pour ma boutique ?", "a": "De plus en plus d'acheteurs demandent aux assistants IA quoi acheter, et ces assistants puisent dans les boutiques dont les données produits sont structurées pour être lues. On bâtit votre catalogue et vos pages de cette façon pour que, quand quelqu'un cherche ce que vous vendez, vos produits aient plus de chances de figurer dans la réponse."}, {"q": "À quel point dois-je être impliqué pendant la construction ?", "a": "On s'occupe du gros du travail et on vous sollicite seulement pour les décisions qui demandent un propriétaire : la direction de marque, les détails produits et quelques approbations. Vous restez concentré sur votre business pendant qu'on bâtit la machine."}]}, "nameFr": "Boutiques Shopify sur mesure"}, {"id": "gmc-approval", "cat": "ecom", "hero": false, "icon": "✅", "name": "Google Merchant Center Approval", "oneLiner": "Get approved on Google Shopping, and stay approved.", "model": "1x", "value": "$750-4,000", "en": {"headline": "Get Approved On Google Shopping, And Stay There", "subhead": "We take your Merchant Center from suspended or limbo to fully approved, then lock it so your products keep showing up. No more guessing why Google rejected your feed.", "forWho": "For: Shopify and ecommerce stores stuck with a disapproved feed, a suspended Merchant Center, or products that just will not show on Google Shopping.", "includes": ["Full Merchant Center and feed audit against Google policy", "Account suspension and misrepresentation appeal handled for you", "Product feed cleanup so every item passes review", "Required policy pages, GTINs, and shipping or tax setup fixed", "Monitoring and reactivation guardrails so approval holds"], "outcome": "Your products go live on Google Shopping and stay there, which means your ads actually run and your catalog earns clicks instead of sitting frozen. Approval becomes one less thing you ever have to fight Google over.", "cta": "Get started", "problem": "Your Merchant Center is suspended or your feed sits in disapproval limbo, so your products are invisible on Google Shopping and your ad spend has nowhere to go. Every day the catalog stays frozen is a day of sales walking straight to competitors who got approved.", "howItWorks": [{"t": "Diagnose the block", "d": "We audit your Merchant Center and feed line by line against current Google policy to pinpoint the exact reason you were flagged or suspended."}, {"t": "Fix and appeal", "d": "We clean the feed, repair the missing policy pages, GTINs, shipping and tax settings, then file the suspension or misrepresentation appeal the way Google actually wants it."}, {"t": "Lock it down", "d": "Once you are approved we put monitoring and guardrails in place so a silent policy change or feed error never quietly knocks you back offline."}], "why": "We run Google Shopping on our own ecommerce stores, so we have fought these exact suspensions and misrepresentation flags with real money on the line, not from a help doc. Google approval is a known system with known rules, and we fix the cause instead of resubmitting and hoping.", "faq": [{"q": "My account is already suspended for misrepresentation. Can that even be reversed?", "a": "Yes, in most cases. Misrepresentation flags almost always trace back to fixable causes like missing policy pages, inconsistent pricing, or contact and trust signals Google cannot verify. We correct the root cause, then submit the appeal correctly so it actually gets reviewed."}, {"q": "How long until my products are live again?", "a": "The fixes on our side move fast, often within days. The variable is Google's own review queue after we submit the appeal, which we cannot control, but doing the cleanup right the first time is what avoids a second rejection and the weeks that adds."}, {"q": "Will the approval actually hold, or will I get suspended again next month?", "a": "That is exactly why we add monitoring and reactivation guardrails. Most repeat suspensions happen because the underlying issue was never fixed or a feed change slipped through unnoticed. We fix the cause and watch for the warning signs so it stays approved."}]}, "fr": {"headline": "Faites approuver vos produits sur Google Shopping, et restez-y", "subhead": "On sort votre Merchant Center du blocage ou de la suspension pour le rendre pleinement approuvé, puis on le verrouille pour que vos produits continuent de s'afficher. Fini de deviner pourquoi Google refuse votre flux.", "forWho": "Pour : les boutiques Shopify et e-commerce coincées avec un flux refusé, un Merchant Center suspendu, ou des produits qui n'apparaissent tout simplement pas sur Google Shopping.", "includes": ["Audit complet du Merchant Center et du flux selon les politiques de Google", "Appel de suspension de compte et de fausse déclaration géré pour vous", "Nettoyage du flux de produits pour que chaque article passe la révision", "Pages de politiques, GTIN et configuration de livraison ou de taxes corrigés", "Surveillance et garde-fous de réactivation pour maintenir l'approbation"], "outcome": "Vos produits passent en ligne sur Google Shopping et y restent, donc vos annonces tournent vraiment et votre catalogue génère des clics au lieu de rester gelé. L'approbation devient une bataille de moins à mener contre Google.", "cta": "Commencer", "problem": "Votre Merchant Center est suspendu ou votre flux reste coincé en refus, donc vos produits sont invisibles sur Google Shopping et votre budget publicitaire n'a nulle part où aller. Chaque journée où le catalogue reste gelé est une journée de ventes qui file directement vers les concurrents qui, eux, ont été approuvés.", "howItWorks": [{"t": "Trouver le blocage", "d": "On audite votre Merchant Center et votre flux ligne par ligne selon les politiques actuelles de Google pour cibler la raison exacte du signalement ou de la suspension."}, {"t": "Corriger et faire appel", "d": "On nettoie le flux, on répare les pages de politiques manquantes, les GTIN et les réglages de livraison et de taxes, puis on dépose l'appel de suspension ou de fausse déclaration de la manière que Google attend vraiment."}, {"t": "Verrouiller le compte", "d": "Une fois que vous êtes approuvé, on met en place de la surveillance et des garde-fous pour qu'un changement de politique silencieux ou une erreur de flux ne vous remette jamais hors ligne sans prévenir."}], "why": "On fait rouler Google Shopping sur nos propres boutiques e-commerce, donc on a combattu ces suspensions et ces signalements de fausse déclaration avec de l'argent réel en jeu, pas à partir d'un document d'aide. L'approbation Google est un système connu avec des règles connues, et on corrige la cause au lieu de resoumettre en espérant.", "faq": [{"q": "Mon compte est déjà suspendu pour fausse déclaration. Est-ce que ça peut vraiment se renverser ?", "a": "Oui, dans la plupart des cas. Les signalements de fausse déclaration remontent presque toujours à des causes corrigeables : pages de politiques manquantes, prix incohérents, ou signaux de contact et de confiance que Google n'arrive pas à vérifier. On corrige la cause à la source, puis on soumet l'appel correctement pour qu'il soit réellement révisé."}, {"q": "Combien de temps avant que mes produits soient de nouveau en ligne ?", "a": "Les corrections de notre côté avancent vite, souvent en quelques jours. La variable, c'est la file de révision de Google une fois l'appel soumis, qu'on ne contrôle pas, mais faire le nettoyage correctement du premier coup, c'est ce qui évite un deuxième refus et les semaines que ça ajoute."}, {"q": "Est-ce que l'approbation va vraiment tenir, ou je vais être suspendu encore le mois prochain ?", "a": "C'est exactement pour ça qu'on ajoute de la surveillance et des garde-fous de réactivation. La plupart des suspensions à répétition arrivent parce que le problème de fond n'a jamais été corrigé ou qu'un changement de flux est passé inaperçu. On corrige la cause et on surveille les signaux d'alerte pour que ça reste approuvé."}]}, "nameFr": "Approbation Google Merchant Center"}, {"id": "subscription-setup", "cat": "ecom", "hero": false, "icon": "🔁", "name": "Subscription & Replenishment", "oneLiner": "Turn one-off buyers into recurring revenue.", "model": "1x", "value": "$500-3,000", "en": {"headline": "Turn one-time buyers into predictable monthly revenue", "subhead": "We install a subscribe and save program that gets first-time customers to opt into recurring orders, then keeps them paying month after month. Your best products refill themselves on autopilot.", "forWho": "For: ecommerce brands selling consumables or replenishable products that should be reordered, not bought once.", "includes": ["Subscribe and save offer built and priced to convert", "Recurring billing and fulfillment wired into your store", "Smart cadence logic so refills land before customers run out", "Churn-cutting flows: pause, swap, skip, win-back", "Subscriber dashboard tracking active subs, retention, and recurring revenue"], "outcome": "You stop re-earning every sale from scratch. A growing base of subscribers pays you on schedule, lifetime value climbs, and your revenue becomes something you can forecast instead of chase.", "problem": "You sell products people run out of and rebuy, but every order starts from zero: new ad, new click, new convincing. The customer who loved your product six weeks ago is gone, and you are paying to win them back as if they never met you.", "howItWorks": [{"t": "Map the refill", "d": "We find the products customers naturally reorder and set the exact cadence each one should ship on so refills arrive right before they run out."}, {"t": "Build the offer", "d": "We construct and price a subscribe and save offer that makes recurring the obvious choice, then wire the recurring billing and fulfillment into your store."}, {"t": "Defend the base", "d": "We install pause, swap, skip, and win-back flows plus a subscriber dashboard so cancellations turn into retained customers and you can see retention at a glance."}], "why": "Recurring revenue is the same machine we run on our own stores, not a theory from a slide deck. When a refill cadence is matched to how fast people actually use a product, opting in feels like convenience instead of commitment, and that is what keeps subscribers paying long past the first order.", "faq": [{"q": "Will subscriptions cannibalize my one-time sales?", "a": "No. The subscribe and save offer is positioned for buyers who were already going to reorder anyway, so you are converting repeat purchases you would have had to re-earn into locked-in recurring revenue, not discounting first-time buyers who would have paid full price."}, {"q": "What if my churn is high once people subscribe?", "a": "That is exactly what the pause, swap, skip, and win-back flows are for. Most cancellations are about timing or too much product, not the product itself, so we give subscribers a way to stay instead of leaving, and the dashboard shows you where churn is actually coming from."}, {"q": "Does this only work for supplements or specific products?", "a": "It works for anything people run out of and rebuy: consumables, refills, replenishables. If a customer has a natural reason to reorder on a predictable rhythm, we can build a subscription around it."}], "cta": "Get started"}, "fr": {"headline": "Transformez vos acheteurs uniques en revenu mensuel prévisible", "subhead": "On installe un programme d'abonnement qui pousse vos nouveaux clients à opter pour des commandes récurrentes, puis qui les garde mois après mois. Vos meilleurs produits se réapprovisionnent tout seuls.", "forWho": "Pour : les marques ecommerce qui vendent des consommables ou des produits à renouveler, ceux qu'on rachète au lieu d'acheter une seule fois.", "includes": ["Offre d'abonnement construite et calibrée pour convertir", "Facturation et expédition récurrentes branchées à votre boutique", "Cadence intelligente pour livrer avant que le client manque de stock", "Flux anti-résiliation : pause, échange, saut de livraison, réactivation", "Tableau de bord des abonnés : abonnements actifs, rétention, revenu récurrent"], "outcome": "Vous arrêtez de regagner chaque vente à zéro. Une base d'abonnés qui grandit vous paie à date fixe, la valeur à vie augmente, et votre revenu devient prévisible au lieu d'être une course perpétuelle.", "problem": "Vous vendez des produits que les gens finissent et rachètent, mais chaque commande repart de zéro : nouvelle pub, nouveau clic, nouvel argumentaire. Le client qui adorait votre produit il y a six semaines est parti, et vous payez pour le reconquérir comme s'il ne vous avait jamais connu.", "howItWorks": [{"t": "Cibler le réachat", "d": "On repère les produits que vos clients rachètent naturellement et on fixe la cadence exacte de chacun pour que le réapprovisionnement arrive juste avant qu'ils manquent de stock."}, {"t": "Bâtir l'offre", "d": "On construit et on calibre une offre d'abonnement qui fait du récurrent le choix évident, puis on branche la facturation et l'expédition récurrentes à votre boutique."}, {"t": "Défendre la base", "d": "On installe les flux pause, échange, saut de livraison et réactivation, plus un tableau de bord des abonnés, pour transformer les résiliations en clients retenus et voir la rétention d'un coup d'œil."}], "why": "Le revenu récurrent, c'est la même machine qu'on fait tourner sur nos propres boutiques, pas une théorie sortie d'une présentation. Quand la cadence de réapprovisionnement colle au rythme réel d'utilisation du produit, s'abonner devient un réflexe de commodité plutôt qu'un engagement, et c'est ça qui garde les abonnés payants bien après la première commande.", "faq": [{"q": "Est-ce que les abonnements vont cannibaliser mes ventes uniques ?", "a": "Non. L'offre d'abonnement vise les clients qui allaient déjà racheter de toute façon, donc vous convertissez des réachats que vous auriez dû regagner en revenu récurrent verrouillé, sans rabais sur les nouveaux clients qui auraient payé plein prix."}, {"q": "Et si mon taux de résiliation grimpe une fois les gens abonnés ?", "a": "C'est exactement le rôle des flux pause, échange, saut de livraison et réactivation. La plupart des résiliations sont une question de timing ou de surplus de produit, pas le produit lui-même, alors on donne à l'abonné un moyen de rester au lieu de partir, et le tableau de bord vous montre d'où vient vraiment la perte."}, {"q": "Est-ce que ça marche seulement pour les suppléments ou des produits précis ?", "a": "Ça marche pour tout ce que les gens finissent et rachètent : consommables, recharges, produits à renouveler. Si un client a une raison naturelle de recommander à un rythme prévisible, on peut bâtir un abonnement autour."}], "cta": "Commencer"}, "nameFr": "Abonnements et réapprovisionnement"}, {"id": "product-sourcing", "cat": "ecom", "hero": false, "icon": "📦", "name": "Product Sourcing & Validation", "oneLiner": "Test demand first; order inventory only when sales come.", "model": "%", "value": "$150-900/product", "en": {"headline": "Prove the Demand Before You Buy the Inventory", "subhead": "We test live demand for a product before a single unit is ordered. You only commit to stock once real buyers have already raised their hand.", "forWho": "For: ecom operators tired of cash trapped in inventory that never sells.", "includes": ["Demand validation tests run on real traffic, not guesses", "Winning-product shortlist with the data behind each pick", "Vetted supplier and sample sourcing for proven winners", "Landing page and offer built to measure true buy intent", "Go or kill call on every product, backed by the numbers"], "outcome": "You stop gambling on hunches and stockpiling dead SKUs. Capital goes only into products that already proved they sell, so your shelf turns into cash instead of a liability.", "cta": "Get started", "problem": "You pick a product that looks like a winner, place a big order, and then watch it sit. The cash is gone, the warehouse is full, and you are stuck running ads to clear stock that buyers never actually wanted.", "howItWorks": [{"t": "Build the test", "d": "We put each candidate product on a real landing page and offer designed to measure genuine buy intent."}, {"t": "Run live demand", "d": "We send real traffic to it and track what people actually click, add, and try to buy, not what they say in a survey."}, {"t": "Go, kill, or source", "d": "Products that clear the bar get vetted suppliers and samples lined up, the rest get killed before you spend a dollar on inventory."}], "why": "We run this same machine on our own stores before we touch yours, so you are buying a validated process, not a theory. Letting real buyers decide with their wallet beats any guru's gut, and it means stock only moves when the demand is already proven.", "faq": [{"q": "How is this different from just reading product research tools?", "a": "Research tools show you what sold for someone else in the past. We test whether buyers want it from you, right now, on your traffic, before you commit a cent to inventory."}, {"q": "Do I have to pay for the inventory upfront to test?", "a": "No. The whole point is to validate demand first, so you only source and order stock for products that already proved they convert."}, {"q": "What if none of my product ideas pass the test?", "a": "Then we just saved you from a dead order, and we shortlist new candidates to test until you have a winner worth backing with real money."}]}, "fr": {"headline": "Prouvez la demande avant d'acheter le stock", "subhead": "On teste la demande réelle pour un produit avant qu'une seule unité soit commandée. Vous vous engagez sur l'inventaire seulement quand de vrais acheteurs ont déjà levé la main.", "forWho": "Pour : les opérateurs ecom fatigués de voir leur cash gelé dans du stock qui ne se vend jamais.", "includes": ["Tests de demande sur du vrai trafic, pas des suppositions", "Liste de produits gagnants avec la donnée derrière chaque choix", "Sourcing de fournisseurs et d'échantillons validés pour les gagnants", "Page de vente et offre conçues pour mesurer la vraie intention d'achat", "Décision go ou kill sur chaque produit, appuyée par les chiffres"], "outcome": "Vous arrêtez de parier sur des intuitions et d'empiler des SKU morts. Le capital va seulement vers des produits qui ont déjà prouvé qu'ils se vendent, donc votre tablette se transforme en cash au lieu d'un boulet.", "cta": "Commencer", "problem": "Vous choisissez un produit qui a l'air gagnant, vous passez une grosse commande, puis vous le regardez dormir. Le cash est parti, l'entrepôt est plein, et vous êtes pris à brûler du budget pub pour écouler un stock que les acheteurs n'ont jamais vraiment voulu.", "howItWorks": [{"t": "Bâtir le test", "d": "On place chaque produit candidat sur une vraie page de vente et une offre conçues pour mesurer l'intention d'achat réelle."}, {"t": "Lancer la demande", "d": "On envoie du vrai trafic dessus et on suit ce que les gens cliquent, ajoutent et tentent d'acheter, pas ce qu'ils disent dans un sondage."}, {"t": "Go, kill ou sourcer", "d": "Les produits qui passent la barre obtiennent des fournisseurs validés et des échantillons, les autres sont tués avant que vous dépensiez un dollar en inventaire."}], "why": "On fait rouler cette même machine sur nos propres boutiques avant d'y toucher pour vous, donc vous achetez un processus validé, pas une théorie. Laisser de vrais acheteurs décider avec leur portefeuille bat l'intuition de n'importe quel gourou, et ça veut dire que le stock bouge seulement quand la demande est déjà prouvée.", "faq": [{"q": "En quoi c'est différent de simplement lire des outils de recherche de produits ?", "a": "Les outils de recherche montrent ce qui s'est vendu pour quelqu'un d'autre dans le passé. Nous, on teste si les acheteurs le veulent de vous, maintenant, sur votre trafic, avant que vous engagiez un sou en inventaire."}, {"q": "Est-ce que je dois payer le stock d'avance pour tester ?", "a": "Non. Le but, c'est justement de valider la demande en premier, donc vous sourcez et commandez seulement les produits qui ont déjà prouvé qu'ils convertissent."}, {"q": "Et si aucune de mes idées de produits ne passe le test ?", "a": "Alors on vient de vous éviter une commande morte, et on bâtit une nouvelle liste de candidats à tester jusqu'à ce que vous ayez un gagnant qui mérite votre argent."}]}, "nameFr": "Sourcing et validation de produits"}, {"id": "ecom-cro", "cat": "ecom", "hero": false, "icon": "🧪", "name": "Ecommerce Audit & CRO", "oneLiner": "Find the leaks costing you orders, then fix them.", "model": "1x", "value": "$1,500-7,500", "en": {"headline": "Stop leaking orders your store already earned", "subhead": "We trace every drop-off from ad click to checkout and seal the leaks killing your conversion rate. The traffic you pay for finally turns into sales.", "forWho": "For: Shopify and ecom brands with real traffic but a conversion rate that won't move.", "includes": ["Full funnel teardown: ad to PDP to cart to checkout", "Session replays and heatmaps on your top pages", "Prioritized leak list, ranked by revenue impact", "Done-for-you fixes on PDP, cart, and checkout", "Before/after conversion tracking so wins are proven"], "outcome": "More of the visitors you already pay for become buyers, so the same traffic and ad spend produce more orders. You see exactly which fix earned what.", "cta": "Get my free leak audit", "problem": "You are paying for traffic that lands, looks, and leaves. Visitors add to cart, hit checkout, and vanish, and you have no idea which step is bleeding the orders you already paid to win.", "howItWorks": [{"t": "Map the funnel", "d": "We watch real sessions, heatmaps, and analytics across every step from ad click to confirmed order to find where buyers actually quit."}, {"t": "Rank the leaks", "d": "We turn every drop-off into a prioritized list, ordered by how much revenue each fix is likely to recover first."}, {"t": "Fix and measure", "d": "We implement the changes on your PDP, cart, and checkout, then track conversion before and after so every win is proven."}], "why": "We do not run this on a sample store. We run the same teardown on our own offers and the brands we operate, so you get fixes pressure-tested by people who actually live in checkout data, not a generic best-practices checklist.", "faq": [{"q": "Do I need more traffic for this to work?", "a": "No. This works on the traffic you already have. The whole point is to convert more of the visitors you are already paying for, not to send you chasing more clicks."}, {"q": "Will you break my store or theme while making changes?", "a": "No. We test changes safely and roll them out so nothing on your live store goes down. Every fix is tracked, so if something does not lift conversion, we know and we adjust."}, {"q": "How fast will I see results?", "a": "You see the prioritized leak list early, so you know what is costing you from the start. Conversion lifts show up as we ship fixes and the before/after data comes in, not months later."}]}, "fr": {"headline": "Arrêtez de perdre les commandes déjà gagnées", "subhead": "On retrace chaque point d'abandon, du clic publicitaire au paiement, et on colmate les fuites qui plombent votre taux de conversion. Le trafic que vous payez se transforme enfin en ventes.", "forWho": "Pour : les marques Shopify et e-commerce qui ont du vrai trafic, mais un taux de conversion qui ne bouge pas.", "includes": ["Analyse complète de l'entonnoir : pub, fiche produit, panier, paiement", "Rejeux de sessions et cartes de chaleur sur vos pages clés", "Liste des fuites priorisée selon l'impact sur les revenus", "Corrections faites pour vous sur la fiche, le panier et le paiement", "Suivi de conversion avant/après pour prouver chaque gain"], "outcome": "Une plus grande part des visiteurs que vous payez déjà deviennent des acheteurs, donc le même trafic et le même budget pub génèrent plus de commandes. Vous voyez exactement quelle correction a rapporté quoi.", "cta": "Obtenir mon audit gratuit", "problem": "Vous payez pour du trafic qui arrive, regarde et repart. Les visiteurs ajoutent au panier, atteignent le paiement et disparaissent, et vous ne savez pas quelle étape vous fait perdre les commandes que vous avez déjà payées pour gagner.", "howItWorks": [{"t": "Cartographier l'entonnoir", "d": "On observe les vraies sessions, les cartes de chaleur et les données à chaque étape, du clic publicitaire à la commande confirmée, pour repérer où les acheteurs abandonnent vraiment."}, {"t": "Prioriser les fuites", "d": "On transforme chaque point d'abandon en une liste priorisée, classée selon le montant de revenus que chaque correction peut récupérer en premier."}, {"t": "Corriger et mesurer", "d": "On applique les changements sur votre fiche produit, votre panier et votre paiement, puis on suit la conversion avant et après pour prouver chaque gain."}], "why": "On ne fait pas ça sur une boutique de démonstration. On applique la même analyse à nos propres offres et aux marques qu'on opère, alors vous obtenez des corrections testées par des gens qui vivent vraiment dans les données de paiement, pas une liste générique de bonnes pratiques.", "faq": [{"q": "Ai-je besoin de plus de trafic pour que ça fonctionne ?", "a": "Non. Ça fonctionne avec le trafic que vous avez déjà. Tout le but est de convertir une plus grande part des visiteurs que vous payez déjà, pas de vous envoyer chercher encore plus de clics."}, {"q": "Allez-vous briser ma boutique ou mon thème en faisant les changements ?", "a": "Non. On teste les changements en sécurité et on les déploie sans faire tomber votre boutique en ligne. Chaque correction est suivie, donc si une n'améliore pas la conversion, on le voit et on ajuste."}, {"q": "En combien de temps vais-je voir des résultats ?", "a": "Vous recevez la liste des fuites priorisée dès le début, alors vous savez tout de suite ce qui vous coûte. Les gains de conversion apparaissent à mesure qu'on déploie les corrections et que les données avant/après arrivent, pas dans des mois."}]}, "nameFr": "Audit e-commerce et CRO"}, {"id": "ad-infrastructure", "cat": "ads", "hero": true, "icon": "⚙️", "name": "Ad Infrastructure", "oneLiner": "Approved ad accounts, Merchant Center approval and management, bundled.", "model": "1x+/mo", "value": "$1,500-6,000 setup + mgmt", "en": {"headline": "Skip the bans. Launch on approved ad accounts.", "subhead": "We hand you pre approved ad accounts and a green Merchant Center, fully managed, so your campaigns go live and stay live. No suspensions, no appeals, no waiting.", "forWho": "For: operators tired of disabled accounts, rejected products, and Merchant Center suspensions killing their ad spend.", "includes": ["Approved Google and Meta ad accounts, ready to spend", "Merchant Center setup, approval, and ongoing management", "Product feed fixes that clear policy review", "Account warmup and spend scaling so you avoid flags", "Suspension monitoring and fast reinstatement if anything trips"], "outcome": "You stop fighting the platforms and start scaling. Your ads run on infrastructure that survives policy reviews, so your money goes to traffic instead of appeals.", "cta": "Get started", "problem": "You finally get a winning product, then Google disables the account or Merchant Center suspends your feed and the revenue stops overnight. Every day stuck in appeals is a day your competitors keep spending and you do not.", "howItWorks": [{"t": "We assess your setup", "d": "On the call we map what got flagged, which platforms you need, and what your feed and offer look like to a policy reviewer."}, {"t": "We hand you the accounts", "d": "You get approved Google and Meta accounts plus a clean Merchant Center, with your feed corrected so it clears review the first time."}, {"t": "We manage and protect spend", "d": "We warm the accounts, scale your budget carefully, and watch for flags so a suspension never quietly kills your campaigns."}], "why": "We run paid traffic on this exact infrastructure for our own offers, so we are not guessing about what survives a policy review. When the accounts are the machine your own money runs on, keeping them green is not a side service, it is the whole job.", "faq": [{"q": "Are these accounts compliant, or am I just renting a workaround?", "a": "These are real, managed accounts set up to pass policy, not a hack that dies on the next review. We fix the feed and offer issues that actually trigger suspensions so the account holds up while you scale."}, {"q": "What happens if an account still gets suspended?", "a": "We monitor for flags and move fast on reinstatement, and because we manage multiple accounts you are not betting your whole business on one. The goal is that one trip never takes your spend offline for long."}, {"q": "Do you handle Merchant Center, or just the ad accounts?", "a": "Both. We set up, approve, and manage Merchant Center alongside the ad accounts and correct the product feed, because a green Merchant Center is usually where Shopping campaigns live or die."}]}, "fr": {"headline": "Fini les bannissements. Lancez sur des comptes approuvés.", "subhead": "On vous remet des comptes publicitaires déjà approuvés et un Merchant Center au vert, gérés de A à Z, pour que vos campagnes partent et restent en ligne. Pas de suspensions, pas d'appels, pas d'attente.", "forWho": "Pour : les opérateurs écœurés des comptes désactivés, des produits refusés et des suspensions Merchant Center qui tuent leur budget pub.", "includes": ["Comptes pub Google et Meta approuvés, prêts à dépenser", "Configuration, approbation et gestion continue du Merchant Center", "Correction du flux de produits pour passer la revue des politiques", "Réchauffement du compte et montée des dépenses sans déclencher de flag", "Surveillance des suspensions et réactivation rapide si quelque chose accroche"], "outcome": "Vous arrêtez de vous battre avec les plateformes et vous commencez à scaler. Vos pubs roulent sur une infrastructure qui survit aux revues de politiques, donc votre argent va au trafic au lieu des appels.", "cta": "Commencer", "problem": "Vous trouvez enfin un produit gagnant, puis Google désactive le compte ou le Merchant Center suspend votre flux et les revenus s'arrêtent du jour au lendemain. Chaque journée coincée dans les appels est une journée où vos concurrents continuent de dépenser et pas vous.", "howItWorks": [{"t": "On évalue votre setup", "d": "Pendant l'appel, on repère ce qui a été flaggé, les plateformes dont vous avez besoin, et l'allure de votre flux et de votre offre aux yeux d'un réviseur de politiques."}, {"t": "On vous remet les comptes", "d": "Vous recevez des comptes Google et Meta approuvés plus un Merchant Center propre, avec votre flux corrigé pour passer la revue du premier coup."}, {"t": "On gère et protège les dépenses", "d": "On réchauffe les comptes, on monte le budget avec soin et on surveille les flags pour qu'une suspension ne vienne jamais tuer vos campagnes en silence."}], "why": "On fait rouler du trafic payant sur cette infrastructure exacte pour nos propres offres, donc on ne devine pas ce qui survit à une revue de politiques. Quand les comptes sont la machine sur laquelle votre propre argent roule, les garder au vert n'est pas un service à côté, c'est tout le travail.", "faq": [{"q": "Ces comptes sont-ils conformes, ou je loue juste un contournement ?", "a": "Ce sont de vrais comptes gérés, montés pour passer les politiques, pas un truc qui meurt à la prochaine revue. On corrige les problèmes de flux et d'offre qui déclenchent réellement les suspensions pour que le compte tienne pendant que vous scalez."}, {"q": "Que se passe-t-il si un compte se fait quand même suspendre ?", "a": "On surveille les flags et on agit vite sur la réactivation, et comme on gère plusieurs comptes, vous ne misez pas toute votre business sur un seul. L'objectif, c'est qu'un accroc ne mette jamais vos dépenses hors ligne longtemps."}, {"q": "Vous gérez le Merchant Center, ou seulement les comptes pub ?", "a": "Les deux. On configure, approuve et gère le Merchant Center avec les comptes pub et on corrige le flux de produits, parce qu'un Merchant Center au vert, c'est souvent là que vos campagnes Shopping vivent ou meurent."}]}, "nameFr": "Infrastructure publicitaire"}, {"id": "ai-product-photos", "cat": "ads", "hero": false, "icon": "📸", "name": "AI Product Photography", "oneLiner": "A 24-hour AI catalog drop instead of a $2,000 shoot.", "model": "per", "value": "$35-120/product", "en": {"headline": "A full product catalog, shot overnight, no studio", "subhead": "We turn your raw product into scroll-stopping AI photography: clean packshots, lifestyle scenes, and ad-ready angles. Your catalog looks like a brand worth buying, in 24 hours instead of weeks.", "forWho": "For: e-commerce and DTC brands that need premium product images fast, without booking a photographer.", "includes": ["White-background packshots for every listing", "Lifestyle and in-context scenes for ads and social", "Multiple angles and crops per product", "Consistent look locked across your whole catalog", "Files sized for Shopify, Amazon, Meta and TikTok"], "outcome": "You launch and test products at the speed of your ideas, with images that lift click-through and trust on every channel. No studio day, no reshoots, no waiting on a slot.", "cta": "Get started", "problem": "Your product photos are the first thing a buyer judges, and right now they are holding you back: phone shots, mismatched backgrounds, and a catalog that looks thrown together. Booking a studio means weeks of lead time and a reshoot every time you add a SKU, so half your products go live with images that kill the sale.", "howItWorks": [{"t": "Send your products", "d": "You ship us your raw product shots or a single sample image, plus any brand references you want us to match."}, {"t": "We generate the set", "d": "We produce packshots, lifestyle scenes, and multiple angles, locking one consistent look across every product in your catalog."}, {"t": "You get launch-ready files", "d": "You receive channel-sized images for Shopify, Amazon, Meta, and TikTok, ready to drop straight into your listings and ads."}], "why": "We run our own stores, so these are the exact images we use to launch and scale products ourselves, not a service we sell from the outside. We know what an image has to do to win the click and earn the trust, because we are testing it with our own money every week.", "faq": [{"q": "Will the photos actually look like my real product?", "a": "Yes. We work from your real product so the shape, color, and key details stay accurate, and we send revisions until each shot matches what shows up in the box."}, {"q": "How many products can you handle at once?", "a": "Whole catalogs. Because there is no studio day to book, scaling from ten products to a few hundred adds turnaround time, not a different process, and the look stays consistent across every one."}, {"q": "What if I need a specific style or brand look?", "a": "Send references, a competitor you admire, or your existing brand assets, and we lock that style across the full set so your catalog reads as one cohesive brand."}]}, "fr": {"headline": "Un catalogue produit complet, shooté en une nuit, sans studio", "subhead": "Nous transformons vos produits bruts en photographie IA qui arrête le pouce : packshots impeccables, scènes lifestyle et angles prêts pour la pub. Votre catalogue a l'air d'une vraie marque, en 24 heures au lieu de plusieurs semaines.", "forWho": "Pour : les marques e-commerce et DTC qui ont besoin d'images produit haut de gamme rapidement, sans réserver de photographe.", "includes": ["Packshots sur fond blanc pour chaque fiche produit", "Scènes lifestyle et en contexte pour la pub et les réseaux sociaux", "Plusieurs angles et cadrages par produit", "Un look cohérent verrouillé sur tout votre catalogue", "Fichiers dimensionnés pour Shopify, Amazon, Meta et TikTok"], "outcome": "Vous lancez et testez vos produits à la vitesse de vos idées, avec des images pensées pour faire grimper le taux de clics et la confiance sur chaque canal. Pas de journée en studio, pas de reprises, pas d'attente pour une plage horaire.", "cta": "Commencer", "problem": "Vos photos de produit sont la première chose qu'un acheteur juge, et présentement elles vous freinent : photos prises au téléphone, arrière-plans qui ne s'agencent pas, un catalogue qui a l'air bricolé. Réserver un studio veut dire des semaines d'attente et une reprise chaque fois que vous ajoutez un produit, alors la moitié de vos produits partent en ligne avec des images qui nuisent à la vente.", "howItWorks": [{"t": "Envoyez vos produits", "d": "Vous nous envoyez vos photos de produit brutes ou une seule image exemple, avec les références de marque que vous voulez qu'on respecte."}, {"t": "Nous générons la série", "d": "Nous produisons les packshots, les scènes lifestyle et plusieurs angles, en verrouillant un look cohérent sur chaque produit de votre catalogue."}, {"t": "Vous recevez des fichiers prêts à lancer", "d": "Vous recevez des images dimensionnées pour Shopify, Amazon, Meta et TikTok, prêtes à déposer directement dans vos fiches et vos pubs."}], "why": "Nous opérons nos propres boutiques, alors ce sont exactement les images que nous utilisons pour lancer et faire grandir nos produits nous-mêmes, pas un service que nous vendons de l'extérieur. Nous savons ce qu'une image doit accomplir pour gagner le clic et mériter la confiance, parce que nous la testons avec notre propre argent chaque semaine.", "faq": [{"q": "Est-ce que les photos vont vraiment ressembler à mon vrai produit ?", "a": "Oui. Nous travaillons à partir de votre vrai produit pour que la forme, la couleur et les détails clés restent fidèles, et nous envoyons des révisions jusqu'à ce que chaque photo corresponde à ce qui arrive dans la boîte."}, {"q": "Combien de produits pouvez-vous traiter d'un coup ?", "a": "Des catalogues complets. Comme il n'y a pas de journée en studio à réserver, passer de dix produits à quelques centaines ajoute du temps de livraison, pas un processus différent, et le look reste cohérent sur chacun."}, {"q": "Et si j'ai besoin d'un style ou d'un look de marque précis ?", "a": "Envoyez des références, un concurrent que vous admirez ou vos éléments de marque existants, et nous verrouillons ce style sur toute la série pour que votre catalogue se lise comme une seule marque cohérente."}]}, "nameFr": "Photographie de produits par IA"}, {"id": "white-label-affiliate", "cat": "software", "hero": false, "icon": "🤝", "name": "White-Label Affiliate Platform", "oneLiner": "Your own branded affiliate platform, live in a week.", "model": "Lic", "value": "$9,500-18,000", "en": {"headline": "Launch your own affiliate platform in a week", "subhead": "We hand you a fully branded affiliate program, partner links, tracking, and payouts running under your name. No third-party logos, no rev-share to a network.", "forWho": "For: brands and operators who want partners selling for them without paying a marketplace to own the relationship.", "includes": ["Branded affiliate portal on your domain, your logo, your colors", "Automated partner signup, approval, and unique tracking links", "Real-time clicks, conversions, and commission dashboard", "Hands-off payout calculation and affiliate statements", "Done-for-you setup and onboarding, live in a week"], "outcome": "You build an army of partners promoting you on commission, own every customer and every data point, and stop renting your growth from a network that takes a cut.", "problem": "You want partners selling for you, but the easy route is a marketplace that slaps its logo on the relationship, takes a cut of every sale, and keeps the customer data. You end up renting growth you should own.", "howItWorks": [{"t": "We build your portal", "d": "We stand up a branded affiliate portal on your domain with signup, approval, and unique tracking links wired in."}, {"t": "Partners go live", "d": "Your affiliates self-serve their links and start driving clicks and conversions you watch in real time."}, {"t": "Payouts run themselves", "d": "Commissions and statements calculate automatically, so you approve and pay without doing the math."}], "why": "We run affiliate programs on our own offers before we hand them to you, so the setup is built from what actually moves partners, not a generic template. Owning the platform means you keep the customer, the data, and the relationship instead of a network.", "faq": [{"q": "Do my customers ever see another company's branding?", "a": "No. The portal lives on your domain with your logo and colors. Partners and customers only ever see you."}, {"q": "Do I have to manage payouts manually?", "a": "No. The system calculates commissions and generates affiliate statements for you. You review and approve, we handle the math behind it."}, {"q": "How fast can this actually be live?", "a": "We build, brand, and onboard in about a week. Setup is done-for-you, so you are recruiting partners while competitors are still picking a network."}], "cta": "Get started"}, "fr": {"headline": "Lancez votre plateforme d'affiliation en une semaine", "subhead": "On vous remet un programme d'affiliation entièrement à votre image, avec liens partenaires, suivi et paiements qui roulent sous votre nom. Aucun logo de tiers, aucune commission versée à un réseau.", "forWho": "Pour : les marques et les opérateurs qui veulent des partenaires qui vendent pour eux sans payer une plateforme pour posséder la relation.", "includes": ["Portail d'affiliation à votre image sur votre domaine, votre logo, vos couleurs", "Inscription, approbation et liens de suivi uniques automatisés pour vos partenaires", "Tableau de bord en temps réel des clics, des conversions et des commissions", "Calcul des paiements et relevés d'affiliés sans intervention de votre part", "Configuration et intégration clé en main, en ligne en une semaine"], "outcome": "Vous bâtissez une armée de partenaires qui vous font la promotion à la commission, vous possédez chaque client et chaque donnée, et vous arrêtez de louer votre croissance à un réseau qui prend sa part.", "problem": "Vous voulez des partenaires qui vendent pour vous, mais la voie facile, c'est une plateforme qui colle son logo sur la relation, prend une part de chaque vente et garde les données de vos clients. Vous finissez par louer une croissance qui devrait vous appartenir.", "howItWorks": [{"t": "On bâtit votre portail", "d": "On déploie un portail d'affiliation à votre image sur votre domaine, avec inscription, approbation et liens de suivi uniques intégrés."}, {"t": "Vos partenaires démarrent", "d": "Vos affiliés récupèrent eux-mêmes leurs liens et commencent à générer des clics et des conversions que vous suivez en temps réel."}, {"t": "Les paiements roulent seuls", "d": "Les commissions et les relevés se calculent automatiquement, vous approuvez et payez sans faire les calculs."}], "why": "On fait rouler des programmes d'affiliation sur nos propres offres avant de vous les remettre, donc la configuration est bâtie à partir de ce qui motive réellement les partenaires, pas d'un modèle générique. Posséder la plateforme, c'est garder le client, les données et la relation au lieu de les confier à un réseau.", "faq": [{"q": "Est-ce que mes clients voient la marque d'une autre entreprise ?", "a": "Non. Le portail vit sur votre domaine, avec votre logo et vos couleurs. Vos partenaires et vos clients ne voient que vous."}, {"q": "Dois-je gérer les paiements à la main ?", "a": "Non. Le système calcule les commissions et génère les relevés d'affiliés pour vous. Vous révisez et approuvez, on s'occupe des calculs derrière."}, {"q": "À quelle vitesse ça peut vraiment être en ligne ?", "a": "On bâtit, on personnalise et on intègre en environ une semaine. La configuration est clé en main, donc vous recrutez des partenaires pendant que vos concurrents choisissent encore un réseau."}], "cta": "Commencer"}, "nameFr": "Plateforme d'affiliation en marque blanche"}, {"id": "custom-app", "cat": "software", "hero": false, "icon": "🧩", "name": "Custom App Development", "oneLiner": "We build your app, end to end (intervos.app proof).", "model": "1x", "value": "$4,000-80,000", "en": {"headline": "Your software, built end to end and shipped", "subhead": "We design, build, and launch the custom app your operation actually needs. The same way we built intervos.app for ourselves.", "forWho": "For: operators tired of duct-taping spreadsheets and off-the-shelf tools that almost fit.", "includes": ["Scoping and product spec mapped to your real workflow", "Full UI and UX design, not a template", "Frontend, backend, database, and integrations built", "Auth, payments, dashboards, and admin wired in", "Deployed, tested, and handed off ready to run"], "outcome": "You get a real product that runs your process instead of fighting it. Built by a team that ships its own software, so the thing works the day it launches.", "cta": "Get started", "problem": "You are running a real operation on a stack of spreadsheets, browser tabs, and tools that each do 70 percent of the job. Every gap gets filled by a person copying data by hand, and that person is usually you.", "howItWorks": [{"t": "Map the workflow", "d": "We sit with you, learn how your operation actually runs, and turn it into a clear product spec before anyone writes a line of code."}, {"t": "Design and build", "d": "We design the interface and build the frontend, backend, database, and integrations as one connected product, not a pile of plugins."}, {"t": "Launch and hand off", "d": "We deploy it, test it against real use, and hand you a working app your team can run on day one."}], "why": "We build and run our own software, like intervos.app, so we design for the operator using it every day instead of a demo. You get a product made by people who live with the consequences of bad software, not a contractor who disappears after launch.", "faq": [{"q": "Do I own the app and the code when it is done?", "a": "Yes. It is your product. You own the code, the data, and the accounts it runs on, and we hand everything off so you are never locked in."}, {"q": "What if my workflow changes after launch?", "a": "It will, and the app is built to change with it. Because we mapped your real process first, adding or adjusting features later is straightforward instead of a rebuild."}, {"q": "I am not technical. Can I still run it?", "a": "That is who we build for. We design the interface so your team can use it without training, and we hand off a clear setup so you are never stuck waiting on a developer."}]}, "fr": {"headline": "Votre logiciel, construit au complet et livré", "subhead": "On conçoit, on développe et on lance l'application sur mesure dont votre opération a vraiment besoin. Comme on a bâti intervos.app pour nous-mêmes.", "forWho": "Pour : les opérateurs tannés de coller des Excel et des outils tout faits qui ne fittent jamais vraiment.", "includes": ["Cadrage et spécifications calqués sur votre vrai flux de travail", "Design UI et UX complet, pas un gabarit", "Frontend, backend, base de données et intégrations bâtis", "Connexion, paiements, tableaux de bord et admin intégrés", "Déployé, testé et remis prêt à rouler"], "outcome": "Vous obtenez un vrai produit qui fait rouler votre processus au lieu de le freiner. Bâti par une équipe qui livre son propre logiciel, donc ça marche dès le lancement.", "cta": "Commencer", "problem": "Vous faites rouler une vraie opération sur une pile d'Excel, d'onglets ouverts et d'outils qui font chacun 70 pour cent de la job. Chaque trou se bouche en copiant des données à la main, et la personne qui le fait, c'est souvent vous.", "howItWorks": [{"t": "Cartographier le flux", "d": "On s'assoit avec vous, on apprend comment votre opération roule vraiment, et on en fait une spec claire avant d'écrire une seule ligne de code."}, {"t": "Concevoir et bâtir", "d": "On conçoit l'interface et on bâtit le frontend, le backend, la base de données et les intégrations comme un seul produit connecté, pas un paquet de plugins."}, {"t": "Lancer et remettre", "d": "On déploie, on teste en conditions réelles et on vous remet une application fonctionnelle que votre équipe peut utiliser dès le jour un."}], "why": "On bâtit et on fait rouler notre propre logiciel, comme intervos.app, donc on conçoit pour l'opérateur qui s'en sert chaque jour, pas pour une démo. Vous obtenez un produit fait par des gens qui vivent avec les conséquences d'un mauvais logiciel, pas un contracteur qui disparaît après le lancement.", "faq": [{"q": "Est-ce que l'application et le code m'appartiennent une fois terminés ?", "a": "Oui. C'est votre produit. Vous possédez le code, les données et les comptes sur lesquels ça roule, et on vous remet tout pour que vous ne soyez jamais pris au piège."}, {"q": "Et si mon flux de travail change après le lancement ?", "a": "Il va changer, et l'application est bâtie pour évoluer avec. Comme on a cartographié votre vrai processus en premier, ajouter ou ajuster des fonctions plus tard est simple au lieu d'être à recommencer."}, {"q": "Je ne suis pas technique. Est-ce que je peux quand même la faire rouler ?", "a": "C'est exactement pour ça qu'on bâtit. On conçoit l'interface pour que votre équipe s'en serve sans formation, et on remet une mise en place claire pour que vous ne soyez jamais bloqué à attendre un développeur."}]}, "nameFr": "Développement d'applications sur mesure"}, {"id": "custom-dashboards", "cat": "software", "hero": false, "icon": "📟", "name": "Custom Dashboards & Ops Centers", "oneLiner": "Analytics, reporting and ops centers built to spec.", "model": "1x", "value": "$3,000-25,000", "en": {"headline": "See Your Whole Business On One Screen", "subhead": "We build the dashboard and ops center that pulls every number you actually run on into one live view. No more digging through tabs, exports, or someone else's report.", "forWho": "For: operators running multiple stores, locations, or revenue streams who need their real numbers in one place, now.", "includes": ["Live ops center pulling sales, ads, and fulfillment into one view", "Connected to your real sources: Shopify, ads, sheets, your database", "Built to your exact metrics and daily decisions, not a template", "Alerts that flag what is breaking before it costs you", "Role views so each person sees only what they own"], "outcome": "You open one screen and know exactly where the business stands and what to fix today. Decisions that used to take an hour of pulling reports take ten seconds.", "problem": "Your numbers live in ten places: Shopify, the ad accounts, a fulfillment tool, three spreadsheets, and someone's head. By the time you stitch them together to see what is actually happening, the moment to act has already passed.", "howItWorks": [{"t": "We map your numbers", "d": "We sit down and pin down the exact metrics you make decisions on and where each one actually lives today."}, {"t": "We wire the sources", "d": "We connect Shopify, your ad accounts, sheets, and your database so the data flows in live with no manual exports."}, {"t": "We build your view", "d": "We lay it out around your daily decisions, add the alerts that matter, and set role views so each person sees only what they own."}], "why": "We run our own stores and revenue streams on this exact kind of ops center, because guessing is expensive. You are not buying a template, you are getting the machine an operator built to watch their own money.", "faq": [{"q": "Can you connect the tools I already use?", "a": "Yes. Shopify, the major ad platforms, your spreadsheets, and most databases plug straight in. If you have an unusual source, tell us on the call and we will tell you honestly whether we can pull it in."}, {"q": "I do not want yet another login. Does this add work?", "a": "It removes work. The whole point is one screen instead of ten tabs, and the data flows in on its own. You open it, you read it, you make the call."}, {"q": "What if my metrics change as the business grows?", "a": "The dashboard is built to your decisions, so it bends with them. As you add stores, channels, or new numbers you watch, we adjust the view to match how you actually run."}], "cta": "Get started"}, "fr": {"headline": "Toute votre entreprise sur un seul écran", "subhead": "On bâtit le tableau de bord et le centre d'opérations qui rassemble en temps réel tous les chiffres sur lesquels vous roulez vraiment. Fini de fouiller dans les onglets, les exports ou le rapport de quelqu'un d'autre.", "forWho": "Pour les opérateurs qui gèrent plusieurs boutiques, points de vente ou sources de revenus et qui ont besoin de leurs vrais chiffres au même endroit, maintenant.", "includes": ["Centre d'opérations en direct qui réunit ventes, pubs et logistique dans une seule vue", "Branché sur vos vraies sources : Shopify, pubs, feuilles de calcul, votre base de données", "Bâti sur vos métriques exactes et vos décisions quotidiennes, pas un gabarit", "Alertes qui signalent ce qui brise avant que ça vous coûte cher", "Vues par rôle pour que chacun voie seulement ce qui le concerne"], "outcome": "Vous ouvrez un seul écran et vous savez où en est l'entreprise et quoi régler aujourd'hui. Des décisions qui prenaient une heure à sortir des rapports peuvent maintenant se prendre en quelques secondes.", "problem": "Vos chiffres vivent dans dix endroits : Shopify, les comptes publicitaires, un outil de logistique, trois feuilles de calcul et la tête de quelqu'un. Le temps que vous les rassembliez pour voir ce qui se passe vraiment, le moment d'agir est souvent déjà passé.", "howItWorks": [{"t": "On cartographie vos chiffres", "d": "On s'assoit avec vous pour cerner les métriques exactes sur lesquelles vous décidez et où chacune vit réellement aujourd'hui."}, {"t": "On branche les sources", "d": "On connecte Shopify, vos comptes publicitaires, vos feuilles et votre base de données pour que les données entrent en direct, sans export manuel."}, {"t": "On bâtit votre vue", "d": "On l'organise autour de vos décisions quotidiennes, on ajoute les alertes qui comptent et on règle les vues par rôle pour que chacun voie seulement ce qui le concerne."}], "why": "On roule nos propres boutiques et sources de revenus sur ce genre exact de centre d'opérations, parce que deviner coûte cher. Vous n'achetez pas un gabarit, vous recevez la machine qu'un opérateur a bâtie pour surveiller son propre argent.", "faq": [{"q": "Pouvez-vous vous brancher sur les outils que j'utilise déjà ?", "a": "Oui. Shopify, les grandes plateformes de pub, vos feuilles de calcul et la plupart des bases de données se branchent directement. Si vous avez une source inhabituelle, dites-le-nous sur l'appel et on vous dira honnêtement si on peut la rapatrier."}, {"q": "Je ne veux pas un autre login. Est-ce que ça ajoute du travail ?", "a": "Ça en enlève. Le but, c'est un seul écran au lieu de dix onglets, et les données entrent toutes seules. Vous l'ouvrez, vous le lisez, vous prenez la décision."}, {"q": "Et si mes métriques changent à mesure que l'entreprise grandit ?", "a": "Le tableau de bord est bâti sur vos décisions, donc il s'adapte avec elles. À mesure que vous ajoutez des boutiques, des canaux ou de nouveaux chiffres à suivre, on ajuste la vue pour qu'elle colle à votre vraie façon de rouler."}], "cta": "Commencer"}, "nameFr": "Tableaux de bord et centres d'opérations sur mesure"}, {"id": "privacy-analytics", "cat": "software", "hero": false, "icon": "🔒", "name": "Privacy-First Analytics", "oneLiner": "Cookieless, Law-25-friendly analytics under your brand.", "model": "Lic", "value": "$400-3,500/mo", "en": {"headline": "Know exactly what works, kill the cookie banner", "subhead": "Cookieless analytics that respects Quebec's Law 25 and shows you real visitor behavior without consent pop-ups. Your brand on the dashboard, not someone else's logo.", "forWho": "For: Quebec brands and agencies who need clean traffic data without the legal exposure of Google Analytics.", "includes": ["Cookieless tracking, no consent banner required", "Law 25 and GDPR compliant by default", "White-labeled dashboard under your own brand", "Real-time traffic, sources, and conversion events", "One-line script install on any site or store"], "outcome": "You finally see which pages and campaigns actually drive sales, while staying on the right side of Quebec privacy law and ditching the banner that scares visitors away.", "problem": "You are either flying blind because the cookie banner kills your data the moment someone clicks reject, or you are quietly breaking Law 25 by running Google Analytics that ships visitor data out of Quebec. Either way, you cannot trust your numbers and you cannot prove which campaigns actually pay.", "howItWorks": [{"t": "Drop in one line", "d": "We add a single lightweight script to your site or store, no plugins, no tag manager spaghetti, no consent gate."}, {"t": "We track cookieless", "d": "Every visit, source, and conversion gets measured at the server level without cookies or personal identifiers, so there is nothing to consent to."}, {"t": "You read your brand", "d": "You log into a dashboard under your own name and see live traffic, top pages, and the campaigns driving real sales."}], "why": "We run this exact stack on our own properties before we ever put it on a client site, so the dashboard you get is the one we trust to make our own decisions. Cookieless tracking captures the visitors that consent banners throw away, which means you are reading from more of your real traffic, not a consented sliver of it.", "faq": [{"q": "If there are no cookies, is the data still accurate?", "a": "Yes. Cookieless measurement counts every session, source, and conversion at the server level, and because nothing gets blocked by a reject click or an ad blocker, you usually see more of your real traffic than a cookie setup ever showed you."}, {"q": "Will I really not need a consent banner?", "a": "Correct. The tracking collects no personal identifiers and stores nothing that triggers consent under Law 25 or GDPR, so the banner that was scaring visitors off your site simply goes away."}, {"q": "Can I put my own brand on it for clients?", "a": "Yes. The dashboard is fully white-labeled, so your clients log in and see your name and your colors, never a third-party analytics logo."}], "cta": "Get started"}, "fr": {"headline": "Sachez ce qui fonctionne, sans bannière de témoins", "subhead": "Des statistiques sans témoins, conformes à la Loi 25 du Québec, qui montrent le vrai comportement de vos visiteurs sans fenêtre de consentement. Votre marque sur le tableau de bord, pas le logo d'un autre.", "forWho": "Pour : les marques et agences du Québec qui veulent des données propres sans le risque juridique de Google Analytics.", "includes": ["Suivi sans témoins, aucune bannière de consentement requise", "Conforme à la Loi 25 et au RGPD par défaut", "Tableau de bord en marque blanche sous votre identité", "Trafic, sources et conversions en temps réel", "Installation en une ligne sur tout site ou boutique"], "outcome": "Vous voyez enfin quelles pages et quelles campagnes génèrent réellement des ventes, tout en respectant la loi québécoise sur la vie privée et en éliminant la bannière qui fait fuir vos visiteurs.", "problem": "Soit vous avancez à l'aveugle parce que la bannière de témoins anéantit vos données dès qu'un visiteur clique sur refuser, soit vous enfreignez la Loi 25 sans le savoir en utilisant Google Analytics qui envoie les données de vos visiteurs hors du Québec. Dans les deux cas, vous ne pouvez pas vous fier à vos chiffres ni prouver quelles campagnes rapportent vraiment.", "howItWorks": [{"t": "Ajoutez une ligne", "d": "Nous installons un seul script léger sur votre site ou votre boutique, sans extension, sans gestionnaire de balises compliqué, sans fenêtre de consentement."}, {"t": "Suivi sans témoins", "d": "Chaque visite, source et conversion est mesurée au niveau du serveur, sans témoins ni identifiants personnels, donc il n'y a aucun consentement à demander."}, {"t": "Lisez sous votre marque", "d": "Vous vous connectez à un tableau de bord à votre nom et voyez en direct le trafic, les meilleures pages et les campagnes qui génèrent de vraies ventes."}], "why": "Nous utilisons exactement cette configuration sur nos propres sites avant de l'installer chez un client, donc le tableau de bord que vous recevez est celui sur lequel nous basons nos propres décisions. Le suivi sans témoins capte les visiteurs que les bannières de consentement laissent de côté, ce qui veut dire que vous lisez une plus grande part de votre vrai trafic, pas une fraction consentie.", "faq": [{"q": "Sans témoins, les données sont-elles quand même fiables ?", "a": "Oui. La mesure sans témoins compte chaque session, source et conversion au niveau du serveur, et comme rien n'est bloqué par un clic de refus ou un bloqueur de publicités, vous voyez souvent une plus grande part de votre vrai trafic qu'avec des témoins."}, {"q": "Vais-je vraiment pouvoir me passer de bannière de consentement ?", "a": "Exactement. Le suivi ne recueille aucun identifiant personnel et ne stocke rien qui déclenche le consentement sous la Loi 25 ou le RGPD, donc la bannière qui faisait fuir vos visiteurs disparaît tout simplement."}, {"q": "Puis-je y mettre ma propre marque pour mes clients ?", "a": "Oui. Le tableau de bord est entièrement en marque blanche, donc vos clients se connectent et voient votre nom et vos couleurs, jamais le logo d'un outil tiers."}], "cta": "Commencer"}, "nameFr": "Analytique axée sur la confidentialité"}, {"id": "fleet-qa", "cat": "software", "hero": false, "icon": "🛰️", "name": "Fleet QA-as-a-Service", "oneLiner": "Catch the broken form or wrong number across hundreds of sites.", "model": "/mo", "value": "$300-1,500/mo", "en": {"headline": "Catch the broken form before your customer does", "subhead": "We watch every form, phone number, and checkout across your entire fleet of sites, around the clock. The second something breaks, you know, not your visitors.", "forWho": "For: operators and agencies running dozens to hundreds of sites where one dead form quietly kills leads and sales.", "includes": ["Continuous monitoring of every form, button, and checkout flow", "Phone number and contact info verification across all sites", "Instant alerts the moment a flow breaks, by your channel", "One dashboard showing health status for your whole fleet", "Weekly QA report flagging what broke and what we fixed"], "outcome": "You stop losing silent leads and orders to errors nobody noticed for weeks. Every site in your fleet stays bookable, buyable, and reachable, without you checking a single one by hand.", "cta": "Get started", "problem": "A form stops sending, a checkout throws an error, a phone number goes dead, and you find out weeks later when leads mysteriously dried up. With dozens or hundreds of sites, nobody is testing every flow by hand, so broken paths bleed revenue in total silence.", "howItWorks": [{"t": "We map your flows", "d": "We catalog every form, button, contact number, and checkout across your full fleet so nothing critical goes unwatched."}, {"t": "We test on autopilot", "d": "Around the clock, we run real submissions and checks against each flow to confirm it actually completes, not just loads."}, {"t": "You get the alert first", "d": "The moment a flow breaks, an alert hits your channel with the site and the exact problem, plus it lands in your weekly QA report."}], "why": "This runs on the same system we built to keep our own fleet of sites converting, because we lost orders to silent breakages too. We test the way a real customer would, end to end, so you find out from us, not from a drop in your numbers.", "faq": [{"q": "Will testing my forms flood my CRM with junk leads?", "a": "No. We submit through controlled test paths and tag or isolate those entries so your real pipeline and reporting stay clean."}, {"q": "How many sites can you cover?", "a": "From a handful to several hundred. The monitoring is built for fleets, so adding more sites does not mean more manual work on your end."}, {"q": "How fast will I know when something breaks?", "a": "Within minutes of the failure, on the channel you choose, with the specific site and broken flow named so you or your team can act right away."}]}, "fr": {"headline": "Repérez le formulaire brisé avant votre client", "subhead": "On surveille chaque formulaire, numéro de téléphone et tunnel d'achat sur l'ensemble de vos sites, jour et nuit. Dès que quelque chose brise, c'est vous qui le savez, pas vos visiteurs.", "forWho": "Pour : les opérateurs et agences qui gèrent des dizaines, voire des centaines de sites, où un seul formulaire mort tue vos leads et vos ventes en silence.", "includes": ["Surveillance continue de chaque formulaire, bouton et tunnel d'achat", "Vérification des numéros de téléphone et des coordonnées sur tous les sites", "Alertes instantanées dès qu'un parcours brise, sur votre canal", "Un seul tableau de bord pour l'état de santé de toute votre flotte", "Rapport QA hebdomadaire de ce qui a brisé et de ce qu'on a corrigé"], "outcome": "Vous arrêtez de perdre des leads et des commandes à cause d'erreurs que personne n'a remarquées pendant des semaines. Chaque site de votre flotte reste réservable, achetable et joignable, sans en vérifier un seul à la main.", "cta": "Commencer", "problem": "Un formulaire arrête d'envoyer, un tunnel d'achat affiche une erreur, un numéro de téléphone tombe mort, et vous l'apprenez des semaines plus tard quand les leads se sont mystérieusement taris. Avec des dizaines ou des centaines de sites, personne ne teste chaque parcours à la main, alors les chemins brisés vous font perdre des revenus en silence total.", "howItWorks": [{"t": "On cartographie vos parcours", "d": "On répertorie chaque formulaire, bouton, numéro de contact et tunnel d'achat sur toute votre flotte pour que rien de critique ne passe sous le radar."}, {"t": "On teste en automatique", "d": "Jour et nuit, on lance de vraies soumissions et vérifications sur chaque parcours pour confirmer qu'il se complète vraiment, pas seulement qu'il s'affiche."}, {"t": "Vous recevez l'alerte en premier", "d": "Dès qu'un parcours brise, une alerte arrive sur votre canal avec le site et le problème exact, et le tout se retrouve dans votre rapport QA hebdomadaire."}], "why": "Ça roule sur le même système qu'on a bâti pour garder notre propre flotte de sites en conversion, parce qu'on a perdu des commandes à cause de bris silencieux nous aussi. On teste comme le ferait un vrai client, du début à la fin, pour que vous l'appreniez de nous, pas d'une chute dans vos chiffres.", "faq": [{"q": "Est-ce que tester mes formulaires va inonder mon CRM de faux leads ?", "a": "Non. On soumet par des chemins de test contrôlés et on marque ou isole ces entrées pour que votre vrai pipeline et vos rapports restent propres."}, {"q": "Combien de sites pouvez-vous couvrir ?", "a": "D'une poignée à plusieurs centaines. La surveillance est conçue pour les flottes, donc ajouter des sites ne veut pas dire plus de travail manuel de votre côté."}, {"q": "En combien de temps vais-je savoir qu'un truc a brisé ?", "a": "En quelques minutes après la panne, sur le canal de votre choix, avec le site précis et le parcours brisé nommés pour que vous ou votre équipe puissiez agir tout de suite."}]}, "nameFr": "QA de flotte en tant que service"}, {"id": "agency-platform", "cat": "software", "hero": false, "icon": "🗂️", "name": "Agency Client Platform", "oneLiner": "Run your whole agency from one screen.", "model": "/mo", "value": "$199-1,499/mo", "en": {"headline": "Run your entire agency from one screen", "subhead": "Clients, projects, billing, and deliverables live in one branded platform your team and your clients actually log into. No more chasing updates across ten tabs and twenty inboxes.", "forWho": "For: agency owners drowning in spreadsheets, DMs, and scattered tools who want one source of truth.", "includes": ["Branded client portal with your logo and domain", "Project and task boards your team and clients both see", "Built-in invoicing, proposals, and recurring billing", "Client onboarding flows and approval requests", "Live dashboards on revenue, capacity, and deadlines"], "outcome": "You stop being the bottleneck. Clients see progress without emailing you, your team knows what is due, and nothing slips through the cracks because everything finally lives in one place.", "cta": "Get started", "problem": "Your agency runs on a patchwork of spreadsheets, DMs, shared docs, and a billing tool that talks to none of them. So you become the human glue: the only person who knows what is due, who owes what, and where every project actually stands.", "howItWorks": [{"t": "We map your workflow", "d": "We sit down and trace how a client actually moves through your agency, from first onboarding to final invoice, so the platform matches how you really work instead of forcing a generic template on you."}, {"t": "We build your platform", "d": "We stand up your branded portal, project boards, billing, and approval flows under your logo and domain, then migrate your live clients and projects in so it is ready on day one."}, {"t": "We train and hand off", "d": "We walk your team and your clients through it, tighten anything that feels clunky, and leave you with one screen that runs the whole shop."}], "why": "We do not sell software we have never run. This is the same kind of operating system we use to run our own agency, so every board, flow, and dashboard exists because it solved a real bottleneck for an operator, not because it looked good in a demo.", "faq": [{"q": "Do my clients have to learn yet another login?", "a": "They get one simple branded portal where they see progress, approve work, and pay invoices. Most clients prefer it to chasing you over email, and there is nothing for them to install."}, {"q": "Can it replace the tools I already pay for?", "a": "Usually yes. Project boards, invoicing, proposals, onboarding, and client comms live in one place, so you can retire the scattered subscriptions instead of stacking another tool on top of them."}, {"q": "What if my agency does not work like everyone else's?", "a": "That is the point. We map your actual workflow first and build around it, so the platform fits your delivery process instead of forcing you into a one size fits all box."}]}, "fr": {"headline": "Gérez toute votre agence depuis un seul écran", "subhead": "Clients, projets, facturation et livrables réunis dans une seule plateforme à votre image, où votre équipe et vos clients se connectent vraiment. Fini de courir après les mises à jour dans dix onglets et vingt boîtes de courriel.", "forWho": "Pour : les propriétaires d'agence noyés sous les fichiers Excel, les messages et les outils éparpillés qui veulent une seule source de vérité.", "includes": ["Portail client à votre image, avec votre logo et votre domaine", "Tableaux de projets et de tâches visibles par l'équipe et les clients", "Facturation, soumissions et paiements récurrents intégrés", "Parcours d'accueil des clients et demandes d'approbation", "Tableaux de bord en direct sur les revenus, la capacité et les échéances"], "outcome": "Vous cessez d'être le goulot d'étranglement. Vos clients voient l'avancement sans vous écrire, votre équipe sait quoi livrer, et beaucoup moins de choses tombent entre les craques parce que tout est enfin au même endroit.", "cta": "Commencer", "problem": "Votre agence roule sur un ramassis de fichiers Excel, de messages, de documents partagés et d'un outil de facturation qui ne parle à aucun des autres. Du coup, c'est vous la colle humaine : la seule personne qui sait ce qui est dû, qui doit quoi, et où chaque projet est rendu pour vrai.", "howItWorks": [{"t": "On cartographie votre flux", "d": "On s'assoit avec vous pour suivre le vrai parcours d'un client dans votre agence, de l'accueil jusqu'à la facture finale, pour que la plateforme colle à votre façon de travailler au lieu de vous imposer un modèle générique."}, {"t": "On bâtit votre plateforme", "d": "On monte votre portail à votre image, vos tableaux de projets, votre facturation et vos approbations sous votre logo et votre domaine, puis on y migre vos clients et vos projets actifs pour que ce soit prêt dès le jour un."}, {"t": "On forme et on remet les clés", "d": "On guide votre équipe et vos clients dans l'outil, on ajuste tout ce qui accroche, et on vous laisse un seul écran qui fait rouler toute la boutique."}], "why": "On ne vend pas un logiciel qu'on n'a jamais utilisé nous-mêmes. C'est le même genre de système d'exploitation qu'on emploie pour gérer notre propre agence, donc chaque tableau, parcours et tableau de bord existe parce qu'il a réglé un vrai goulot pour un opérateur, pas parce qu'il était beau dans une démo.", "faq": [{"q": "Mes clients doivent-ils apprendre encore un autre logiciel ?", "a": "Ils ont un seul portail simple à votre image où ils voient l'avancement, approuvent le travail et paient leurs factures. La plupart préfèrent ça à vous courir après par courriel, et il n'y a rien à installer."}, {"q": "Est-ce que ça remplace les outils que je paie déjà ?", "a": "Dans bien des cas, oui. Tableaux de projets, facturation, soumissions, accueil et communications clients vivent au même endroit, donc vous pouvez couper des abonnements éparpillés au lieu d'empiler un outil de plus par-dessus."}, {"q": "Et si mon agence ne fonctionne pas comme les autres ?", "a": "C'est exactement le but. On cartographie d'abord votre vrai flux de travail et on bâtit autour, pour que la plateforme épouse votre façon de livrer au lieu de vous forcer dans un moule unique."}]}, "nameFr": "Plateforme client pour agences"}, {"id": "ops-stack", "cat": "software", "hero": false, "icon": "🖥️", "name": "Self-Hosted Ops Stack", "oneLiner": "A private cockpit for your business, on your own server.", "model": "1x+/mo", "value": "$4,000-10,000 + /mo", "en": {"headline": "Run your whole business from one screen you own", "subhead": "We build you a private cockpit on your own server, so every number, order, and lever lives in one place you control. No subscriptions stacked on subscriptions, no vendor holding your data hostage.", "forWho": "For: operators running multiple stores or revenue lines who are tired of juggling ten dashboards and exporting CSVs at midnight.", "includes": ["Private server provisioned, hardened, and fully owned by you", "Unified dashboard pulling sales, orders, and ops into one view", "Live KPIs and alerts so problems surface before they cost you", "Automations that replace the manual tasks eating your team's day", "Role-based access so the right people see the right numbers"], "outcome": "You stop renting your visibility from a dozen tools and start running the business from a single source of truth. Faster decisions, cleaner data, and infrastructure that scales with you instead of taxing you per seat.", "cta": "Get started", "problem": "Your numbers are scattered across ten dashboards, three logins, and a midnight CSV export, so by the time you see a problem it has already cost you. You are paying per seat for tools that don't talk to each other and still don't give you the full picture.", "howItWorks": [{"t": "Map your stack", "d": "We sit with you and chart every store, tool, and revenue line you touch so we know exactly what needs to flow into one place."}, {"t": "Build your cockpit", "d": "We provision and harden a private server, then wire your sales, orders, and ops into a single dashboard with live KPIs and alerts."}, {"t": "Hand you the keys", "d": "We set role-based access, switch on the automations, and train your team so the machine runs without us in the loop."}], "why": "We run our own businesses on this exact setup, so you are buying the cockpit we trust with our own revenue, not a theory. Because you own the server and the data, nothing breaks when a vendor changes their pricing or pulls a feature.", "faq": [{"q": "Do I need a technical team to run this?", "a": "No. We build it, harden it, and train your people on the day-to-day. You get a clean dashboard, not a server you have to babysit, and we are there if something needs adjusting."}, {"q": "Will it connect to the tools I already use?", "a": "That is the whole point. We pull your stores, payment data, and ops tools into one view, so you keep what works and finally see it all in one screen instead of ten."}, {"q": "What happens to my data if we stop working together?", "a": "It stays yours, on your server, full stop. You own the infrastructure and the data from day one, so you are never locked in or held hostage by us or anyone else."}]}, "fr": {"headline": "Pilotez toute votre entreprise depuis un seul écran qui vous appartient", "subhead": "On vous bâtit un cockpit privé sur votre propre serveur, pour que chaque chiffre, chaque commande et chaque levier vivent à une seule place que vous contrôlez. Plus d'abonnements empilés les uns sur les autres, plus de fournisseur qui retient vos données en otage.", "forWho": "Pour : les opérateurs qui gèrent plusieurs boutiques ou sources de revenus et qui en ont assez de jongler avec dix tableaux de bord et d'exporter des CSV à minuit.", "includes": ["Serveur privé configuré, sécurisé et entièrement à vous", "Tableau de bord unifié qui regroupe ventes, commandes et opérations", "KPI en direct et alertes pour voir les problèmes avant qu'ils vous coûtent cher", "Automatisations qui remplacent les tâches manuelles qui grugent la journée de votre équipe", "Accès par rôle pour que chaque personne voie les bons chiffres"], "outcome": "Vous arrêtez de louer votre visibilité à une douzaine d'outils et vous pilotez l'entreprise depuis une seule source de vérité. Des décisions plus rapides, des données plus propres et une infrastructure qui grandit avec vous au lieu de vous taxer par siège.", "cta": "Commencer", "problem": "Vos chiffres sont éparpillés dans dix tableaux de bord, trois connexions et un export CSV à minuit, alors quand vous voyez enfin un problème, il vous a déjà coûté cher. Vous payez par siège pour des outils qui ne se parlent pas et qui ne vous donnent quand même pas le portrait complet.", "howItWorks": [{"t": "On cartographie votre stack", "d": "On s'assoit avec vous et on trace chaque boutique, chaque outil et chaque source de revenus que vous touchez pour savoir exactement quoi regrouper à une seule place."}, {"t": "On bâtit votre cockpit", "d": "On configure et sécurise un serveur privé, puis on branche vos ventes, vos commandes et vos opérations dans un seul tableau de bord avec KPI en direct et alertes."}, {"t": "On vous remet les clés", "d": "On règle les accès par rôle, on active les automatisations et on forme votre équipe pour que la machine roule sans qu'on soit dans la boucle."}], "why": "On fait rouler nos propres entreprises sur exactement ce montage, alors vous achetez le cockpit qu'on utilise pour nos propres revenus, pas une théorie. Comme vous possédez le serveur et les données, votre visibilité ne dépend plus des changements de prix ou de fonctions d'un fournisseur.", "faq": [{"q": "Est-ce que j'ai besoin d'une équipe technique pour faire rouler ça ?", "a": "Non. On le bâtit, on le sécurise et on forme vos gens sur le quotidien. Vous obtenez un tableau de bord propre, pas un serveur à surveiller, et on reste là si quelque chose doit être ajusté."}, {"q": "Est-ce que ça va se connecter aux outils que j'utilise déjà ?", "a": "C'est tout le but. On regroupe vos boutiques, vos données de paiement et vos outils d'opérations dans une seule vue, alors vous gardez ce qui fonctionne et vous voyez enfin tout sur un seul écran au lieu de dix."}, {"q": "Qu'arrive-t-il à mes données si on arrête de travailler ensemble ?", "a": "Elles restent à vous, sur votre serveur, point final. Vous possédez l'infrastructure et les données dès le jour un, alors vous restez maître de votre visibilité, sans dépendre de nous ni de personne d'autre."}]}, "nameFr": "Stack d'opérations auto-hébergé"}, {"id": "payment-dashboards", "cat": "payments", "hero": false, "icon": "💳", "name": "Payment Analytics & Reporting", "oneLiner": "See every dollar across processors in one dashboard.", "model": "1x+/mo", "value": "$5,000-15,000 + /mo", "en": {"headline": "Every dollar across every processor, one live view", "subhead": "Stripe, Shopify Payments, PayPal, and your bank reconciled into a single dashboard. No more exporting CSVs and praying the totals match.", "forWho": "For: operators running revenue through multiple processors who can never get one clean number.", "includes": ["Unified dashboard merging every processor and payout into one view", "Net revenue after fees, refunds, and chargebacks broken out clearly", "Daily payout and bank reconciliation so deposits always tie out", "Failed payment, decline, and chargeback alerts before they pile up", "Cohort and product-level margin reporting you can actually trust"], "outcome": "You stop guessing what you actually made and start every morning knowing your true net to the dollar. Decisions get faster, leaks get caught, and your books stop fighting your processors.", "problem": "Your money lands in three or four different processors, each with its own dashboard, its own fees, and its own version of the truth. So you export CSVs, stitch them in a spreadsheet, and still end up guessing what you actually cleared.", "howItWorks": [{"t": "Connect your stack", "d": "We plug into Stripe, Shopify Payments, PayPal, and your bank so every transaction and payout flows into one place."}, {"t": "Reconcile to net", "d": "We strip out fees, refunds, and chargebacks and tie every payout back to your bank so the number you see is the number you keep."}, {"t": "Live dashboard plus alerts", "d": "You get one always-on view of true net revenue, with alerts firing the moment payments fail or chargebacks hit."}], "why": "We built this because we run revenue through multiple processors ourselves and got tired of never trusting a single total. This is the same reconciliation machine we rely on to know our own net to the dollar, not a generic reporting plugin.", "faq": [{"q": "Which processors and platforms do you support?", "a": "Stripe, Shopify Payments, PayPal, and your bank are the core, and we connect most major processors and gateways. If you run something unusual, tell us on the call and we will confirm before we start."}, {"q": "Will this replace my accountant or bookkeeper?", "a": "No. It gives you and your bookkeeper one reconciled source of truth so the books stop fighting your processors. It makes their job faster, it does not replace them."}, {"q": "How is this different from the reports inside Stripe or Shopify?", "a": "Those only show you one processor at a time. We merge all of them into a single net number after fees, refunds, and chargebacks, then tie it back to the cash that actually hit your bank."}], "cta": "Get started"}, "fr": {"headline": "Chaque dollar, chaque processeur, une seule vue en direct", "subhead": "Stripe, Shopify Payments, PayPal et votre banque réconciliés dans un seul tableau de bord. Fini les exports CSV et l'espoir que les totaux concordent.", "forWho": "Pour : les opérateurs qui encaissent sur plusieurs processeurs et n'arrivent jamais à obtenir un chiffre net clair.", "includes": ["Tableau de bord unifié qui fusionne chaque processeur et chaque versement", "Revenu net après frais, remboursements et rétrofacturations, ventilé clairement", "Réconciliation quotidienne des versements et de la banque pour des dépôts qui balancent", "Alertes sur les paiements échoués, refus et rétrofacturations avant que ça s'accumule", "Rapports de marge par cohorte et par produit auxquels vous pouvez vous fier"], "outcome": "Vous arrêtez de deviner ce que vous avez vraiment gagné et commencez chaque matin en connaissant votre net réel au dollar près. Les décisions vont plus vite, les fuites se voient, et votre comptabilité cesse de se battre avec vos processeurs.", "problem": "Votre argent arrive dans trois ou quatre processeurs différents, chacun avec son propre tableau de bord, ses propres frais et sa propre version de la vérité. Alors vous exportez des CSV, vous les recollez dans un chiffrier, et vous finissez quand même par deviner ce que vous avez réellement encaissé.", "howItWorks": [{"t": "On branche vos outils", "d": "On se connecte à Stripe, Shopify Payments, PayPal et votre banque pour que chaque transaction et chaque versement arrive au même endroit."}, {"t": "On réconcilie au net", "d": "On retire les frais, les remboursements et les rétrofacturations, et on rattache chaque versement à votre banque pour que le chiffre affiché soit celui que vous gardez."}, {"t": "Tableau de bord et alertes", "d": "Vous obtenez une seule vue toujours active de votre revenu net réel, avec des alertes dès qu'un paiement échoue ou qu'une rétrofacturation tombe."}], "why": "On a bâti ça parce qu'on encaisse nous-mêmes sur plusieurs processeurs et qu'on était tannés de ne jamais faire confiance à un seul total. C'est la même machine de réconciliation qu'on utilise pour connaître notre propre net au dollar près, pas un module de rapports générique.", "faq": [{"q": "Quels processeurs et plateformes prenez-vous en charge ?", "a": "Stripe, Shopify Payments, PayPal et votre banque forment la base, et on connecte la plupart des grands processeurs et passerelles. Si vous utilisez quelque chose d'inhabituel, dites-le nous pendant l'appel et on confirmera avant de commencer."}, {"q": "Est-ce que ça remplace mon comptable ou mon teneur de livres ?", "a": "Non. Ça vous donne, à vous et à votre teneur de livres, une seule source de vérité réconciliée pour que la comptabilité cesse de se battre avec vos processeurs. Ça accélère leur travail, ça ne les remplace pas."}, {"q": "En quoi est-ce différent des rapports dans Stripe ou Shopify ?", "a": "Ces rapports ne montrent qu'un processeur à la fois. Nous, on les fusionne tous en un seul chiffre net après frais, remboursements et rétrofacturations, puis on le rattache à l'argent qui est vraiment entré dans votre banque."}], "cta": "Commencer"}, "nameFr": "Analytique et rapports de paiements"}, {"id": "lead-capture-page", "cat": "design", "hero": false, "icon": "📥", "name": "Bilingual Lead-Capture Page", "oneLiner": "A page engineered to never drop a lead.", "model": "1x+/mo", "value": "$750-2,500 + /mo", "en": {"headline": "The page built to never drop a lead", "subhead": "One bilingual page engineered to turn cold clicks into booked calls. Every word, field, and pixel earns its place, in English and French.", "forWho": "For: operators sending paid or organic traffic to a page that leaks leads instead of capturing them.", "includes": ["Conversion-first page in English and French", "Friction-killing form that captures, not scares off", "Headline, offer, and proof block written to convert", "Instant lead routing to your inbox or CRM", "Mobile-first build with tracking wired in"], "outcome": "You stop paying for traffic that bounces. Every visitor hits a page tuned to one job: hand you their name and book the call.", "cta": "Get started", "problem": "You are buying clicks, but they land on a page that buries the offer, asks for too much, and gives people a dozen reasons to leave. Every bounce is ad spend you already paid for, walking out the door.", "howItWorks": [{"t": "We map the offer", "d": "We pin down the one action this page must drive, then strip everything that does not push the visitor toward it."}, {"t": "We build to convert", "d": "We write and build the headline, proof block, and frictionless form in English and French, mobile-first, with tracking wired in from the start."}, {"t": "We route the leads", "d": "Every submission lands instantly in your inbox or CRM, so you are following up while the lead is still warm."}], "why": "This is the same page structure we run on our own traffic before we ever hand it to a client. We do not theorize about what converts, we build pages that have to earn their keep against real ad spend.", "faq": [{"q": "Do I really need both English and French?", "a": "If a single visitor speaks French and hits an English-only page, you lose them. One bilingual build captures both audiences from the same traffic, with no second page to manage."}, {"q": "Will this work with the ads I already run?", "a": "Yes. The page is the destination your clicks deserve. We wire in tracking so you can see exactly which traffic books calls and which does not."}, {"q": "What do you need from me to start?", "a": "Your offer, where you want the leads delivered, and any brand assets you have. We handle the copy, the build, and the routing from there."}]}, "fr": {"headline": "La page conçue pour ne jamais perdre un lead", "subhead": "Une seule page bilingue bâtie pour transformer les clics froids en appels réservés. Chaque mot, chaque champ et chaque pixel justifie sa place, en français comme en anglais.", "forWho": "Pour : les opérateurs qui envoient du trafic payant ou organique vers une page qui laisse fuir les leads au lieu de les capter.", "includes": ["Page axée conversion en français et en anglais", "Formulaire sans friction qui capte au lieu de faire fuir", "Titre, offre et bloc de preuve écrits pour convertir", "Acheminement instantané des leads vers votre boîte courriel ou votre CRM", "Construction mobile d'abord avec le suivi déjà branché"], "outcome": "Vous arrêtez de payer pour du trafic qui rebondit. Chaque visiteur arrive sur une page réglée pour une seule tâche : vous donner son nom et réserver l'appel.", "cta": "Commencer", "problem": "Vous payez pour des clics, mais ils atterrissent sur une page qui enterre l'offre, demande trop d'infos et donne mille raisons de partir. Chaque rebond, c'est du budget publicitaire déjà dépensé qui s'en va.", "howItWorks": [{"t": "On cible l'offre", "d": "On définit la seule action que cette page doit provoquer, puis on retire tout ce qui n'y pousse pas le visiteur."}, {"t": "On bâtit pour convertir", "d": "On rédige et on construit le titre, le bloc de preuve et le formulaire sans friction en français et en anglais, mobile d'abord, avec le suivi branché dès le départ."}, {"t": "On achemine les leads", "d": "Chaque soumission arrive instantanément dans votre boîte courriel ou votre CRM, pour que vous fassiez le suivi pendant que le lead est encore chaud."}], "why": "C'est la même structure de page que l'on utilise sur notre propre trafic avant même de la confier à un client. On ne théorise pas sur ce qui convertit : on bâtit des pages qui doivent faire leurs preuves contre du vrai budget publicitaire.", "faq": [{"q": "Ai-je vraiment besoin du français et de l'anglais ?", "a": "Si un seul visiteur parle français et tombe sur une page uniquement en anglais, vous le perdez. Une seule construction bilingue capte les deux publics à partir du même trafic, sans deuxième page à gérer."}, {"q": "Est-ce que ça fonctionne avec les pubs que je fais déjà ?", "a": "Oui. La page, c'est la destination que vos clics méritent. On branche le suivi pour que vous voyiez exactement quel trafic réserve des appels et lequel n'en réserve pas."}, {"q": "De quoi avez-vous besoin de ma part pour commencer ?", "a": "Votre offre, l'endroit où vous voulez recevoir les leads et les éléments de marque que vous avez. On s'occupe du texte, de la construction et de l'acheminement à partir de là."}]}, "nameFr": "Page de capture de leads bilingue"}, {"id": "chat-support", "cat": "support", "hero": false, "icon": "💬", "name": "AI + Human Chat Support", "oneLiner": "Answers like your best agent, 24/7, in two languages.", "model": "1x+/mo", "value": "$1,500-4,000 + /mo", "en": {"headline": "Every customer answered in seconds, day or night", "subhead": "AI handles the flood instantly and routes the messy ones to a real person. Your buyers get your best agent's answer at 3 a.m., in English or French, without you hiring a night shift.", "forWho": "For: high-volume stores and service businesses drowning in repeat questions and slow replies", "includes": ["AI agent trained on your products, policies and tone of voice", "Live human takeover for refunds, complaints and edge cases", "Bilingual coverage so French and English buyers feel at home", "Order, shipping and FAQ answers wired to your real data", "Tagged transcripts that surface what customers keep asking for"], "outcome": "Response times drop from hours to seconds, abandoned carts get rescued before they leave, and your team stops answering the same five questions all day. You capture sales you were quietly losing while asleep.", "cta": "Get started", "problem": "Customers ask the same questions at all hours, and the ones you miss overnight or during a rush just leave and buy elsewhere. Every slow reply is a cart you paid to acquire and then quietly lost.", "howItWorks": [{"t": "We train the agent", "d": "We feed your products, policies, shipping rules and tone into an AI agent so it answers exactly the way you would."}, {"t": "It answers instantly", "d": "The agent handles the flood of repeat questions in seconds, in English or French, wired to your real order and shipping data."}, {"t": "Humans catch the rest", "d": "Refunds, complaints and edge cases get handed to a real person, and tagged transcripts show you what buyers keep asking for."}], "why": "We run this on our own stores before we ever put it on yours, so the agent is tuned by an operator who lives in the inbox, not a vendor reading a script. It only answers from your real policies and data, so fast does not mean wrong.", "faq": [{"q": "Will the AI give wrong answers and embarrass my brand?", "a": "It only answers from your actual products, policies and order data, and anything it is unsure about gets routed to a human instead of guessed. You stay in control of the script."}, {"q": "Can a real person still take over when it matters?", "a": "Yes. Refunds, complaints and anything sensitive get handed straight to a person, so customers never feel trapped talking to a bot."}, {"q": "Does it really handle both French and English?", "a": "It answers each buyer in their own language with your brand voice intact, so your francophone and anglophone customers both feel taken care of."}]}, "fr": {"headline": "Chaque client répondu en quelques secondes, jour et nuit", "subhead": "L'IA gère le volume instantanément et transfère les cas délicats à une vraie personne. Vos acheteurs reçoivent la réponse de votre meilleur agent à 3 h du matin, en français ou en anglais, sans que vous ayez à embaucher un quart de nuit.", "forWho": "Pour : les boutiques et entreprises de services qui croulent sous les questions répétitives et les réponses trop lentes", "includes": ["Agent IA formé sur vos produits, vos politiques et votre ton", "Prise en charge humaine en direct pour les remboursements, les plaintes et les cas particuliers", "Couverture bilingue pour que vos clients francophones et anglophones se sentent chez eux", "Réponses sur les commandes, la livraison et la FAQ branchées sur vos vraies données", "Conversations classées qui révèlent ce que vos clients demandent sans cesse"], "outcome": "Les délais de réponse passent de quelques heures à quelques secondes, les paniers abandonnés sont récupérés avant le départ, et votre équipe arrête de répondre aux mêmes cinq questions toute la journée. Vous captez les ventes que vous perdiez en silence pendant votre sommeil.", "cta": "Commencer", "problem": "Vos clients posent les mêmes questions à toute heure, et ceux que vous manquez la nuit ou en pleine cohue partent acheter ailleurs. Chaque réponse trop lente est un panier que vous avez payé pour acquérir et que vous perdez en silence.", "howItWorks": [{"t": "On forme l'agent", "d": "On nourrit l'agent IA avec vos produits, vos politiques, vos règles de livraison et votre ton pour qu'il réponde exactement comme vous le feriez."}, {"t": "Il répond à l'instant", "d": "L'agent gère le flot de questions répétitives en quelques secondes, en français ou en anglais, branché sur vos vraies données de commandes et de livraison."}, {"t": "L'humain prend le relais", "d": "Les remboursements, les plaintes et les cas particuliers sont confiés à une vraie personne, et les conversations classées vous montrent ce que vos clients demandent sans cesse."}], "why": "On fait tourner ce système sur nos propres boutiques avant de le poser sur la vôtre, alors l'agent est réglé par un opérateur qui vit dans la boîte de réception, pas par un fournisseur qui lit un script. Il ne répond qu'à partir de vos vraies politiques et données, donc rapide ne veut pas dire à côté de la plaque.", "faq": [{"q": "Est-ce que l'IA va donner de mauvaises réponses et nuire à ma marque ?", "a": "Elle ne répond qu'à partir de vos vrais produits, politiques et données de commandes, et tout ce dont elle n'est pas certaine est transféré à un humain plutôt que deviné. Vous gardez le contrôle du discours."}, {"q": "Une vraie personne peut-elle encore prendre le relais au besoin ?", "a": "Oui. Les remboursements, les plaintes et tout ce qui est délicat sont confiés directement à une personne, pour que vos clients ne se sentent jamais coincés avec un robot."}, {"q": "Est-ce que ça gère vraiment le français et l'anglais ?", "a": "L'agent répond à chaque acheteur dans sa propre langue tout en gardant votre voix de marque, pour que vos clients francophones et anglophones se sentent tous bien servis."}]}, "nameFr": "Clavardage IA + humain"}, {"id": "managed-ops", "cat": "support", "hero": false, "icon": "🧤", "name": "Managed Operations", "oneLiner": "White-glove. Our team runs it so you do not have to.", "model": "/mo", "value": "$1,200-20,000/mo", "en": {"headline": "Hand us the growth machine. We run it.", "subhead": "Our team operates your marketing day to day so nothing stalls in your inbox. You stay in your zone, we keep the engine turning.", "forWho": "For: operators who already have the offer and the traffic but no time to babysit the execution.", "includes": ["A dedicated operator who owns your account end to end", "Weekly execution: campaigns built, launched, and optimized for you", "Hands-on reporting with the moves we made and why", "Direct line to our team, no ticket queue", "Proactive fixes before small leaks become lost revenue"], "outcome": "You stop being the bottleneck. The work that used to pile up gets done by people who run this same playbook on our own money.", "cta": "Get started", "problem": "The offer works and the traffic shows up, but the execution lives in your head and dies in your inbox. Campaigns sit half built, optimizations get pushed to next week, and you are the single point of failure on everything that actually drives revenue.", "howItWorks": [{"t": "We map the machine", "d": "We audit your current marketing, find where the work is stalling, and document the playbook your operator will run every week."}, {"t": "Operator takes the wheel", "d": "A dedicated operator owns your account and executes the campaigns, launches, and optimizations so the work leaves your plate for good."}, {"t": "You review, we adjust", "d": "You get hands-on reporting on every move we made and why, and we keep tightening the engine without you having to chase it."}], "why": "We do not hand you a strategy deck and walk away. We run this exact operating playbook on our own offers with our own money, so the person managing your account already knows what moves actually convert.", "faq": [{"q": "Will I lose visibility into what's happening in my account?", "a": "No. You get a direct line to your operator and clear reporting on every move and the reasoning behind it. You see more than you do today, you just stop having to do the work yourself."}, {"q": "I'm protective of my brand voice. Will you get it right?", "a": "Yes. We map your offer, voice, and standards before we touch anything, then run a tight feedback loop early so the work sounds like you, not like an agency template."}, {"q": "What if I already have a marketing person on my team?", "a": "We can own the whole account or take the pieces that keep falling through the cracks. Plenty of operators use us to handle execution so their internal person can focus on strategy and offer."}]}, "fr": {"headline": "Confiez-nous la machine. On la fait rouler.", "subhead": "Notre équipe opère votre marketing au quotidien pour que rien ne traîne dans votre boîte de courriels. Vous restez dans votre zone, on garde le moteur en marche.", "forWho": "Pour : les opérateurs qui ont déjà l'offre et le trafic, mais pas le temps de surveiller l'exécution.", "includes": ["Un opérateur dédié qui prend votre compte en charge de bout en bout", "Exécution hebdomadaire : campagnes bâties, lancées et optimisées pour vous", "Rapports concrets avec les actions posées et le pourquoi", "Ligne directe avec notre équipe, sans file d'attente", "Corrections proactives avant qu'une petite fuite devienne du revenu perdu"], "outcome": "Vous cessez d'être le goulot d'étranglement. Le travail qui s'accumulait est fait par des gens qui appliquent ce même plan sur leur propre argent.", "cta": "Commencer", "problem": "L'offre fonctionne et le trafic arrive, mais l'exécution vit dans votre tête et meurt dans votre boîte de courriels. Les campagnes restent à moitié bâties, les optimisations sont repoussées à la semaine prochaine, et vous êtes le seul point de défaillance sur tout ce qui génère vraiment du revenu.", "howItWorks": [{"t": "On cartographie la machine", "d": "On audite votre marketing actuel, on trouve où le travail bloque, et on documente le plan que votre opérateur fera rouler chaque semaine."}, {"t": "L'opérateur prend le volant", "d": "Un opérateur dédié prend votre compte en charge et exécute les campagnes, les lancements et les optimisations pour que le travail quitte votre assiette pour de bon."}, {"t": "Vous révisez, on ajuste", "d": "Vous recevez un rapport concret sur chaque action posée et le pourquoi, et on continue de resserrer le moteur sans que vous ayez à courir après."}], "why": "On ne vous remet pas un plan stratégique avant de disparaître. On applique ce même plan d'opération sur nos propres offres avec notre propre argent, alors la personne qui gère votre compte sait déjà quelles actions convertissent réellement.", "faq": [{"q": "Vais-je perdre la visibilité sur ce qui se passe dans mon compte ?", "a": "Non. Vous avez une ligne directe avec votre opérateur et un rapport clair sur chaque action et le raisonnement derrière. Vous voyez plus qu'aujourd'hui, vous cessez simplement d'avoir à faire le travail vous-même."}, {"q": "Je suis protecteur de ma voix de marque. Allez-vous bien la rendre ?", "a": "Oui. On cartographie votre offre, votre voix et vos standards avant de toucher à quoi que ce soit, puis on met en place une boucle de rétroaction serrée dès le début pour que le travail sonne comme vous, pas comme un gabarit d'agence."}, {"q": "Et si j'ai déjà une personne au marketing dans mon équipe ?", "a": "On peut prendre tout le compte en charge ou seulement les morceaux qui passent constamment entre les mailles. Plusieurs opérateurs nous confient l'exécution pour que leur personne interne se concentre sur la stratégie et l'offre."}]}, "nameFr": "Opérations gérées"}, {"id": "opportunity-intel", "cat": "research", "hero": false, "icon": "🧠", "name": "Opportunity Intelligence", "oneLiner": "Scored, ranked product and niche opportunities, continuously.", "model": "/mo", "value": "$99-999/mo", "en": {"headline": "Know your next winning product before the market does", "subhead": "We surface scored, ranked product and niche opportunities and refresh them continuously, so you stop guessing and start launching what is already pulling demand.", "forWho": "For: operators and brand owners who need to pick the next product or niche with conviction, not vibes.", "includes": ["Ranked shortlist of product and niche opportunities, scored on demand and competition", "A clear why behind every score, not a black box", "Continuous refresh as trends move, not a one-time dump", "Saturation and competition read on each opportunity", "Watchlist tracking so you act the moment a trend breaks"], "outcome": "You walk into every launch decision already knowing which bets are worth your inventory, ad spend, and attention. Less time researching, more time on opportunities with proven pull.", "cta": "Get started", "problem": "You are picking your next product off gut feel, scattered trend videos, and whatever a competitor seems to be running. By the time a trend is obvious enough to feel safe, the margin is already gone and you are launching into a crowd.", "howItWorks": [{"t": "We scan demand", "d": "We pull live demand and trend signals across products and niches, then score each one on real pull instead of hype."}, {"t": "We rank and explain", "d": "You get a ranked shortlist with the saturation read and the clear reasoning behind every score, so you can defend the call."}, {"t": "We keep watching", "d": "We refresh the scores and track your watchlist continuously, so you move the moment a trend breaks instead of after."}], "why": "This is the same opportunity machine we run to choose what we launch ourselves, not a theory deck. When the people scoring the trends also have to live with the bets, the scores get honest fast.", "faq": [{"q": "Is this just a trend report I could pull off TikTok myself?", "a": "No. A trend video tells you something is hot once everyone already knows. We score demand against competition and saturation and keep refreshing it, so you see the opening while it is still an opening, not after it closes."}, {"q": "Does this work for my niche, or only the obvious ecom categories?", "a": "It is niche-agnostic. We score on demand and competition signals, so the same engine surfaces opportunities whether you sell physical products, digital products, or services."}, {"q": "How do I actually use the shortlist once I have it?", "a": "You use it to decide where your inventory, ad spend, and attention go. Each opportunity comes with its score, saturation read, and the why, so you can move straight from shortlist to a confident launch decision."}]}, "fr": {"headline": "Trouvez votre prochain produit gagnant avant le marché", "subhead": "On fait ressortir des opportunités de produits et de niches notées et classées, et on les rafraîchit en continu, pour que vous arrêtiez de deviner et lanciez ce qui attire déjà la demande.", "forWho": "Pour : les opérateurs et propriétaires de marques qui veulent choisir leur prochain produit ou niche avec conviction, pas au feeling.", "includes": ["Liste classée d'opportunités de produits et de niches, notées selon la demande et la concurrence", "Un pourquoi clair derrière chaque note, pas une boîte noire", "Rafraîchissement continu au fil des tendances, pas un rapport unique", "Lecture de la saturation et de la concurrence pour chaque opportunité", "Suivi en liste de surveillance pour agir dès qu'une tendance décolle"], "outcome": "Vous prenez chaque décision de lancement en sachant déjà quels paris méritent votre inventaire, vos budgets pub et votre attention. Moins de temps à chercher, plus de temps sur des opportunités à traction prouvée.", "cta": "Commencer", "problem": "Vous choisissez votre prochain produit au feeling, à coups de vidéos de tendances éparpillées et de ce qu'un concurrent semble lancer. Le temps qu'une tendance soit assez évidente pour vous rassurer, la marge est déjà partie et vous lancez dans la foule.", "howItWorks": [{"t": "On scanne la demande", "d": "On capte les signaux de demande et de tendances en temps réel sur les produits et les niches, puis on note chacun selon la vraie traction plutôt que le buzz."}, {"t": "On classe et on explique", "d": "Vous recevez une liste classée avec la lecture de la saturation et le raisonnement clair derrière chaque note, pour que vous puissiez défendre la décision."}, {"t": "On garde l'oeil ouvert", "d": "On rafraîchit les notes et on suit votre liste de surveillance en continu, pour que vous bougiez dès qu'une tendance décolle plutôt qu'après."}], "why": "C'est la même machine à opportunités qu'on utilise pour choisir ce qu'on lance nous-mêmes, pas une présentation théorique. Quand ceux qui notent les tendances doivent aussi vivre avec les paris, les notes deviennent honnêtes très vite.", "faq": [{"q": "Est-ce juste un rapport de tendances que je pourrais sortir de TikTok moi-même ?", "a": "Non. Une vidéo de tendance vous dit qu'un truc est chaud une fois que tout le monde le sait déjà. On note la demande face à la concurrence et à la saturation, et on rafraîchit le tout, pour que vous voyiez l'ouverture pendant qu'elle est encore une ouverture, pas après qu'elle se referme."}, {"q": "Est-ce que ça marche pour ma niche, ou seulement les catégories ecom évidentes ?", "a": "C'est agnostique à la niche. On note selon les signaux de demande et de concurrence, donc le même moteur fait ressortir des opportunités que vous vendiez des produits physiques, des produits numériques ou des services."}, {"q": "Comment j'utilise concrètement la liste une fois que je l'ai ?", "a": "Vous l'utilisez pour décider où vont votre inventaire, vos budgets pub et votre attention. Chaque opportunité arrive avec sa note, sa lecture de saturation et son pourquoi, pour que vous passiez directement de la liste à une décision de lancement assumée."}]}, "nameFr": "Veille d'opportunités"}, {"id": "regulated-marketing", "cat": "leverage", "hero": true, "icon": "🧬", "name": "Regulated / High-Risk Marketing", "oneLiner": "Marketing for the industries every other agency turns away, done compliantly.", "model": "/mo", "value": "$2,000-8,000/mo", "en": {"headline": "Marketing for the industries everyone else won't touch", "subhead": "Cannabis, supplements, finance, firearms, adult, crypto. We run paid and organic growth in the niches that get other operators banned, and we keep your accounts alive while we do it.", "forWho": "For: regulated and high-risk brands tired of suspended ad accounts, frozen payments, and agencies that ghost the second they read your category.", "includes": ["Compliance-first ad creative built to pass platform review", "Account structure and warm-up that survives policy sweeps", "Backup ad accounts and payment rails before you need them", "Compliant landing pages and claims review for your offers", "Channel mix beyond Meta and Google, where your niche actually converts"], "outcome": "You stop rebuilding from zero every time a platform flags you, and start scaling on accounts that stay live. The same machine we use to run our own high-risk offers, pointed at yours.", "cta": "Get started", "problem": "You finally get an ad account running and a payment processor approved, then a policy sweep wipes it out and you are back to square one. Every agency you call goes quiet the moment they read your category, so the growth never compounds.", "howItWorks": [{"t": "Audit and armor", "d": "We map every account, payment rail, and claim in your funnel, then fix the weak points that get high-risk brands flagged before we spend a dollar."}, {"t": "Launch compliant", "d": "We build ad creative and landing pages engineered to pass platform review, structured across backup accounts so one ban never takes your whole operation down."}, {"t": "Scale and defend", "d": "We push spend into the channels where your niche actually converts while keeping spare accounts and rails warm, so a flag becomes a switch, not a shutdown."}], "why": "We run our own high-risk offers through the exact same machine every day, so we are not guessing at what survives a policy sweep, we are living it. When your account is the one that pays our bills, compliance stops being a checkbox and becomes the whole job.", "faq": [{"q": "Can you actually keep my ad accounts from getting banned?", "a": "No honest operator promises zero bans in regulated niches. What we promise is structure: compliant creative, backup accounts, and payment rails ready before you need them, so a flag costs you a day instead of your whole business."}, {"q": "My category is too risky for Meta and Google. Now what?", "a": "Then we stop forcing channels that fight you. We move spend to the networks, placements, and organic plays where your niche converts and policy is friendlier, and we use compliant assets to stay live where the big platforms will tolerate you."}, {"q": "Will you review my claims and offers, or just run ads?", "a": "Both. We review the claims on your offers and landing pages first, because the fastest way to get banned is a non-compliant promise. We fix the message, then we drive traffic to it."}]}, "fr": {"headline": "Le marketing des industries que les autres refusent de toucher", "subhead": "Cannabis, suppléments, finance, armes à feu, contenu pour adultes, crypto. Nous gérons votre croissance payante et organique dans les niches qui font bannir les autres opérateurs, et nous gardons vos comptes en vie pendant que nous le faisons.", "forWho": "Pour : les marques réglementées et à haut risque, tannées des comptes publicitaires suspendus, des paiements gelés et des agences qui disparaissent à la seconde où elles voient votre catégorie.", "includes": ["Des créatifs publicitaires axés sur la conformité, conçus pour passer la révision des plateformes", "Une structure de compte et un réchauffement qui résistent aux vagues de bannissement", "Des comptes publicitaires et des solutions de paiement de secours, prêts avant que vous en ayez besoin", "Des pages de destination conformes et une révision des allégations de vos offres", "Un mélange de canaux au-delà de Meta et Google, là où votre niche convertit vraiment"], "outcome": "Vous arrêtez de tout reconstruire à zéro chaque fois qu'une plateforme vous signale, et vous commencez à scaler sur des comptes qui restent en ligne. La même machine que nous utilisons pour nos propres offres à haut risque, pointée sur la vôtre.", "cta": "Commencer", "problem": "Vous réussissez enfin à faire rouler un compte publicitaire et à faire approuver un processeur de paiement, puis une vague de bannissement efface tout et vous repartez de zéro. Chaque agence que vous appelez devient muette dès qu'elle voit votre catégorie, alors la croissance ne s'accumule jamais.", "howItWorks": [{"t": "Audit et blindage", "d": "Nous cartographions chaque compte, chaque solution de paiement et chaque allégation dans votre tunnel, puis nous corrigeons les points faibles qui font signaler les marques à haut risque, avant de dépenser un sou."}, {"t": "Lancement conforme", "d": "Nous bâtissons des créatifs et des pages de destination conçus pour passer la révision des plateformes, répartis sur des comptes de secours pour qu'un seul bannissement ne fasse jamais tomber toute votre opération."}, {"t": "Scaler et défendre", "d": "Nous poussons le budget vers les canaux où votre niche convertit vraiment tout en gardant des comptes et des solutions de paiement de rechange au chaud, pour qu'un signalement devienne un interrupteur, pas un arrêt complet."}], "why": "Nous faisons rouler nos propres offres à haut risque dans cette même machine tous les jours, alors nous ne devinons pas ce qui survit à une vague de bannissement, nous le vivons. Quand c'est votre compte qui paie nos factures, la conformité arrête d'être une case à cocher et devient le cœur du travail.", "faq": [{"q": "Pouvez-vous vraiment empêcher mes comptes publicitaires de se faire bannir ?", "a": "Aucun opérateur honnête ne promet zéro bannissement dans les niches réglementées. Ce que nous promettons, c'est une structure : des créatifs conformes, des comptes de secours et des solutions de paiement prêts avant que vous en ayez besoin, pour qu'un signalement vous coûte une journée au lieu de toute votre entreprise."}, {"q": "Ma catégorie est trop risquée pour Meta et Google. On fait quoi ?", "a": "Là, nous arrêtons de forcer des canaux qui se battent contre vous. Nous déplaçons le budget vers les réseaux, les placements et les stratégies organiques où votre niche convertit et où les politiques sont plus tolérantes, et nous utilisons des actifs conformes pour rester en ligne là où les grandes plateformes vont vous tolérer."}, {"q": "Allez-vous réviser mes allégations et mes offres, ou juste rouler des annonces ?", "a": "Les deux. Nous révisons d'abord les allégations sur vos offres et vos pages de destination, parce que la façon la plus rapide de se faire bannir, c'est une promesse non conforme. Nous corrigeons le message, puis nous y dirigeons le trafic."}]}, "nameFr": "Marketing réglementé / haut risque"}, {"id": "white-label-platform", "cat": "leverage", "hero": true, "icon": "🏷️", "name": "White-Label the Platform", "oneLiner": "Run our entire engine under your brand. Sell it all; we power it.", "model": "Lic", "value": "$2,500-7,500/mo + rev-share", "en": {"headline": "Sell our entire growth engine under your own brand", "subhead": "You front the relationship and own the client. We run the machine quietly in the background, the same one we use on our own money.", "forWho": "For: agencies, consultants, and operators who want a proven product to sell without building it.", "includes": ["Full platform rebranded with your name, logo, and domain", "Done-for-you delivery on every account you close", "Your own dashboard so clients only ever see you", "Onboarding scripts and sales assets to close faster", "Private operator support and a clear revenue split"], "outcome": "You walk into pitches with a finished, battle-tested product instead of a promise. You keep the client and the brand equity while we carry the operational load.", "cta": "Get started", "problem": "You can sell, but you have no product to put behind the pitch. Building your own platform means months of engineering, hiring a delivery team, and burning cash before you ever bill a client.", "howItWorks": [{"t": "We rebrand the platform", "d": "We set up the full engine under your name, logo, and domain so every client touchpoint looks like it was built by you."}, {"t": "You close the client", "d": "You pitch with our onboarding scripts and sales assets, sign the account, and own the relationship from day one."}, {"t": "We deliver in the background", "d": "We run the work and reporting quietly behind your dashboard while you collect the wins and keep the brand equity."}], "why": "This is not a reseller kit we cooked up to flip. It is the exact machine we run on our own money and our own clients, so you are selling something already proven in the field instead of a prototype.", "faq": [{"q": "Will my clients know you exist?", "a": "No. Everything they touch carries your name, your domain, and your dashboard. We stay invisible by design, so the relationship and the credit stay entirely yours."}, {"q": "How much delivery work do I have to do?", "a": "Almost none. You close the deal and stay the face of the account. We handle the fulfillment and reporting so you can sell more instead of getting buried in operations."}, {"q": "What if I have never run an agency before?", "a": "That is fine. You get the onboarding scripts, sales assets, and private operator support to close and keep clients, so you can lean on a proven system instead of figuring it out alone."}]}, "fr": {"headline": "Vendez notre moteur de croissance complet sous votre marque", "subhead": "Vous gardez la relation et le client. On fait rouler la machine en arrière-plan, la même qu'on utilise sur notre propre argent.", "forWho": "Pour : agences, consultants et opérateurs qui veulent un produit éprouvé à vendre sans avoir à le bâtir.", "includes": ["Plateforme complète à votre nom, logo et domaine", "Livraison clé en main sur chaque compte que vous signez", "Votre propre tableau de bord, le client ne voit que vous", "Scripts d'accueil et outils de vente pour conclure plus vite", "Soutien privé d'opérateur et partage des revenus clair"], "outcome": "Vous arrivez en rendez-vous avec un produit fini et éprouvé au lieu d'une promesse. Vous gardez le client et la valeur de votre marque pendant qu'on porte toute la charge opérationnelle.", "cta": "Commencer", "problem": "Vous savez vendre, mais vous n'avez aucun produit à mettre derrière votre pitch. Bâtir votre propre plateforme, c'est des mois de développement, une équipe de livraison à embaucher et du capital brûlé avant même de facturer un seul client.", "howItWorks": [{"t": "On rebrande la plateforme", "d": "On configure le moteur complet à votre nom, logo et domaine, pour que chaque point de contact client ait l'air d'avoir été bâti par vous."}, {"t": "Vous signez le client", "d": "Vous présentez avec nos scripts d'accueil et nos outils de vente, vous signez le compte et vous gardez la relation dès le départ."}, {"t": "On livre en arrière-plan", "d": "On fait rouler le travail et les rapports discrètement derrière votre tableau de bord pendant que vous récoltez les gains et la valeur de votre marque."}], "why": "Ce n'est pas un kit de revente improvisé pour faire un coup vite fait. C'est exactement la machine qu'on fait rouler sur notre propre argent et nos propres clients, donc vous vendez une chose déjà éprouvée sur le terrain au lieu d'un prototype.", "faq": [{"q": "Est-ce que mes clients vont savoir que vous existez ?", "a": "Non. Tout ce qu'ils voient porte votre nom, votre domaine et votre tableau de bord. On reste invisible par choix, pour que la relation et le mérite vous reviennent en entier."}, {"q": "Combien de travail de livraison dois-je faire moi-même ?", "a": "Presque aucun. Vous signez l'entente et restez le visage du compte. On gère la livraison et les rapports pour que vous puissiez vendre plus au lieu d'être enseveli sous les opérations."}, {"q": "Et si je n'ai jamais géré d'agence avant ?", "a": "Aucun problème. Vous recevez les scripts d'accueil, les outils de vente et le soutien privé d'opérateur pour signer et garder vos clients, donc vous vous appuyez sur un système éprouvé au lieu de tout deviner seul."}]}, "nameFr": "La plateforme en marque blanche"}, {"id": "business-in-a-box", "cat": "leverage", "hero": true, "icon": "🚀", "name": "Business-in-a-Box", "oneLiner": "Your whole business launched and running, domain to revenue.", "model": "1x+/mo", "value": "$5,000-25,000 + /mo", "en": {"headline": "We build your business, you collect the revenue", "subhead": "From bare domain to a live, money-making operation, we stand up the whole machine and hand you the keys. The same playbook we run on our own businesses, deployed on yours.", "forWho": "For: operators who want a proven business live and selling, not another project to manage.", "includes": ["Domain, brand, and conversion-built site, live and ready to sell", "Offer, pricing, and funnel engineered to turn clicks into customers", "Payments, automations, and back-office wired end to end", "Traffic engine turned on, paid and organic, pointed at the offer", "Handoff with the dashboards and SOPs to run it without us"], "outcome": "You skip the year of guessing and start with a business that already works. We rent you the exact machine that runs our own money, then hand you the controls.", "problem": "Most people spend a year stitching together a domain, a site, an offer, payments, and traffic, and still end up with a half-built thing that does not sell. The hard part was never the idea, it was assembling the whole machine and getting it to actually make money.", "howItWorks": [{"t": "We map the build", "d": "We pick the offer, the niche, and the funnel, then lock the exact stack that will turn visitors into paying customers."}, {"t": "We stand it up", "d": "We build the brand, site, payments, automations, and back-office, then switch on paid and organic traffic pointed straight at the offer."}, {"t": "We hand you the keys", "d": "You get the live business, the dashboards, and the SOPs so it keeps running and selling without us in the loop."}], "why": "We are not theorists handing you a template, we run these same machines on our own businesses every day. We only deploy a build once it works on our own money, so you start on a system that is already proven, not an experiment.", "faq": [{"q": "Do I need experience to run it after handoff?", "a": "No. We hand you dashboards and step-by-step SOPs built so an operator with no prior experience can keep the machine running. If you can follow a checklist, you can run it."}, {"q": "How is this different from a website agency?", "a": "An agency hands you a site and walks away. We hand you a full business: the offer, the funnel, the payments, the traffic, and the playbook to operate it. The site is one part of the machine, not the deliverable."}, {"q": "Who owns the business once it is built?", "a": "You do, fully. We build it, prove it, and hand you the keys along with everything you need to run it on your own. It is your asset from the handoff forward."}], "cta": "Get started"}, "fr": {"headline": "Nous bâtissons votre entreprise, vous encaissez les revenus", "subhead": "Du nom de domaine vide à une opération en ligne qui vend, nous montons la machine au complet et nous vous remettons les clés. Le même playbook que nous roulons sur nos propres business, déployé sur le vôtre.", "forWho": "Pour : les opérateurs qui veulent une entreprise prouvée, en ligne et qui vend, pas un autre projet à gérer.", "includes": ["Domaine, image de marque et site conçu pour convertir, en ligne et prêt à vendre", "Offre, prix et entonnoir bâtis pour transformer les clics en clients", "Paiements, automatisations et back-office branchés de bout en bout", "Moteur de trafic activé, payé et organique, dirigé vers l'offre", "Remise des clés avec les tableaux de bord et les procédures pour rouler sans nous"], "outcome": "Vous sautez l'année de tâtonnements et vous partez avec une entreprise qui fonctionne déjà. Nous vous louons la machine exacte qui fait rouler notre propre argent, puis nous vous passons les commandes.", "problem": "La plupart des gens passent un an à coller ensemble un domaine, un site, une offre, des paiements et du trafic, et finissent quand même avec un truc à moitié bâti qui ne vend pas. Le difficile n'a jamais été l'idée, c'était d'assembler la machine au complet et de la faire vraiment générer de l'argent.", "howItWorks": [{"t": "Nous planifions le build", "d": "Nous choisissons l'offre, le créneau et l'entonnoir, puis nous verrouillons la stack exacte qui va transformer les visiteurs en clients payants."}, {"t": "Nous montons la machine", "d": "Nous bâtissons l'image de marque, le site, les paiements, les automatisations et le back-office, puis nous activons le trafic payé et organique dirigé droit sur l'offre."}, {"t": "Nous vous remettons les clés", "d": "Vous recevez l'entreprise en ligne, les tableaux de bord et les procédures pour qu'elle continue de rouler et de vendre sans nous."}], "why": "Nous ne sommes pas des théoriciens qui vous remettent un gabarit : nous roulons ces mêmes machines sur nos propres business chaque jour. Nous déployons un build seulement une fois qu'il fonctionne sur notre propre argent, donc vous partez sur un système déjà éprouvé, pas une expérience.", "faq": [{"q": "Faut-il de l'expérience pour la rouler après la remise des clés ?", "a": "Non. Nous vous remettons des tableaux de bord et des procédures étape par étape bâties pour qu'un opérateur sans expérience puisse garder la machine en marche. Si vous savez suivre une liste, vous pouvez la rouler."}, {"q": "En quoi est-ce différent d'une agence web ?", "a": "Une agence vous remet un site puis s'en va. Nous, nous vous remettons une entreprise complète : l'offre, l'entonnoir, les paiements, le trafic et le playbook pour l'opérer. Le site est une pièce de la machine, pas le livrable."}, {"q": "À qui appartient l'entreprise une fois bâtie ?", "a": "À vous, au complet. Nous la bâtissons, nous la prouvons et nous vous remettons les clés avec tout ce qu'il faut pour la rouler par vous-même. C'est votre actif dès la remise des clés."}], "cta": "Commencer"}, "nameFr": "Entreprise clé en main"}, {"id": "franchise-apps", "cat": "leverage", "hero": false, "icon": "🧱", "name": "White-Label Niche Apps", "oneLiner": "Proven app DNA, rebranded for your niche and live this week.", "model": "Lic", "value": "$4,500-12,000 + /mo", "en": {"headline": "Launch a Proven App, Branded For Your Niche", "subhead": "We take an app that already works in the wild, rebrand it as yours, and ship it live this week. You skip the year of building and the burned cash that usually comes with it.", "forWho": "For: operators who want a real, working product to sell under their own name without funding a build from zero.", "includes": ["Battle-tested app core rebranded with your name, colors, and domain", "Niche-specific copy, screens, and onboarding tuned to your buyers", "Live deployment and hosting handled, no dev team to hire", "Your branded checkout and billing wired in and ready to take signups", "Ongoing updates and fixes pushed to your app, so it keeps working"], "outcome": "You own a polished product your market actually pays for, live in days instead of quarters. While competitors are still scoping a build, you are already collecting signups.", "cta": "Get started", "problem": "You know exactly what your market would pay for, but building it means hiring developers, waiting a year, and watching the budget bleed before you ever take a single signup. So the idea sits in a doc while someone else ships first.", "howItWorks": [{"t": "We pick the engine", "d": "We start from an app core that already works and sells in the real world, so you inherit a proven product instead of a risky bet."}, {"t": "We rebrand it as yours", "d": "We reskin the name, colors, domain, copy, and onboarding so it reads as your product built for your niche, not a generic template."}, {"t": "We ship it live", "d": "We deploy, host, and wire your branded checkout so your app is online and taking signups within days, then keep it updated."}], "why": "This works because we are not guessing in a vacuum, we run products like this ourselves and only put our name behind cores that have already proven they sell. You are launching on a machine that is already turning, not a prototype hoping to find traction.", "faq": [{"q": "Is this really my app, or am I renting someone else's?", "a": "It launches under your name, your colors, and your domain, with your checkout collecting the revenue. The proven core stays under the hood so you skip the build risk, while the brand and the customers are yours."}, {"q": "How is this live in days when a build takes a year?", "a": "Because the hard part, the working product, already exists. We are rebranding and deploying something proven instead of engineering from zero, which is where the year and the burned cash usually go."}, {"q": "What happens after it is live?", "a": "We keep hosting it and push ongoing updates and fixes to your app, so it stays stable and current while you focus on selling it and serving your buyers."}]}, "fr": {"headline": "Lancez une app éprouvée, à votre image", "subhead": "On prend une app qui fonctionne déjà sur le terrain, on la rebrande à votre nom, et on la met en ligne cette semaine. Vous sautez l'année de développement et l'argent brûlé qui vient habituellement avec.", "forWho": "Pour : les opérateurs qui veulent un vrai produit fonctionnel à vendre sous leur propre nom, sans financer un développement à partir de zéro.", "includes": ["Cœur d'app éprouvé, rebrandé avec votre nom, vos couleurs et votre domaine", "Textes, écrans et accueil taillés pour votre niche et vos clients", "Déploiement et hébergement gérés, aucune équipe de développeurs à embaucher", "Votre paiement et votre facturation à votre image, prêts à encaisser", "Mises à jour et correctifs poussés en continu, pour que l'app reste solide"], "outcome": "Vous possédez un produit fini que votre marché paie réellement, en ligne en quelques jours au lieu de plusieurs mois. Pendant que vos concurrents planifient encore leur développement, vous récoltez déjà des inscriptions.", "cta": "Commencer", "problem": "Vous savez exactement ce que votre marché paierait, mais le construire veut dire embaucher des développeurs, attendre un an et regarder le budget fondre avant la moindre inscription. Alors l'idée dort dans un document pendant qu'un autre lance en premier.", "howItWorks": [{"t": "On choisit le moteur", "d": "On part d'un cœur d'app qui fonctionne et qui se vend déjà sur le terrain, alors vous héritez d'un produit éprouvé au lieu d'un pari risqué."}, {"t": "On le rebrande à votre nom", "d": "On refait le nom, les couleurs, le domaine, les textes et l'accueil pour que ça se lise comme votre produit, taillé pour votre niche, pas un gabarit générique."}, {"t": "On le met en ligne", "d": "On déploie, on héberge et on branche votre paiement à votre image, alors votre app est en ligne et encaisse des inscriptions en quelques jours, puis on la garde à jour."}], "why": "Ça fonctionne parce qu'on ne devine pas dans le vide : on opère nous-mêmes des produits comme celui-là et on ne met notre nom que derrière des cœurs qui ont déjà prouvé qu'ils se vendent. Vous lancez sur une machine qui tourne déjà, pas sur un prototype qui espère trouver sa traction.", "faq": [{"q": "Est-ce vraiment mon app, ou est-ce que je loue celle d'un autre ?", "a": "Elle se lance sous votre nom, vos couleurs et votre domaine, avec votre paiement qui encaisse les revenus. Le cœur éprouvé reste sous le capot pour vous éviter le risque du développement, mais la marque et les clients sont à vous."}, {"q": "Comment est-ce en ligne en quelques jours alors qu'un développement prend un an ?", "a": "Parce que le plus dur, le produit fonctionnel, existe déjà. On rebrande et on déploie quelque chose d'éprouvé au lieu de tout coder à partir de zéro, et c'est justement là que passent l'année et l'argent brûlé."}, {"q": "Qu'est-ce qui se passe une fois en ligne ?", "a": "On continue de l'héberger et on pousse des mises à jour et des correctifs en continu sur votre app, alors elle reste stable et à jour pendant que vous vous concentrez sur la vente et vos clients."}]}, "nameFr": "Applications de niche en marque blanche"}], "niches": [{"id": "personal-injury-law", "label": "Personal injury law", "complianceNote": "Results vary and are not guaranteed. This is marketing and SEO content, not legal advice, and no specific case result, ranking, settlement, or client outcome is promised. Past performance does not predict future results. All numbers shown are illustrative. Content is written to fit attorney advertising rules, but you are responsible for final compliance in your jurisdiction.", "painPoints": ["You are paying $80 to $120 a click on 'car accident lawyer' and renting shared intake leads that the same vendor already sold to two other firms in your market before your phone even rings.", "Injured people now ask ChatGPT and Gemini 'do I have a case?' and 'how long do I have to file?' before they ever type a firm name, and your firm is not showing up in those answers or the sources behind them.", "Your site has one thin practice-area page and a contact form, so you lose the long-tail searches that actually convert (specific injuries, specific intersections, 'is it too late to sue') to bigger firms with hundreds of pages of content."], "exampleSearches": ["car accident lawyer near me free consultation no win no fee", "do I have a case if I got rear-ended and my back still hurts two weeks later", "Ask ChatGPT: I slipped at a grocery store last week and hurt my shoulder, who should I call and is there a deadline to file a claim in my state?"], "whatWeDo": ["Publish the injury-intent content people actually search after a crash or a fall: statute-of-limitations explainers, 'what to do after a rear-end accident,' how medical bills and liens get paid from a settlement, and local accident-hotspot pages for the intersections, highways, and counties you serve.", "Structure every article so AI assistants can pull from it: clean question-and-answer formatting, your service areas and practice focus spelled out, and the entity and source signals that help a firm get surfaced in ChatGPT, Gemini, Perplexity, and Google AI Overviews.", "Build up your Google Business Profile and Maps presence so 'injury lawyer near me' and 'free consultation' searches surface your firm, with blog content that routes readers straight to your call button, intake form, and case-evaluation flow.", "Keep every post safe for attorney advertising: written in your voice and your jurisdiction, no outcome or settlement guarantees, no fabricated testimonials, proper disclaimer language, and your sign-off before a single word publishes under your name."], "headline": "Be the injury firm Google and AI both recommend after the accident", "subhead": "We write and publish an ongoing, bar-aware blog in your firm's voice that helps injured people find you in Google Search, Google Maps, and AI answers, then routes them to your profile and intake. You approve every post before it goes live.", "proof": "In one illustrative 6-month build for a single-office injury firm, non-branded organic visits to injury-intent pages grew from 287 to 2,613 a month, with 38 intake-form starts that traced back to blog content. Illustrative only, and your results will differ.", "faq": [{"q": "Will you promise me case results or first-page rankings?", "a": "No, and you should walk away from anyone who does. Bar advertising rules and Google both prohibit guaranteed outcomes. What we build is consistent, on-brand content designed to help the right injured people in your area find you and trust your firm before they ever call. We focus on visibility and credibility, not promises no one can keep."}, {"q": "Is the content safe for attorney advertising?", "a": "We write to fit attorney advertising standards: no outcome or settlement guarantees, no invented testimonials, appropriate disclaimer language, and everything kept in your voice and your jurisdiction. You review and approve each post before it publishes, so your firm stays fully in control of what goes out under your name. You remain responsible for final compliance, and we make that easy."}, {"q": "We already run Google Ads and buy intake leads. Why add content?", "a": "Paid clicks stop the second you stop paying, and shared leads get resold to other firms the same hour. A blog that ranks in Search, Maps, and AI answers is an asset your firm owns. It keeps working while you are in trial, it warms people up before they call you instead of the firm down the street, and it never splits a prospect with anyone else."}], "icon": "⚖️", "fr": {"label": "Droit des blessures corporelles", "complianceNote": "Les résultats varient et ne sont pas garantis. Il s'agit de contenu marketing et de référencement, et non d'un avis juridique; aucun résultat de dossier, classement, règlement ou dénouement client précis n'est promis. Les résultats passés ne garantissent pas les résultats futurs. Tous les chiffres présentés le sont à titre indicatif. Le contenu est rédigé pour respecter les règles encadrant la publicité des avocats, mais la conformité finale dans votre territoire relève de votre responsabilité.", "painPoints": ["Vous payez de 80 $ à 120 $ le clic sur 'avocat accident de voiture' et vous louez des leads d'admission partagés que le même fournisseur a déjà vendus à deux autres cabinets de votre marché avant même que votre téléphone ne sonne.", "Les personnes blessées demandent maintenant à ChatGPT et à Gemini 'est-ce que j'ai un dossier?' et 'combien de temps ai-je pour déposer une réclamation?' avant même de taper le nom d'un cabinet, et le vôtre n'apparaît ni dans ces réponses ni dans les sources qui les alimentent.", "Votre site n'a qu'une mince page de domaine de pratique et un formulaire de contact, alors vous perdez les recherches de longue traîne qui convertissent vraiment (blessures précises, intersections précises, 'est-ce trop tard pour poursuivre') au profit de plus gros cabinets aux centaines de pages de contenu."], "exampleSearches": ["avocat accident de voiture près de chez moi consultation gratuite aucuns frais sans gain", "est-ce que j'ai un dossier si je me suis fait emboutir par l'arrière et que mon dos fait encore mal deux semaines plus tard", "Demandez à ChatGPT : j'ai glissé dans une épicerie la semaine dernière et je me suis blessé à l'épaule, qui devrais-je appeler et y a-t-il un délai pour déposer une réclamation dans ma province?"], "whatWeDo": ["Publier le contenu à intention 'blessure' que les gens recherchent vraiment après une collision ou une chute : explications sur les délais de prescription, 'quoi faire après un accident par l'arrière', comment les frais médicaux et les privilèges sont remboursés à même un règlement, et des pages locales sur les points chauds d'accidents pour les intersections, les autoroutes et les régions que vous desservez.", "Structurer chaque article pour que les assistants IA puissent y puiser : format clair de questions et réponses, vos secteurs desservis et votre champ de pratique bien explicites, et les signaux d'entité et de source qui aident un cabinet à ressortir dans ChatGPT, Gemini, Perplexity et les aperçus IA de Google.", "Renforcer votre fiche d'établissement Google et votre présence sur Maps afin que les recherches 'avocat en blessures près de chez moi' et 'consultation gratuite' fassent ressortir votre cabinet, avec un contenu de blogue qui dirige les lecteurs directement vers votre bouton d'appel, votre formulaire d'admission et votre processus d'évaluation de dossier.", "Garder chaque publication conforme aux règles de publicité des avocats : rédigée dans votre voix et pour votre territoire, sans garantie de dénouement ou de règlement, sans témoignages inventés, avec une formulation d'avertissement appropriée et votre approbation avant qu'un seul mot ne paraisse sous votre nom."], "headline": "Soyez le cabinet en blessures que Google et l'IA recommandent tous les deux après l'accident", "subhead": "Nous rédigeons et publions un blogue continu, conscient des règles du barreau et écrit dans la voix de votre cabinet, qui aide les personnes blessées à vous trouver dans la recherche Google, sur Google Maps et dans les réponses des IA, puis les dirige vers votre fiche et votre admission. Vous approuvez chaque publication avant sa mise en ligne.", "proof": "Dans un cas illustratif de développement sur 6 mois pour un cabinet en blessures à bureau unique, les visites organiques non liées à la marque vers les pages à intention 'blessure' sont passées de 287 à 2 613 par mois, avec 38 amorces de formulaire d'admission rattachées au contenu du blogue. À titre indicatif seulement; vos résultats seront différents.", "faq": [{"q": "Allez-vous me promettre des résultats de dossier ou un classement en première page?", "a": "Non, et vous devriez fuir quiconque le fait. Les règles de publicité du barreau et Google interdisent tous deux les dénouements garantis. Ce que nous bâtissons, c'est un contenu cohérent et fidèle à votre marque, conçu pour aider les bonnes personnes blessées de votre région à vous trouver et à faire confiance à votre cabinet avant même de vous appeler. Nous misons sur la visibilité et la crédibilité, pas sur des promesses que personne ne peut tenir."}, {"q": "Le contenu est-il conforme aux règles de publicité des avocats?", "a": "Nous rédigeons selon les normes de publicité des avocats : aucune garantie de dénouement ou de règlement, aucun témoignage inventé, une formulation d'avertissement appropriée et tout est gardé dans votre voix et pour votre territoire. Vous révisez et approuvez chaque publication avant sa parution, alors votre cabinet garde le plein contrôle de ce qui paraît sous votre nom. La conformité finale demeure votre responsabilité, et nous vous la rendons facile."}, {"q": "Nous faisons déjà de la publicité Google et achetons des leads d'admission. Pourquoi ajouter du contenu?", "a": "Les clics payants s'arrêtent dès que vous cessez de payer, et les leads partagés sont revendus à d'autres cabinets dans la même heure. Un blogue qui se classe dans la recherche, sur Maps et dans les réponses des IA est un actif que votre cabinet possède. Il continue de travailler pendant que vous êtes en procès, il réchauffe les gens avant qu'ils ne vous appellent plutôt que le cabinet d'à côté, et il ne partage jamais un client potentiel avec qui que ce soit."}]}}, {"id": "family-law", "label": "Family & divorce law", "headline": "Be the family law firm Google and AI recommend the night someone decides it's time", "subhead": "We write and publish an ongoing, on-brand blog that helps your firm show up in Google Search and Maps, and gets your name surfaced when people ask ChatGPT or Gemini who to call. So the right cases find you instead of the firm down the street.", "painPoints": ["You're up against firms with billboard budgets and pages of sponsored ads, so the second someone types 'divorce lawyer near me,' you're buried under big multi-location practices and pay-per-click bidders.", "Family law clients research quietly for weeks before they ever pick up the phone. They're reading about custody schedules, alimony, and 'how long does a divorce take' at 1am, and if your site has nothing that answers them, they bond with the firm whose site does.", "You get leads, but the wrong ones: people who can't fund a retainer, callers fishing for free advice, and spouses already consulting five other firms to create a conflict. Your intake staff burns hours on consults that were never going to retain."], "exampleSearches": ["divorce lawyer near me free consultation", "how is child custody decided in [state]", "Ask ChatGPT: I'm filing for divorce in [city], we have two kids and a house in both our names, what kind of family lawyer do I need and what should I ask in the first consultation?"], "whatWeDo": ["Publish authoritative, plain-English articles on what your clients actually search: how to file for divorce in your state, how custody and parenting time get decided, what counts as marital property, how long the process takes, and what really happens in a first consultation.", "Optimize every post for local intent so your firm surfaces for 'divorce lawyer near me' and your specific practice areas, from contested custody to high-asset division, and reinforces your Google Business Profile and Maps presence.", "Structure your content the way AI assistants actually read and cite it, so when someone asks ChatGPT, Gemini, or Perplexity for a family lawyer in your area, your firm shows up in the answer, not just your competitors.", "Keep the tone calm, credible, and reassuring so you attract serious, ready-to-retain clients and gently filter out tire-kickers, then route them straight to your consultation booking."], "proof": "A solo family law practice that started publishing consistently saw organic blog visits grow to roughly 1,847 a month within two quarters, with a noticeable lift in consultation requests that referenced a specific article. Illustrative only; results vary by market, firm, and practice area.", "faq": [{"q": "Will the articles actually sound like our firm, or generic legal filler?", "a": "They sound like your firm. We write in your voice, reference how things actually work in your state, and keep everything plain-spoken and human. Someone facing a divorce doesn't want jargon, they want to feel understood, and every post is built to do that. You approve the direction and can request edits anytime."}, {"q": "Does publishing this content create liability or count as giving legal advice?", "a": "No. Everything is written as general educational information, not legal advice, with appropriate disclaimers, and it never promises a specific outcome or creates an attorney-client relationship. It positions your firm as the knowledgeable, trustworthy option without making representations it shouldn't. You always have final review before anything goes live."}, {"q": "How long until we see family law clients coming from this?", "a": "Local SEO and AI visibility build over time, usually a few months as articles get indexed and start ranking, then they compound. We don't promise rankings or a set number of cases. What we do is publish consistently and correctly so more of the right people in your area find you, month after month."}], "complianceNote": "This content is general information, not legal advice, and does not create an attorney-client relationship. We do not guarantee rankings, leads, case outcomes, or results. Individual results are not guaranteed and vary by market, firm, and practice area. Month to month, cancel anytime, 60-day money-back guarantee.", "icon": "👪", "fr": {"label": "Droit de la famille et divorce", "complianceNote": "Ce contenu constitue de l'information générale, et non un avis juridique; il ne crée aucune relation avocat-client. Nous ne garantissons aucun classement, aucune demande de consultation, aucun résultat de dossier ni aucun résultat. Les résultats individuels ne sont pas garantis et varient selon le marché, le cabinet et le domaine de pratique. Abonnement de mois en mois, annulez en tout temps, garantie de remboursement de 60 jours.", "painPoints": ["Vous affrontez des cabinets aux budgets d'affichage géants et des pages entières d'annonces commanditées; alors dès qu'une personne tape 'avocat divorce près de chez moi', vous êtes enseveli sous les grandes études multi-bureaux et les enchérisseurs au coût par clic.", "Les clients en droit de la famille font leurs recherches en silence pendant des semaines avant de décrocher le téléphone. À 1 h du matin, ils lisent sur les ententes de garde, la pension alimentaire et 'combien de temps prend un divorce'; si votre site n'a rien pour leur répondre, ils s'attachent au cabinet dont le site, lui, répond.", "Vous recevez des demandes, mais les mauvaises : des gens incapables de payer une provision, des appels qui cherchent un conseil gratuit, et des conjoints qui consultent déjà cinq autres cabinets pour créer des conflits d'intérêts. Votre personnel d'accueil brûle des heures sur des consultations qui n'allaient jamais se transformer en mandat."], "exampleSearches": ["avocat divorce près de chez moi consultation gratuite", "comment la garde des enfants est décidée au québec", "Demandez à ChatGPT : je dépose une demande de divorce à [ville], on a deux enfants et une maison aux deux noms, de quel avocat en droit de la famille ai-je besoin et quoi demander à la première consultation ?"], "whatWeDo": ["Publier des articles crédibles, en langage clair, sur ce que vos clients cherchent réellement : comment entreprendre un divorce dans votre province, comment se décident la garde et le temps parental, ce qui constitue un patrimoine familial, combien de temps dure le processus, et ce qui se passe vraiment lors d'une première consultation.", "Optimiser chaque article pour l'intention locale afin que votre cabinet ressorte pour 'avocat divorce près de chez moi' et pour vos domaines de pratique précis, de la garde contestée au partage d'actifs importants, tout en renforçant votre fiche Google Business et votre présence sur Maps.", "Structurer votre contenu de la façon dont les assistants IA le lisent et le citent réellement, pour que lorsqu'une personne demande à ChatGPT, Gemini ou Perplexity un avocat en droit de la famille dans votre région, votre cabinet apparaisse dans la réponse, et pas seulement vos concurrents.", "Garder un ton calme, crédible et rassurant pour attirer des clients sérieux, prêts à confier un mandat, et écarter en douceur les curieux sans intention, puis les diriger directement vers la prise de rendez-vous pour une consultation."], "headline": "Soyez le cabinet en droit de la famille que Google et l'IA recommandent le soir où quelqu'un décide qu'il est temps", "subhead": "Nous rédigeons et publions un blogue continu, fidèle à votre image, qui aide votre cabinet à apparaître dans la recherche Google et dans Maps, et qui fait ressortir votre nom quand les gens demandent à ChatGPT ou Gemini qui appeler. Ainsi, les bons dossiers vous trouvent au lieu d'aller au cabinet d'à côté.", "proof": "Un cabinet solo en droit de la famille qui s'est mis à publier de façon constante a vu ses visites organiques sur le blogue grimper à environ 1 847 par mois en deux trimestres, avec une hausse notable des demandes de consultation qui mentionnaient un article précis. À titre indicatif seulement; les résultats varient selon le marché, le cabinet et le domaine de pratique.", "faq": [{"q": "Est-ce que les articles vont vraiment ressembler à notre cabinet, ou à du remplissage juridique générique ?", "a": "Ils ressemblent à votre cabinet. Nous écrivons dans votre voix, nous expliquons comment les choses fonctionnent vraiment dans votre province, et nous gardons tout clair et humain. Une personne qui traverse un divorce ne veut pas de jargon : elle veut se sentir comprise, et chaque article est conçu pour ça. Vous approuvez l'orientation et pouvez demander des modifications en tout temps."}, {"q": "Est-ce que publier ce contenu crée une responsabilité ou équivaut à donner un avis juridique ?", "a": "Non. Tout est rédigé comme de l'information éducative générale, et non comme un avis juridique, avec les mises en garde appropriées; cela ne promet jamais un résultat précis et ne crée aucune relation avocat-client. Le contenu positionne votre cabinet comme l'option compétente et digne de confiance, sans faire d'affirmations qu'il ne devrait pas faire. Vous avez toujours la révision finale avant toute mise en ligne."}, {"q": "Combien de temps avant que des clients en droit de la famille arrivent grâce à ça ?", "a": "Le référencement local et la visibilité dans l'IA se bâtissent avec le temps, habituellement quelques mois pendant que les articles sont indexés et commencent à se classer, puis l'effet se cumule. Nous ne promettons ni classement ni nombre fixe de dossiers. Ce que nous faisons, c'est publier de façon constante et rigoureuse pour que plus de bonnes personnes dans votre région vous trouvent, mois après mois."}]}}, {"id": "cosmetic-plastic-surgery", "label": "Cosmetic & plastic surgery", "headline": "Be the Cosmetic Surgery Practice Google and AI Recommend", "subhead": "We write and publish an ongoing, on-brand blog designed to help your practice show up when someone searches \"rhinoplasty near me\" on Google, and when they ask ChatGPT who to trust with their face. Built for cosmetic and plastic surgeons across the US and Canada.", "painPoints": ["You pay $47 to $88 a click on Google Ads for high-intent procedures like rhinoplasty and breast augmentation, while a practice a few suites down ranks organically for those same searches and pays nothing for that traffic.", "Cosmetic patients research for weeks and read everything before they ever book a consult, but your site has one thin procedure page and a blog that hasn't been touched in a year, so they keep reading until a competitor answers their questions better.", "You have no visibility into whether ChatGPT or Google's AI Overview ever names your practice when someone asks 'best plastic surgeon in [city] for a mommy makeover,' and right now it almost certainly doesn't."], "exampleSearches": ["best board-certified plastic surgeon near me for breast augmentation", "how much does a rhinoplasty cost in [city] and how long is the recovery", "Ask ChatGPT: I'm in [city] and considering a tummy tuck, which board-certified plastic surgeons should I look into and what should I ask at the consult?"], "whatWeDo": ["Publish procedure-deep articles your patients actually search before booking, from 'rhinoplasty recovery week by week' to 'liposuction vs CoolSculpting' to 'how to choose a board-certified plastic surgeon,' so you capture months of quiet research instead of fighting for the last 'near me' click.", "Build the local and AI signals designed to surface your practice in Google Maps, the local pack, and AI answers, then funnel readers straight to your Google Business Profile and consult booking.", "Write everything in your surgeon's voice, reviewed for medical accuracy and advertising compliance, so it reads like your practice and never like generic AI filler a board would flag.", "Track which procedures and patient questions are pulling in consult-ready traffic each month, and steer the content plan toward the higher-margin cases you actually want to fill your OR with."], "proof": "In one illustrative example, a cosmetic surgery practice grew from 237 monthly organic visitors to 1,813 over several months of consistent publishing, with consult-page visits rising alongside. Illustrative only, individual results are not guaranteed.", "faq": [{"q": "Will the content respect medical advertising rules and avoid promising results?", "a": "Yes. Everything is written to be educational and compliant, with no guaranteed outcomes, no before-and-after promises, and no claims a board would flag. We frame procedures honestly, note that results vary by patient, and keep the focus on helping the right patients understand their options and feel confident choosing you."}, {"q": "We focus on specific procedures like rhinoplasty and facelifts. Can the blog reflect that instead of generic 'plastic surgery'?", "a": "That's the whole point. We build the plan around the exact procedures and patient profiles you want more of, whether that's facial work, body contouring, or breast procedures, and write to how those specific patients search Google and what they ask AI before they ever call."}, {"q": "How is this different from the SEO agency that just churns out keyword posts?", "a": "Most agencies write thin posts to chase a keyword. We write the in-depth, reassuring answers a nervous, high-consideration patient needs, and we structure them so AI assistants like ChatGPT and Google's AI Overview can find and cite your practice. You get found by the patient and by the algorithm reading on their behalf."}], "complianceNote": "This is educational marketing content, not medical advice. Results vary by patient and individual results are not guaranteed. All content is written to support compliant medical advertising and does not promise specific outcomes.", "icon": "✨", "fr": {"label": "Chirurgie esthétique et plastique", "complianceNote": "Il s'agit de contenu marketing éducatif et non d'un avis médical. Les résultats varient d'un patient à l'autre et aucun résultat individuel n'est garanti. Tout le contenu est rédigé pour appuyer une publicité médicale conforme et ne promet aucun résultat précis.", "painPoints": ["Vous payez de 47 $ à 88 $ le clic en publicité Google pour des interventions à forte intention comme la rhinoplastie et l'augmentation mammaire, pendant qu'une clinique à quelques portes de chez vous se classe naturellement pour ces mêmes recherches et ne paie rien pour ce trafic.", "Les patients en esthétique font des recherches pendant des semaines et lisent tout avant même de réserver une consultation, mais votre site n'a qu'une mince page d'intervention et un blogue qui n'a pas été touché depuis un an; ils continuent donc à lire jusqu'à ce qu'un concurrent réponde mieux à leurs questions.", "Vous n'avez aucune visibilité quant à savoir si ChatGPT ou l'aperçu IA de Google nomme votre clinique lorsqu'une personne demande « meilleur chirurgien plasticien à [ville] pour un mommy makeover », et en ce moment, ce n'est presque certainement pas le cas."], "exampleSearches": ["meilleur chirurgien plasticien certifié près de chez moi pour augmentation mammaire", "combien coûte une rhinoplastie à [ville] et combien de temps dure la convalescence", "Demandez a ChatGPT : je suis à [ville] et j'envisage une abdominoplastie, quels chirurgiens plasticiens certifiés devrais-je consulter et quoi demander à la consultation ?"], "whatWeDo": ["Publier des articles approfondis sur les interventions que vos patients cherchent réellement avant de réserver, de « convalescence après rhinoplastie semaine par semaine » à « liposuccion ou CoolSculpting » jusqu'à « comment choisir un chirurgien plasticien certifié », afin de capter des mois de recherches discrètes au lieu de vous battre pour le dernier clic « près de chez moi ».", "Bâtir les signaux locaux et IA conçus pour faire ressortir votre clinique dans Google Maps, le pack local et les réponses IA, puis diriger les lecteurs directement vers votre fiche Google Business et la réservation de consultation.", "Tout rédiger dans la voix de votre chirurgien, révisé pour l'exactitude médicale et la conformité publicitaire, pour que ça se lise comme votre clinique et jamais comme du remplissage IA générique qu'un ordre professionnel signalerait.", "Suivre chaque mois quelles interventions et quelles questions de patients attirent un trafic prêt à consulter, et orienter le plan de contenu vers les cas à plus forte marge que vous voulez vraiment voir remplir votre salle d'opération."], "headline": "Devenez la clinique de chirurgie esthétique que Google et l'IA recommandent", "subhead": "Nous rédigeons et publions un blogue continu et à votre image, conçu pour aider votre clinique à apparaître quand quelqu'un cherche « rhinoplastie près de chez moi » sur Google, et quand il demande à ChatGPT à qui confier son visage. Pensé pour les chirurgiens esthétiques et plasticiens partout aux États-Unis et au Canada.", "proof": "Dans un exemple à titre indicatif, une clinique de chirurgie esthétique est passée de 237 visiteurs organiques par mois à 1 813 sur plusieurs mois de publication constante, les visites de la page de consultation augmentant en parallèle. À titre indicatif seulement; aucun résultat individuel n'est garanti.", "faq": [{"q": "Le contenu respectera-t-il les règles de publicité médicale et évitera-t-il de promettre des résultats ?", "a": "Oui. Tout est rédigé pour être éducatif et conforme, sans résultat garanti, sans promesse d'avant-après et sans affirmation qu'un ordre professionnel signalerait. Nous présentons les interventions honnêtement, précisons que les résultats varient d'un patient à l'autre, et gardons le cap sur ce qui aide les bons patients à comprendre leurs options et à se sentir en confiance de vous choisir."}, {"q": "Nous nous concentrons sur des interventions précises comme la rhinoplastie et le lifting. Le blogue peut-il refléter cela au lieu de « chirurgie plastique » en général ?", "a": "C'est exactement le but. Nous bâtissons le plan autour des interventions et des profils de patients précis que vous voulez attirer davantage, qu'il s'agisse de chirurgie du visage, de remodelage corporel ou d'interventions mammaires, et nous rédigeons selon la façon dont ces patients précis cherchent sur Google et ce qu'ils demandent à l'IA avant même de vous appeler."}, {"q": "En quoi est-ce différent de l'agence SEO qui se contente de pondre des articles bourrés de mots-clés ?", "a": "La plupart des agences écrivent des articles minces pour courir après un mot-clé. Nous rédigeons les réponses approfondies et rassurantes dont a besoin un patient nerveux et hautement réfléchi, et nous les structurons pour que des assistants IA comme ChatGPT et l'aperçu IA de Google puissent trouver et citer votre clinique. Vous êtes repéré par le patient et par l'algorithme qui lit en son nom."}]}}, {"id": "med-spas", "label": "Med spas & aesthetics", "complianceNote": "Results vary by practice, market, and treatment menu. Not medical advice. Individual results are not guaranteed. You stay responsible for keeping all before/after content and claims compliant with FDA, your state medical board, and platform advertising rules, and we write to help you stay inside those lines.", "exampleSearches": ["botox near me prices first time", "best lip filler injector in [city] reviews honest", "Ask ChatGPT: I'm 38 and want to soften my forehead lines without looking frozen. Which med spa near me is actually good at natural-looking Botox, and how do I know the injector is legit?"], "faq": [{"q": "Will the blog say anything that gets me in trouble with my medical board or the FDA?", "a": "No. We write for aesthetic clinics every day, so we stay on the safe side of medical advertising. We avoid guaranteed outcomes, off-label claims, and before/after misuse. We educate on treatments, candidacy, downtime, and what to expect, then point readers to a consult. You approve the voice and the boundaries up front, and you can flag anything you never want us to say."}, {"q": "I already pay for ads and they only work while I'm spending. How is this different?", "a": "Ads stop the day you stop paying. Content compounds. A clear guide on 'how long does filler last' or 'Botox vs Dysport' keeps pulling in people researching for weeks and months after it's published, and it's the exact material AI assistants pull from when someone asks who to trust for injectables nearby. You're building an asset you own instead of renting attention."}, {"q": "We mostly get clients from Instagram. Why does a blog matter?", "a": "Instagram is great for showing results and staying top of mind, but it's a closed garden. It doesn't help you show up when someone Googles 'tear trough filler near me' or asks ChatGPT who does laser safely in your area. The blog covers the high-intent research moment Instagram can't reach, and it feeds your Google Business Profile so the map listing and the search results work together."}], "headline": "Be the Med Spa Google and AI Recommend When Someone's Finally Ready to Book Botox", "subhead": "We write and publish an ongoing, board-safe blog for your clinic, built to help you get found in Google Search and Maps and to get your name surfaced inside ChatGPT, Gemini, and AI Overviews, then send those ready-to-book people straight to your profile and consult form.", "painPoints": ["You're booked solid from Instagram on filler weekends, but the moment someone Googles 'lip filler near me' or 'best Botox injector in [city],' a competitor with a deeper website shows up first and takes the client who was ready to pay.", "Your marketing is one talented injector posting reels at midnight. There's no steady stream of content answering the candidacy, downtime, and 'will I look frozen' questions clients research before they trust you with their face, so you live and die by referrals and the algorithm.", "People now ask ChatGPT and Google AI 'who does the best tear trough filler near me,' and your clinic isn't in the answer, because AI pulls from published content and reviews and you don't have either at the depth it looks for."], "whatWeDo": ["Publish on-brand articles that target how aesthetic clients actually search: 'how long does lip filler last,' 'Botox vs Dysport,' 'is Morpheus8 worth it,' and '[treatment] near me,' so you're found at the moment someone decides to book.", "Write everything to stay inside medical advertising lines: no guaranteed outcomes, no off-label promises, no misused before/afters, with candidacy, downtime, and consult language tuned for aesthetic clinics specifically.", "Structure each piece so AI assistants can quote it cleanly, with treatment FAQs, honest pricing context, and local signals that make it easier for ChatGPT, Gemini, and Perplexity to surface your clinic by name.", "Connect the content to your Google Business Profile and booking flow so a reader who lands on 'tear trough filler in [city]' moves straight to your map listing, reviews, and consult request."], "proof": "In one illustrative 90-day window, a single aesthetic clinic's published content started showing up for an estimated 1,213 additional local searches a month and appeared in 3 of 7 AI assistant answers we tested for 'Botox near me' in its city. Illustrative only. Individual results vary.", "icon": "💉", "fr": {"label": "Med spas et soins esthétiques", "complianceNote": "Les résultats varient selon la clinique, le marché et le menu de traitements. Ceci ne constitue pas un avis médical. Les résultats individuels ne sont pas garantis. Vous demeurez responsable de garder tout votre contenu avant/après ainsi que vos affirmations conformes aux exigences de Santé Canada, de votre ordre professionnel et des règles publicitaires des plateformes; nous rédigeons de façon à vous aider à rester à l'intérieur de ces balises.", "painPoints": ["Vos fins de semaine d'injections affichent complet grâce à Instagram, mais dès que quelqu'un cherche sur Google « filler à lèvres près de moi » ou « meilleure injectrice de Botox à [ville] », un concurrent au site web plus étoffé apparaît en premier et rafle la cliente qui était prête à payer.", "Votre marketing repose sur une seule injectrice talentueuse qui publie des reels à minuit. Il n'y a aucun flux régulier de contenu qui répond aux questions sur l'admissibilité, le temps de récupération et le « est-ce que je vais avoir l'air figée » que les clientes recherchent avant de vous confier leur visage; vous vivez donc au rythme des références et de l'algorithme.", "Les gens demandent maintenant à ChatGPT et à l'IA de Google « qui fait le meilleur filler de cernes près de moi », et votre clinique n'apparaît pas dans la réponse, parce que l'IA puise dans le contenu publié et les avis, et vous n'avez ni l'un ni l'autre avec la profondeur qu'elle recherche."], "exampleSearches": ["botox près de moi prix première fois", "meilleure injectrice filler à lèvres à [ville] avis honnêtes", "Demandez a ChatGPT : j'ai 38 ans et je veux adoucir mes rides du front sans avoir l'air figée. Quel med spa près de moi est vraiment bon pour un Botox d'apparence naturelle, et comment savoir si l'injectrice est sérieuse?"], "whatWeDo": ["Nous publions des articles fidèles à votre image qui ciblent la façon dont les clientes esthétiques cherchent réellement : « combien de temps dure le filler à lèvres », « Botox ou Dysport », « le Morpheus8 en vaut-il la peine » et « [traitement] près de moi », pour qu'on vous trouve au moment précis où quelqu'un décide de réserver.", "Nous rédigeons tout pour rester à l'intérieur des balises de la publicité médicale : aucun résultat garanti, aucune promesse hors indication, aucun usage abusif des photos avant/après, avec un langage sur l'admissibilité, le temps de récupération et la consultation adapté spécifiquement aux cliniques esthétiques.", "Nous structurons chaque article pour que les assistants IA puissent le citer proprement, avec des FAQ sur les traitements, un contexte de prix honnête et des signaux locaux qui facilitent à ChatGPT, Gemini et Perplexity de mentionner votre clinique par son nom.", "Nous relions le contenu à votre fiche d'établissement Google et à votre processus de réservation pour qu'une lectrice qui arrive sur « filler de cernes à [ville] » passe directement à votre emplacement sur la carte, vos avis et votre demande de consultation."], "headline": "Soyez le med spa que Google et l'IA recommandent quand quelqu'un est enfin prêt à réserver son Botox", "subhead": "Nous rédigeons et publions un blogue continu et conforme aux normes professionnelles pour votre clinique, conçu pour vous aider à être trouvé dans la recherche Google et dans Maps, et à faire ressortir votre nom dans ChatGPT, Gemini et les aperçus IA, puis à envoyer ces gens prêts à réserver directement vers votre fiche et votre formulaire de consultation.", "proof": "Dans une fenêtre de 90 jours fournie à titre indicatif, le contenu publié d'une seule clinique esthétique a commencé à apparaître pour environ 1 213 recherches locales supplémentaires par mois et est ressorti dans 3 réponses sur 7 d'assistants IA que nous avons testées pour « Botox près de moi » dans sa ville. À titre indicatif seulement. Les résultats individuels varient.", "faq": [{"q": "Le blogue va-t-il dire quelque chose qui pourrait me causer des ennuis avec mon ordre professionnel ou Santé Canada?", "a": "Non. Nous rédigeons pour des cliniques esthétiques tous les jours, alors nous restons du bon côté de la publicité médicale. Nous évitons les résultats garantis, les affirmations hors indication et le mauvais usage des photos avant/après. Nous informons sur les traitements, l'admissibilité, le temps de récupération et ce à quoi s'attendre, puis nous dirigeons les lecteurs vers une consultation. Vous approuvez le ton et les limites dès le départ, et vous pouvez signaler tout ce que vous ne voulez jamais nous voir dire."}, {"q": "Je paie déjà pour de la publicité et ça ne fonctionne que tant que je dépense. En quoi est-ce différent?", "a": "La publicité s'arrête le jour où vous cessez de payer. Le contenu, lui, s'accumule. Un guide clair sur « combien de temps dure le filler » ou « Botox ou Dysport » continue d'attirer des gens qui font des recherches pendant des semaines et des mois après sa publication, et c'est exactement le matériel dans lequel les assistants IA puisent quand quelqu'un demande à qui faire confiance pour des injectables dans le coin. Vous bâtissez un actif que vous possédez au lieu de louer de l'attention."}, {"q": "La plupart de nos clientes viennent d'Instagram. Pourquoi un blogue est-il important?", "a": "Instagram est excellent pour montrer des résultats et rester dans les esprits, mais c'est un jardin clos. Ça ne vous aide pas à apparaître quand quelqu'un cherche sur Google « filler de cernes près de moi » ou demande à ChatGPT qui fait du laser de façon sécuritaire dans votre région. Le blogue couvre ce moment de recherche à forte intention qu'Instagram ne peut pas atteindre, et il alimente votre fiche d'établissement Google pour que l'emplacement sur la carte et les résultats de recherche travaillent ensemble."}]}}, {"id": "cosmetic-dentistry", "label": "Cosmetic & implant dentistry", "complianceNote": "Results vary by practice, market, and case mix. This is not dental or medical advice. Individual results are not guaranteed, and no specific rankings, consult volume, or case outcomes are promised. Illustrative figures are examples only and do not reflect a typical or expected result.", "headline": "Be the Cosmetic and Implant Dentist Google and AI Recommend", "subhead": "We write and publish an ongoing, on-brand blog that helps your practice show up in Google Search, Google Maps, and AI answers right when high-value patients are researching veneers, implants, and Invisalign. So the people ready to invest in their smile find you while they're still deciding.", "painPoints": ["Veneer, implant, and Invisalign patients research for weeks before they ever pick up the phone, and right now they're reading corporate DSO pages and clear-aligner brand sites instead of yours.", "You're paying a premium per click on 'dental implants near me' and 'cost of veneers,' yet your own site never answers the cost, pain, healing-time, and 'am I a candidate' questions those same patients are typing.", "When someone asks ChatGPT or Google's AI Overview 'who's a good implant dentist near me,' it surfaces the same handful of practices every time, and your high-ticket All-on-4 and smile-makeover cases quietly walk into their chairs."], "exampleSearches": ["dental implants near me cost / how much is a full set of veneers in [city]", "best Invisalign dentist near me reviews / cosmetic dentist that does payment plans", "Ask ChatGPT: \"I'm missing two front teeth and I'm embarrassed to smile. What are my options, and who's a good cosmetic or implant dentist near [city] that offers sedation?\""], "whatWeDo": ["Publish patient-first articles on the exact topics that drive high-value consults: implant cost and longevity, veneers vs. bonding, Invisalign vs. braces for adults, All-on-4, sedation options, bone grafting, and honest 'am I a candidate' guides, all in your voice and written for your city.", "Structure every post so Google can rank it and AI assistants can quote it, with direct answers, local context, and FAQ sections that mirror how patients actually phrase smile and implant questions to ChatGPT, Gemini, and Perplexity.", "Connect your content to your Google Business Profile and booking flow so a reader weighing a smile makeover or full-arch implant case moves from 'just researching' to requesting a consult with you.", "Track which topics and questions are surfacing your practice in search and AI answers, then keep publishing on what's actually bringing in cosmetic and implant cases, not vanity traffic."], "proof": "In one illustrative case, an implant and cosmetic practice's blog grew from 312 to 4,187 organic visits a month over two quarters, and consult requests started mentioning specific articles patients had read before reaching out. Illustrative only; results vary.", "faq": [{"q": "Cosmetic and implant cases are high-ticket. Can a blog really bring in those patients?", "a": "That's exactly what it's built for. Someone weighing veneers, implants, or Invisalign is spending thousands of dollars, so they read several articles and quietly judge who they trust before booking. We publish the content that answers their cost, candidacy, sedation, and 'what is it really like' questions, so your practice is the one they keep finding and feel confident calling."}, {"q": "Is this safe for a dental practice? I can't make medical claims.", "a": "Yes. We write educational, patient-friendly content and never promise outcomes or make clinical guarantees. Everything is framed responsibly so it supports your reputation and stays within how a dental practice should communicate online, and you can review anything before it publishes."}, {"q": "How is this different from the SEO agency or ad spend I already have?", "a": "Ads stop the moment you stop paying, and most SEO retainers never produce the steady, patient-focused content that ranking and AI recommendation actually depend on. We focus on consistently publishing on-brand articles designed to get your practice found in both Google and AI answers, which keeps working between billing cycles. It's month to month, cancel anytime, with a 60-day money-back guarantee."}], "icon": "🦷", "fr": {"label": "Dentisterie esthétique et implantologie", "complianceNote": "Les résultats varient selon la clinique, le marché et le type de cas traités. Ceci ne constitue pas un avis dentaire ni médical. Les résultats individuels ne sont pas garantis, et aucun positionnement précis, volume de consultations ou résultat clinique n'est promis. Les chiffres présentés le sont à titre indicatif seulement et ne reflètent pas un résultat typique ou attendu.", "painPoints": ["Les patients qui envisagent des facettes, des implants ou Invisalign font des recherches pendant des semaines avant même de décrocher le téléphone, et en ce moment, ils lisent les pages des grandes bannières dentaires et des marques de gouttières transparentes au lieu des vôtres.", "Vous payez le gros prix par clic sur « implants dentaires près de chez moi » et « coût des facettes », pourtant votre propre site ne répond jamais aux questions de coût, de douleur, de temps de guérison et de « suis-je un bon candidat » que ces mêmes patients tapent.", "Quand quelqu'un demande à ChatGPT ou à l'aperçu IA de Google « quel est un bon dentiste en implantologie près de chez moi », ce sont toujours les mêmes quelques cliniques qui ressortent, et vos cas à forte valeur comme les All-on-4 et les transformations du sourire s'installent discrètement dans leurs fauteuils."], "exampleSearches": ["implants dentaires près de chez moi prix / combien coûte un ensemble complet de facettes à [ville]", "meilleur dentiste invisalign près de chez moi avis / dentiste esthétique avec plan de paiement", "Demandez a ChatGPT : « Il me manque deux dents en avant et j'ai honte de sourire. Quelles sont mes options, et quel est un bon dentiste esthétique ou en implantologie près de [ville] qui offre la sédation? »"], "whatWeDo": ["Publier des articles axés sur le patient, sur les sujets exacts qui génèrent des consultations à forte valeur : coût et durabilité des implants, facettes ou facettes en composite, Invisalign ou broches pour adultes, All-on-4, options de sédation, greffe osseuse, et des guides honnêtes du type « suis-je un bon candidat », le tout dans votre voix et écrit pour votre ville.", "Structurer chaque article pour que Google puisse le classer et que les assistants IA puissent le citer, avec des réponses directes, un contexte local et des sections FAQ qui reprennent la façon dont les patients formulent réellement leurs questions sur le sourire et les implants à ChatGPT, Gemini et Perplexity.", "Relier votre contenu à votre fiche Google Business et à votre processus de prise de rendez-vous, pour qu'un lecteur qui pèse une transformation du sourire ou un cas d'implants sur arcade complète passe de « je magasine » à demander une consultation chez vous.", "Suivre quels sujets et quelles questions font ressortir votre clinique dans les recherches et les réponses IA, puis continuer à publier sur ce qui amène réellement des cas esthétiques et d'implants, pas du trafic de vanité."], "headline": "Soyez le dentiste esthétique et en implantologie que Google et l'IA recommandent", "subhead": "Nous rédigeons et publions un blogue continu, fidèle à votre image, qui aide votre clinique à apparaître dans la recherche Google, dans Google Maps et dans les réponses IA juste au moment où des patients à forte valeur s'informent sur les facettes, les implants et Invisalign. Ainsi, les gens prêts à investir dans leur sourire vous trouvent pendant qu'ils sont encore en train de décider.", "proof": "Dans un cas présenté à titre indicatif, le blogue d'une clinique d'implantologie et de dentisterie esthétique est passé de 312 à 4 187 visites organiques par mois en deux trimestres, et les demandes de consultation se sont mises à mentionner des articles précis que les patients avaient lus avant de prendre contact. À titre indicatif seulement; les résultats varient.", "faq": [{"q": "Les cas esthétiques et d'implants sont à forte valeur. Un blogue peut-il vraiment attirer ces patients?", "a": "C'est exactement ce pour quoi il est conçu. Une personne qui envisage des facettes, des implants ou Invisalign s'apprête à dépenser des milliers de dollars; elle lit donc plusieurs articles et juge discrètement à qui elle fait confiance avant de réserver. Nous publions le contenu qui répond à ses questions de coût, d'admissibilité, de sédation et de « à quoi ça ressemble vraiment », pour que votre clinique soit celle qu'elle continue de trouver et qu'elle se sente en confiance d'appeler."}, {"q": "Est-ce sécuritaire pour une clinique dentaire? Je ne peux pas faire d'allégations médicales.", "a": "Oui. Nous rédigeons du contenu éducatif et convivial pour les patients, et nous ne promettons jamais de résultats ni ne faisons de garanties cliniques. Tout est formulé de façon responsable, afin de soutenir votre réputation et de rester dans les limites de la façon dont une clinique dentaire devrait communiquer en ligne, et vous pouvez tout réviser avant la publication."}, {"q": "En quoi est-ce différent de l'agence de référencement ou du budget publicitaire que j'ai déjà?", "a": "Les publicités s'arrêtent dès que vous cessez de payer, et la plupart des forfaits de référencement ne produisent jamais le contenu constant et axé sur le patient dont dépendent réellement le classement et la recommandation par l'IA. Nous nous concentrons sur la publication régulière d'articles fidèles à votre image, conçus pour faire trouver votre clinique à la fois dans Google et dans les réponses IA, ce qui continue de travailler entre les cycles de facturation. C'est de mois en mois, annulable en tout temps, avec une garantie de remboursement de 60 jours."}]}}, {"id": "weight-loss-glp1", "label": "Weight-loss & GLP-1 clinics", "headline": "Be the GLP-1 Clinic Google and AI Recommend", "subhead": "When someone nearby searches semaglutide, tirzepatide, or medical weight loss, you want to be the clinic that shows up. We publish an ongoing, on-brand blog built to help you get found in Google Search, Google Maps, and AI assistants like ChatGPT and Gemini, then route those patients to your booking page.", "painPoints": ["You are up against telehealth giants and compounding pharmacies that outspend you, while local patients who would happily drive in for real provider oversight never learn your clinic exists.", "People research GLP-1s for weeks before booking (monthly cost, side effects, dosing, 'do I even qualify'), they ask Google and ChatGPT, but your site has nothing answering those questions, so the answer engine never names you.", "You are caught between strict medical advertising rules and the pressure to market harder, with no time to write compliant content between consults, titration check-ins, and prior-auth paperwork."], "exampleSearches": ["semaglutide weight loss clinic near me", "tirzepatide cost per month without insurance [city]", "Ask ChatGPT: I want to start a GLP-1 for weight loss in [city]. Which local clinics offer it, do they take cash pay, and roughly what does it run per month?"], "whatWeDo": ["Publish patient-intent articles that answer what actually drives GLP-1 searches: 'Do I qualify for semaglutide?', tirzepatide vs semaglutide, what month one looks like, and how to handle common side effects like nausea.", "Build local service-area pages that tie your treatments to the towns you serve, so you surface for 'medical weight loss near me' and 'GLP-1 clinic in [city]' across Search and Maps.", "Structure every post so AI assistants can cite your clinic when someone asks where to start a weight-loss program, with clear service, location, cash-pay, and eligibility details they can quote back.", "Keep each article reviewed against medical advertising norms and point readers to your Google Business Profile and booking link, with no outcome claims that put your clinic at risk."], "proof": "In one illustrative case, a medical weight-loss clinic grew from 41 to 1,213 monthly blog visitors over several months, with 187 of them reaching the 'do I qualify' page that feeds consult bookings. Illustrative only; results vary.", "faq": [{"q": "Will the content make medical claims that could get my clinic in trouble?", "a": "No. Every article is written to inform, not to promise outcomes. We avoid guaranteed weight-loss numbers and specific results, keep GLP-1 information educational, and you can review or approve anything before it publishes. The goal is to get you found, not to create compliance headaches."}, {"q": "How is this different from the national telehealth brands ranking everywhere?", "a": "Those brands win broad, generic searches. Your edge is local and trust-based: patients who want an in-person clinic, real provider oversight, and someone in their own city. We aim your content at 'near me' intent and local service-area pages, which is exactly where AI assistants and Maps look when someone wants a clinic they can actually walk into."}, {"q": "Do I have to write or edit anything myself?", "a": "No. This is done-for-you. We handle the topics, drafting, on-page SEO, and publishing to your blog on an ongoing schedule. You stay focused on patients. If you want to review before posts go live, we make that easy, and you can cancel anytime."}], "complianceNote": "Educational content only, not medical advice. We do not promise specific weight-loss results, eligibility, or search rankings. Individual results vary, and all treatment decisions are between a patient and their licensed provider. Month to month, cancel anytime, 60-day money-back guarantee.", "icon": "📉", "fr": {"label": "Cliniques de perte de poids et GLP-1", "complianceNote": "Contenu éducatif seulement, pas un avis médical. Nous ne promettons aucun résultat précis de perte de poids, aucune admissibilité ni aucun classement dans les moteurs de recherche. Les résultats varient d'une personne à l'autre, et toute décision de traitement relève du patient et de son professionnel de la santé autorisé. De mois en mois, annulez en tout temps, garantie de remboursement de 60 jours.", "painPoints": ["Vous êtes en concurrence avec des géants de la télésanté et des pharmacies de préparations magistrales qui dépensent bien plus que vous, pendant que des patients de votre région, prêts à se déplacer pour un vrai suivi clinique, ne savent même pas que votre clinique existe.", "Les gens se renseignent sur les GLP-1 pendant des semaines avant de prendre rendez-vous (coût mensuel, effets secondaires, posologie, « est-ce que je suis admissible »); ils posent leurs questions à Google et à ChatGPT, mais votre site n'y répond pas, alors le moteur de réponses ne vous nomme jamais.", "Vous êtes coincé entre des règles strictes de publicité médicale et la pression de vendre plus fort, sans avoir le temps de rédiger du contenu conforme entre les consultations, les suivis d'ajustement de dose et la paperasse d'autorisation préalable."], "exampleSearches": ["clinique perte de poids semaglutide près de chez moi", "coût mensuel tirzepatide sans assurance [ville]", "Demandez a ChatGPT : je veux commencer un GLP-1 pour perdre du poids à [ville]. Quelles cliniques locales en offrent, acceptent-elles le paiement comptant, et ça coûte environ combien par mois ?"], "whatWeDo": ["Publier des articles axés sur l'intention des patients qui répondent à ce qui motive vraiment les recherches sur les GLP-1 : « Suis-je admissible au semaglutide ? », tirzepatide ou semaglutide, à quoi ressemble le premier mois et comment gérer des effets secondaires courants comme les nausées.", "Créer des pages locales par zone de service qui relient vos traitements aux villes que vous desservez, pour que vous apparaissiez sur « perte de poids médicale près de chez moi » et « clinique GLP-1 à [ville] » dans la recherche et dans Maps.", "Structurer chaque article pour que les assistants IA puissent citer votre clinique quand quelqu'un demande où commencer un programme de perte de poids, avec des détails clairs sur le service, l'emplacement, le paiement comptant et l'admissibilité qu'ils peuvent reprendre.", "Réviser chaque article selon les normes de publicité médicale et diriger les lecteurs vers votre fiche Google Business Profile et votre lien de prise de rendez-vous, sans aucune promesse de résultat qui mettrait votre clinique à risque."], "headline": "Soyez la clinique GLP-1 que Google et l'IA recommandent", "subhead": "Quand une personne près de chez vous cherche semaglutide, tirzepatide ou perte de poids médicale, vous voulez être la clinique qui ressort. Nous publions un blogue continu, à votre image, conçu pour vous aider à être trouvé dans la recherche Google, dans Google Maps et dans les assistants IA comme ChatGPT et Gemini, puis à diriger ces patients vers votre page de prise de rendez-vous.", "proof": "Dans un cas présenté à titre indicatif, une clinique de perte de poids médicale est passée de 41 à 1 213 visiteurs de blogue par mois sur quelques mois, dont 187 ont atteint la page « suis-je admissible » qui alimente les prises de rendez-vous en consultation. À titre indicatif seulement; les résultats varient.", "faq": [{"q": "Le contenu va-t-il faire des affirmations médicales qui pourraient causer des ennuis à ma clinique ?", "a": "Non. Chaque article est rédigé pour informer, pas pour promettre des résultats. Nous évitons les chiffres de perte de poids garantis et les résultats précis, nous gardons l'information sur les GLP-1 éducative, et vous pouvez tout réviser ou approuver avant la publication. L'objectif est de vous faire trouver, pas de vous créer des maux de tête de conformité."}, {"q": "En quoi est-ce différent des grandes marques nationales de télésanté qui se classent partout ?", "a": "Ces marques remportent les recherches larges et génériques. Votre avantage est local et fondé sur la confiance : des patients qui veulent une clinique en personne, un vrai suivi clinique et quelqu'un dans leur propre ville. Nous orientons votre contenu vers l'intention « près de chez moi » et vers des pages locales par zone de service, soit exactement là où les assistants IA et Maps regardent quand quelqu'un veut une clinique où il peut vraiment se présenter."}, {"q": "Dois-je rédiger ou modifier quoi que ce soit moi-même ?", "a": "Non. C'est un service clé en main. Nous nous occupons des sujets, de la rédaction, du référencement sur la page et de la publication sur votre blogue selon un calendrier continu. Vous restez concentré sur vos patients. Si vous voulez réviser avant la mise en ligne, nous facilitons les choses, et vous pouvez annuler en tout temps."}]}}, {"id": "fertility-ivf", "label": "Fertility & IVF", "complianceNote": "Educational content only. Not medical advice. Individual results and treatment outcomes vary, and success depends on many personal factors including age and diagnosis. Nothing here predicts or guarantees pregnancy, search rankings, or patient volume.", "exampleSearches": ["best IVF clinic near me with good success rates", "how much does one round of IVF cost without insurance in [city]", "Ask ChatGPT: I'm 38 and we've been trying for over a year. What questions should I ask at a first fertility consult, and which clinics near me are worth looking into?"], "faq": [{"q": "We're a medical practice. Will the content stay compliant and on-brand?", "a": "Yes. Everything reads as patient education, never medical advice or a promise of pregnancy. We steer clear of success-rate claims, stay careful around age, diagnosis, and donor topics, and send anything sensitive to your team before it publishes. Your physicians can approve or edit any piece. It should sound like your clinic, warm and credible, not like a marketing brochure."}, {"q": "How does this help us show up when someone asks ChatGPT or Gemini for a fertility clinic?", "a": "AI assistants pull from clear, well-structured content they can trust. We publish real depth on the things patients ask about: IUI vs IVF, egg freezing, what one round costs and how financing works, what a first consult actually involves, and your specific services. We format it the way these models read best and reinforce the signals tied to your Google Business Profile. So when someone asks an AI for fertility help in your area, you're a clinic it can confidently surface."}, {"q": "Patients research for months before booking. Does blog content actually bring consults?", "a": "That long, anxious research window is exactly why this works. People compare clinics, costs, and success language for weeks, sometimes longer, before they pick up the phone. If your clinic answers the questions they're Googling and asking AI at each stage, from first worry to choosing a protocol, you're the name they already trust when they finally book. We aim the content at real decision moments, not vanity traffic."}], "headline": "Become the Fertility Clinic Google and AI Recommend to Couples Ready to Start", "subhead": "We write and publish an ongoing, physician-safe blog that answers the real questions hopeful parents type into Google and ask AI, then guides them to your Google profile and consult booking. Built for the long, careful research journey fertility patients actually take.", "painPoints": ["Patients spend weeks or months quietly researching IVF, IUI, and egg freezing before they ever call, and your clinic is invisible during the exact window when they're deciding who to trust with something this personal.", "Big networks and clinics with full-time marketing teams own the top of Google, and now they're showing up in AI answers too. A single-location practice gets buried even when the care is better.", "Marketing fertility is a compliance minefield. You can't promise success rates or pregnancy, every claim feels risky, and generic agencies write content that sounds salesy or crosses a line your physicians won't sign off on."], "whatWeDo": ["Publish patient-education articles on the decisions they're actually searching: IVF vs IUI, egg freezing and timing, what one cycle costs and how financing works, donor and LGBTQ+ family building, and what to expect at a first consultation.", "Optimize for Google Search and Google Maps so you surface for high-intent local searches like 'fertility clinic near me' and 'IVF cost in [city].'", "Structure content so ChatGPT, Gemini, Perplexity, and Google AI Overviews can read and recommend your clinic when someone asks an AI for fertility help in your area.", "Keep every piece medically careful and review-ready: no success guarantees, no risky claims, written in your clinic's compassionate voice with physician approval before anything goes live."], "proof": "A regional fertility practice that began publishing consistent patient-education content saw its non-branded organic visits climb to roughly 3,142 a month, with articles starting to appear in AI answers for first-consult and cost questions. Illustrative only; individual results vary.", "icon": "🍼", "fr": {"label": "Fertilité et FIV", "complianceNote": "Contenu éducatif seulement. Ne constitue pas un avis médical. Les résultats individuels et l'issue des traitements varient, et le succès dépend de nombreux facteurs personnels, dont l'âge et le diagnostic. Rien ici ne prédit ni ne garantit une grossesse, un classement dans les moteurs de recherche ou un volume de patients.", "painPoints": ["Vos patients passent des semaines, parfois des mois, à se renseigner discrètement sur la FIV, l'IIU et la congélation d'ovules avant même de vous appeler, et votre clinique reste invisible précisément au moment où ils décident à qui confier quelque chose d'aussi personnel.", "Les grands réseaux et les cliniques dotées d'équipes marketing à temps plein occupent le haut de Google, et ils apparaissent maintenant aussi dans les réponses générées par l'IA. Une clinique à établissement unique se retrouve enterrée, même quand les soins y sont meilleurs.", "Faire la promotion d'un service de fertilité, c'est marcher sur un champ de mines réglementaire. Vous ne pouvez pas promettre de taux de succès ni de grossesse, chaque affirmation semble risquée, et les agences génériques rédigent un contenu qui sonne trop commercial ou qui franchit une ligne que vos médecins n'approuveront jamais."], "exampleSearches": ["meilleure clinique de fertilité près de chez moi avec bons taux de succès", "combien coûte un cycle de fiv sans assurance à [ville]", "Demandez a ChatGPT : j'ai 38 ans et on essaie depuis plus d'un an. Quelles questions devrais-je poser lors d'une première consultation en fertilité, et quelles cliniques près de chez moi valent la peine d'être considérées?"], "whatWeDo": ["Nous publions des articles d'éducation aux patients sur les décisions qu'ils cherchent vraiment à comprendre : FIV ou IIU, congélation d'ovules et bon moment pour le faire, ce que coûte un cycle et comment fonctionne le financement, le parcours pour fonder une famille avec donneur ou pour les familles LGBTQ+, et à quoi s'attendre lors d'une première consultation.", "Nous optimisons pour la recherche Google et Google Maps afin que vous ressortiez sur les recherches locales à forte intention comme « clinique de fertilité près de chez moi » et « coût d'une FIV à [ville] ».", "Nous structurons le contenu pour que ChatGPT, Gemini, Perplexity et les aperçus IA de Google puissent lire et recommander votre clinique quand quelqu'un demande de l'aide en fertilité dans votre région.", "Nous gardons chaque texte prudent sur le plan médical et prêt à être révisé : aucune garantie de succès, aucune affirmation risquée, le tout rédigé dans la voix bienveillante de votre clinique et soumis à l'approbation des médecins avant toute mise en ligne."], "headline": "Devenez la clinique de fertilité que Google et l'IA recommandent aux couples prêts à se lancer", "subhead": "Nous rédigeons et publions un blogue continu, sécuritaire pour les médecins, qui répond aux vraies questions que les futurs parents tapent dans Google et posent à l'IA, puis qui les guide vers votre fiche Google et la prise de rendez-vous pour une consultation. Conçu pour le long parcours de recherche, prudent et réfléchi, que vivent réellement les patients en fertilité.", "proof": "Une clinique de fertilité régionale qui s'est mise à publier régulièrement du contenu d'éducation aux patients a vu ses visites organiques non liées à sa marque grimper à environ 3 142 par mois, ses articles commençant à apparaître dans les réponses de l'IA pour les questions de première consultation et de coût. À titre indicatif seulement; les résultats individuels varient.", "faq": [{"q": "Nous sommes une clinique médicale. Le contenu restera-t-il conforme et fidèle à notre image?", "a": "Oui. Tout se lit comme de l'éducation aux patients, jamais comme un avis médical ni une promesse de grossesse. Nous évitons les affirmations sur les taux de succès, nous demeurons prudents sur les sujets liés à l'âge, au diagnostic et aux donneurs, et nous soumettons tout contenu délicat à votre équipe avant publication. Vos médecins peuvent approuver ou modifier chaque texte. Ça doit sonner comme votre clinique, chaleureux et crédible, pas comme une brochure publicitaire."}, {"q": "Comment cela nous aide-t-il à ressortir quand quelqu'un demande une clinique de fertilité à ChatGPT ou Gemini?", "a": "Les assistants IA puisent dans du contenu clair, bien structuré et digne de confiance. Nous publions une vraie profondeur sur ce que les patients demandent : IIU ou FIV, congélation d'ovules, ce que coûte un cycle et comment fonctionne le financement, ce qu'implique réellement une première consultation, et vos services précis. Nous le mettons en forme de la façon que ces modèles lisent le mieux et nous renforçons les signaux liés à votre fiche d'établissement Google. Ainsi, quand quelqu'un demande de l'aide en fertilité à une IA dans votre région, vous êtes une clinique qu'elle peut mettre de l'avant avec confiance."}, {"q": "Les patients font des recherches pendant des mois avant de prendre rendez-vous. Le contenu de blogue amène-t-il vraiment des consultations?", "a": "C'est justement cette longue période de recherche anxieuse qui fait fonctionner cette approche. Les gens comparent les cliniques, les coûts et le discours sur le succès pendant des semaines, parfois plus longtemps, avant de décrocher le téléphone. Si votre clinique répond aux questions qu'ils tapent dans Google et posent à l'IA à chaque étape, de la première inquiétude au choix d'un protocole, vous êtes le nom auquel ils font déjà confiance au moment de prendre rendez-vous. Nous orientons le contenu vers les vrais moments de décision, pas vers du trafic de vanité."}]}}, {"id": "hair-restoration", "label": "Hair restoration", "headline": "Be the Hair Restoration Clinic Google and AI Recommend", "subhead": "We write and publish an ongoing, on-brand blog that helps your clinic show up in Google Search, Google Maps, and the AI answers people now trust. So the right patients find you while they are quietly researching FUE, FUT, and PRP at 1 a.m.", "painPoints": ["Your patients research in private for months before they ever pick up the phone, and most of that comparison happens on Google and inside ChatGPT, where your clinic is invisible. By the time they book a consult somewhere, you were never on the shortlist.", "You are competing against the big chains and the medical-tourism offers running their entire pitch on Instagram before-and-afters, while your actual surgical credentials, technique, and graft-count expertise never get explained where a cautious buyer is actually reading.", "Generic agencies treat hair transplants like any other 'medical SEO,' so the content reads like a brochure. It ignores how nervous and skeptical these buyers are and never touches the questions that decide the sale: turkey versus a local surgeon, cost per graft, scarring, shock loss, and whether it will actually look natural."], "exampleSearches": ["best hair transplant clinic near me cost per graft", "is FUE or FUT better for a receding hairline at 32", "Ask ChatGPT: I'm losing my hair in my early 30s, what's the difference between FUE, FUT, and PRP, and how do I find a reputable hair transplant surgeon near me?"], "whatWeDo": ["Publish patient-focused articles on the questions that actually drive consults: FUE vs FUT, realistic cost per graft, recovery and shock-loss timelines, what a 'natural-looking hairline' really means, and how to vet a surgeon. So you get found mid-research, not after they have chosen someone else.", "Structure every piece so AI assistants can recognize and reference your clinic when someone asks ChatGPT, Gemini, or Perplexity for hair restoration guidance, then point them toward your Google Business Profile and consult booking.", "Build local authority for the specific cities and neighborhoods you serve, so you show up in Google Maps and the local pack against the chains and the overseas package deals.", "Keep the tone medically responsible and credibility-first, leaning on your technique, graft-count experience, and board certifications, written to inform and earn trust without overpromising any result."], "proof": "In one illustrative case, a hair restoration practice saw blog-attributed consult requests grow from 11 to 43 a month over roughly 6 months of consistent publishing. Illustrative only, individual results vary.", "faq": [{"q": "Hair restoration is a high-trust, expensive decision. Will the content actually sound credible?", "a": "Yes. We write for a cautious, well-researched reader, not to hype. Articles lean on your real technique, graft-count experience, and credentials, and we never promise a specific result. The goal is to make your clinic the one that reads as the most trustworthy when someone is deciding where to spend thousands of dollars on their own scalp."}, {"q": "How does showing up in ChatGPT or Gemini actually bring me patients?", "a": "More people now ask AI assistants things like 'how do I choose a hair transplant surgeon' before they ever open Google Maps. We structure your content so those tools can recognize and surface your clinic, then route the reader to your booking and Google Business Profile. It puts you in the conversation at the exact moment someone is forming their shortlist."}, {"q": "I already run Instagram and Google Ads. Why add a blog?", "a": "Ads and social capture people who already know they want a transplant. The blog reaches the much larger group still researching, comparing FUE and FUT, and worrying about scars, cost, and natural results. It is the compounding asset that keeps working between ad campaigns and feeds the AI answers your paid channels cannot reach."}], "complianceNote": "Educational content only, not medical advice. We never guarantee rankings, consult volume, or surgical outcomes. Individual results vary and depend on many factors outside our control. Month to month, cancel anytime, backed by a 60-day money-back guarantee.", "icon": "💈", "fr": {"label": "Restauration capillaire", "complianceNote": "Contenu éducatif seulement, ne constitue pas un avis médical. Nous ne garantissons jamais le positionnement, le volume de consultations ni les résultats chirurgicaux. Les résultats varient d'une personne à l'autre et dépendent de nombreux facteurs hors de notre contrôle. Sans engagement, mois après mois, annulez en tout temps, le tout appuyé par une garantie de remboursement de 60 jours.", "painPoints": ["Vos patients font leurs recherches en privé pendant des mois avant même de décrocher le téléphone, et la majeure partie de cette comparaison se passe sur Google et dans ChatGPT, là où votre clinique est invisible. Au moment où ils réservent une consultation quelque part, vous n'avez jamais figuré sur leur liste.", "Vous êtes en concurrence avec les grandes chaînes et les offres de tourisme médical qui basent tout leur argumentaire sur des photos avant-après Instagram, pendant que vos véritables compétences chirurgicales, votre technique et votre expertise du nombre de greffons ne sont jamais expliquées là où un acheteur prudent lit réellement.", "Les agences génériques traitent la greffe de cheveux comme n'importe quel autre « SEO médical », alors le contenu se lit comme une brochure. Il ignore à quel point ces acheteurs sont nerveux et sceptiques, et n'aborde jamais les questions qui décident de la vente : la Turquie versus un chirurgien d'ici, le coût par greffon, les cicatrices, le choc de perte (shock loss) et si le résultat aura vraiment l'air naturel."], "exampleSearches": ["meilleure clinique greffe de cheveux près de chez moi coût par greffon", "fue ou fut mieux pour une calvitie frontale à 32 ans", "Demandez a ChatGPT : je perds mes cheveux au début de la trentaine, quelle est la différence entre la FUE, la FUT et le PRP, et comment trouver un chirurgien en greffe capillaire réputé près de chez moi ?"], "whatWeDo": ["Nous publions des articles axés sur les patients qui répondent aux vraies questions menant à une consultation : FUE versus FUT, coût réaliste par greffon, échéanciers de récupération et de choc de perte, ce que veut vraiment dire une « ligne capillaire d'allure naturelle » et comment bien évaluer un chirurgien. Ainsi, on vous trouve en pleine recherche, et non une fois qu'ils ont déjà choisi quelqu'un d'autre.", "Nous structurons chaque article pour que les assistants IA puissent reconnaître et mentionner votre clinique lorsqu'une personne demande conseil sur la restauration capillaire à ChatGPT, Gemini ou Perplexity, puis les orientons vers votre fiche d'établissement Google et votre prise de rendez-vous.", "Nous bâtissons votre autorité locale pour les villes et les quartiers précis que vous desservez, afin que vous apparaissiez dans Google Maps et le bloc local face aux chaînes et aux forfaits à l'étranger.", "Nous gardons un ton médicalement responsable qui mise d'abord sur la crédibilité, en nous appuyant sur votre technique, votre expérience en nombre de greffons et vos certifications professionnelles, le tout rédigé pour informer et bâtir la confiance sans surpromettre quelque résultat que ce soit."], "headline": "Devenez la clinique de restauration capillaire que Google et l'IA recommandent", "subhead": "Nous rédigeons et publions un blogue continu et fidèle à votre image qui aide votre clinique à apparaître dans la recherche Google, dans Google Maps et dans les réponses IA auxquelles les gens se fient désormais. Ainsi, les bons patients vous trouvent pendant qu'ils s'informent discrètement sur la FUE, la FUT et le PRP à 1 h du matin.", "proof": "Dans un cas présenté à titre indicatif, une clinique de restauration capillaire a vu les demandes de consultation attribuées au blogue passer de 11 à 43 par mois sur environ 6 mois de publication constante. À titre indicatif seulement, les résultats varient d'une personne à l'autre.", "faq": [{"q": "La restauration capillaire est une décision coûteuse qui demande beaucoup de confiance. Le contenu va-t-il vraiment paraître crédible ?", "a": "Oui. Nous écrivons pour un lecteur prudent et bien renseigné, pas pour faire du tape-à-l'oeil. Les articles s'appuient sur votre véritable technique, votre expérience en nombre de greffons et vos qualifications, et nous ne promettons jamais un résultat précis. L'objectif est de faire en sorte que votre clinique soit perçue comme la plus digne de confiance lorsqu'une personne décide où dépenser des milliers de dollars sur son propre cuir chevelu."}, {"q": "Comment le fait d'apparaître dans ChatGPT ou Gemini m'amène-t-il concrètement des patients ?", "a": "De plus en plus de gens posent maintenant aux assistants IA des questions comme « comment choisir un chirurgien en greffe de cheveux » avant même d'ouvrir Google Maps. Nous structurons votre contenu pour que ces outils puissent reconnaître et mettre en avant votre clinique, puis dirigent le lecteur vers votre prise de rendez-vous et votre fiche d'établissement Google. Cela vous place dans la conversation au moment exact où quelqu'un est en train de bâtir sa liste de candidats."}, {"q": "Je fais déjà de l'Instagram et de la publicité Google. Pourquoi ajouter un blogue ?", "a": "La publicité et les réseaux sociaux captent les gens qui savent déjà qu'ils veulent une greffe. Le blogue rejoint le groupe beaucoup plus vaste de ceux qui en sont encore à s'informer, à comparer la FUE et la FUT et à s'inquiéter des cicatrices, du coût et du naturel du résultat. C'est l'actif cumulatif qui continue de travailler entre vos campagnes publicitaires et qui alimente les réponses IA que vos canaux payants ne peuvent pas atteindre."}]}}, {"id": "immigration-law", "label": "Immigration law", "headline": "Be the Immigration Firm Google and AI Recommend", "subhead": "We write and publish an ongoing, on-brand blog so your firm shows up when someone searches \"immigration lawyer near me\" and when they ask ChatGPT how to bring a spouse over, respond to an RFE, or fight a denial. Designed to help you get found on Google, Maps, and inside AI answers.", "painPoints": ["You compete against national lead-gen mills and directory sites that outrank your firm for nearly every visa term, so the people searching never even see your name.", "Your best cases come by referral, but when a referred client Googles your firm or asks an AI to vet you before booking, there is almost nothing recent or substantive to find.", "Immigration rules move constantly (priority date movement, new policy memos, fee changes, shifting USCIS processing times), so your site content goes stale fast and the firm looks inactive to both Google and prospective clients."], "exampleSearches": ["immigration lawyer near me for green card through marriage", "best immigration attorney in [city] for H-1B RFE response", "Ask ChatGPT: \"My work visa was denied and I have a short window to respond. What are my options and what kind of immigration lawyer should I talk to?\""], "whatWeDo": ["Publish plain-language guides on the cases you actually want (family green cards, employment visas, asylum, naturalization, deportation defense) so the right clients find you instead of a referral mill.", "Write the way real clients search and ask AI, by situation and worry (\"can I travel while my I-485 is pending\", \"will a DUI affect my naturalization\", \"how long is consular processing right now\"), not by dry statute names.", "Keep your firm current with timely posts when policy, processing times, or filing fees shift, signaling to Google and AI that the firm is active and authoritative.", "Build the local and topical signals that point searchers toward your Google Business Profile and consultation booking, so visibility has a real path to becoming actual consults."], "proof": "In one illustrative case, an immigration firm grew from 287 to 1,613 monthly organic visitors over several months of consistent publishing, alongside a noticeable lift in consultation form fills. Illustrative only; individual results vary.", "faq": [{"q": "Will the content be accurate? Immigration rules change all the time.", "a": "Everything is written in clear, current language and framed as general information, not legal advice, with your firm positioned as the place to get case-specific guidance. When policy, fees, or processing times shift, we publish updates so your site reflects the current landscape instead of last year's rules. You can review anything before it goes live."}, {"q": "How does this actually help an AI assistant point people to my firm?", "a": "When your blog clearly answers the real questions people ask (about visas, denials, timelines, eligibility), it becomes the kind of source AI tools tend to pull from and reference. We structure content so assistants can find your firm and route people toward your booking, while keeping every claim honest and free of guarantees. We can't promise any assistant will name you, but this is how you become a credible, citable option."}, {"q": "We serve clients in multiple states and languages. Can you handle that?", "a": "Yes. We tailor content to the jurisdictions and client communities you serve, focusing on the case types and locations you want more of. We do not promise specific rankings or case outcomes. The goal is steady, durable visibility so more of the right people find and contact your firm."}], "complianceNote": "Attorney advertising. Informational content only, not legal advice, and no attorney-client relationship is formed by reading it. Results vary and individual case outcomes are not guaranteed. Month to month, cancel anytime, with a 60-day money-back guarantee.", "icon": "🛂", "fr": {"label": "Droit de l'immigration", "complianceNote": "Publicité d'avocat. Contenu informatif seulement, qui ne constitue pas un avis juridique; sa lecture ne crée aucune relation avocat-client. Les résultats varient et l'issue d'un dossier individuel n'est pas garantie. De mois en mois, annulation en tout temps, avec une garantie de remboursement de 60 jours.", "painPoints": ["Vous êtes en concurrence avec des usines à prospects nationales et des sites d'annuaires qui devancent votre cabinet sur presque chaque terme lié aux visas, si bien que les gens qui cherchent ne voient jamais votre nom.", "Vos meilleurs dossiers viennent par référence, mais quand un client référé cherche votre cabinet sur Google ou demande à une IA de vous évaluer avant de réserver, il n'y a presque rien de récent ou de substantiel à trouver.", "Les règles d'immigration bougent constamment (mouvement des dates de priorité, nouvelles notes de politique, changements de frais, délais de traitement de l'USCIS qui fluctuent), alors le contenu de votre site devient vite périmé et le cabinet paraît inactif autant aux yeux de Google que des clients potentiels."], "exampleSearches": ["avocat en immigration près de chez moi pour carte verte par mariage", "meilleur avocat en immigration à [ville] pour réponse à un RFE de visa H-1B", "Demandez a ChatGPT : « Mon visa de travail a été refusé et j'ai peu de temps pour répondre. Quelles sont mes options et quel genre d'avocat en immigration devrais-je consulter? »"], "whatWeDo": ["Publier des guides en langage clair sur les dossiers que vous voulez réellement (cartes vertes familiales, visas d'emploi, asile, naturalisation, défense contre l'expulsion) pour que les bons clients vous trouvent au lieu d'une usine à références.", "Rédiger comme les vrais clients cherchent et interrogent l'IA, par situation et par inquiétude (« puis-je voyager pendant que mon I-485 est en attente », « une condamnation pour conduite avec facultés affaiblies nuira-t-elle à ma naturalisation », « combien de temps prend le traitement consulaire en ce moment »), et non par noms de lois arides.", "Garder votre cabinet à jour avec des publications opportunes dès que les politiques, les délais de traitement ou les frais de dépôt changent, ce qui signale à Google et à l'IA que le cabinet est actif et fait autorité.", "Bâtir les signaux locaux et thématiques qui orientent les chercheurs vers votre fiche d'établissement Google et la prise de consultation, afin que la visibilité ait un véritable chemin pour se transformer en consultations concrètes."], "headline": "Devenez le cabinet d'immigration que Google et l'IA recommandent", "subhead": "Nous rédigeons et publions un blogue continu, fidèle à votre marque, pour que votre cabinet apparaisse quand quelqu'un cherche « avocat en immigration près de chez moi » et quand il demande à ChatGPT comment faire venir son conjoint, répondre à un RFE ou contester un refus. Conçu pour vous aider à être trouvé sur Google, sur Maps et à l'intérieur des réponses des IA.", "proof": "Dans un cas à titre indicatif, un cabinet d'immigration est passé de 287 à 1 613 visiteurs organiques par mois sur plusieurs mois de publication constante, en parallèle d'une hausse notable des formulaires de consultation remplis. À titre indicatif seulement; les résultats individuels varient.", "faq": [{"q": "Le contenu sera-t-il exact? Les règles d'immigration changent tout le temps.", "a": "Tout est rédigé dans un langage clair et à jour, présenté comme de l'information générale et non comme un avis juridique, votre cabinet étant positionné comme l'endroit pour obtenir des conseils propres à chaque dossier. Quand les politiques, les frais ou les délais de traitement changent, nous publions des mises à jour pour que votre site reflète le paysage actuel plutôt que les règles de l'an dernier. Vous pouvez tout réviser avant la mise en ligne."}, {"q": "Concrètement, comment cela aide-t-il un assistant IA à diriger les gens vers mon cabinet?", "a": "Quand votre blogue répond clairement aux vraies questions que les gens posent (sur les visas, les refus, les échéanciers, l'admissibilité), il devient le genre de source que les outils d'IA ont tendance à utiliser et à citer. Nous structurons le contenu pour que les assistants puissent trouver votre cabinet et acheminer les gens vers votre prise de rendez-vous, tout en gardant chaque affirmation honnête et sans garantie. Nous ne pouvons pas promettre qu'un assistant vous nommera, mais c'est ainsi que vous devenez une option crédible et citable."}, {"q": "Nous servons des clients dans plusieurs États et langues. Pouvez-vous gérer cela?", "a": "Oui. Nous adaptons le contenu aux juridictions et aux communautés de clients que vous servez, en mettant l'accent sur les types de dossiers et les emplacements que vous voulez davantage. Nous ne promettons aucun classement ni aucune issue de dossier précise. L'objectif est une visibilité stable et durable pour que davantage des bonnes personnes trouvent et contactent votre cabinet."}]}}, {"id": "dermatology", "label": "Dermatology", "headline": "Be the Dermatology Clinic Google and AI Recommend", "subhead": "We write and publish an ongoing, on-brand blog for your practice, built to help you show up in Google Search, Google Maps, and the AI answers patients now trust. So more of the right people find you when they go looking for a dermatologist.", "painPoints": ["Your schedule fills with low-margin acne and rash visits, while the cosmetic patients searching 'Botox near me' or 'best dermatologist for melasma' land on a med-spa or a corporate group instead of your practice.", "You have one of the strongest clinical reputations in town, but online you are buried under Healthgrades, Zocdoc, and big hospital systems that out-publish you on every condition and treatment page.", "Patients now ask ChatGPT or Google AI Overviews 'is this mole something to worry about' or 'who treats psoriasis near me', and you have no way of knowing whether your clinic is ever the answer they get."], "exampleSearches": ["dermatologist near me that takes my insurance for a suspicious mole", "best place for Botox and skin tightening in [city] with good reviews", "Ask ChatGPT: I have red scaly patches on my elbows that won't go away, what could it be and what kind of dermatologist should I see in [city]?"], "whatWeDo": ["Publish patient-question blog posts on the conditions and treatments you want more of, from eczema, acne, and skin cancer screenings to Mohs surgery, lasers, and injectables, written in your clinic's voice and reviewed by you before anything goes live.", "Structure every article so Google can connect it to your Google Business Profile and Maps listing, building topical authority around your city and your specialties.", "Format content the way AI assistants pull answers, with clear question-and-answer sections and local context, so your clinic is positioned to be named when patients ask ChatGPT, Gemini, Perplexity, or Google AI Overviews.", "Guide readers toward your booking link and Google Business Profile with clear next steps, so a 'should I get this checked' search has a natural path to a scheduled appointment."], "proof": "\"One dermatology practice we model this approach on grew from 312 to 1,847 monthly organic blog visitors over several months, with cosmetic consult requests climbing alongside. Illustrative only, and individual results are not guaranteed.\"", "faq": [{"q": "Will the content be medically accurate and compliant for a dermatology practice?", "a": "Yes. We write in plain, patient-friendly language and keep claims careful and educational, never promising outcomes or giving individual medical advice. Every post is sent to you for review and approval before it publishes, so a clinician always has the final say."}, {"q": "We mostly want more cosmetic and self-pay patients. Can you focus there?", "a": "Absolutely. We build your content plan around the mix you want, whether that leans toward injectables, lasers, body contouring, and skin rejuvenation, or medical dermatology like skin cancer screenings and chronic conditions. You tell us which visits are most valuable and we weight the calendar toward them."}, {"q": "How is this different from the SEO agency or marketing person we already use?", "a": "Most of them still optimize only for classic Google rankings. We do that, and we also structure your content for how patients now search through AI assistants like ChatGPT and Google AI Overviews. It is month to month with a 60-day money-back guarantee, so you can see whether it earns its place before committing further."}], "complianceNote": "Educational content only, not medical advice. Results vary by practice and market, and individual results are not guaranteed. All posts are reviewed and approved by your clinic before publishing. Month to month, cancel anytime, 60-day money-back guarantee.", "icon": "🧴", "fr": {"label": "Dermatologie", "complianceNote": "Contenu éducatif seulement, ne constitue pas un avis médical. Les résultats varient selon la clinique et le marché, et les résultats individuels ne sont pas garantis. Tous les articles sont révisés et approuvés par votre clinique avant leur publication. De mois en mois, annulation en tout temps, garantie de remboursement de 60 jours.", "painPoints": ["Votre horaire se remplit de consultations à faible marge pour l'acné et les éruptions cutanées, pendant que les patients esthétiques qui cherchent « Botox près de chez moi » ou « meilleur dermatologue pour le mélasma » aboutissent dans un med-spa ou une chaîne corporative au lieu de votre clinique.", "Vous avez l'une des meilleures réputations cliniques en ville, mais en ligne, vous êtes enseveli sous Healthgrades, Zocdoc et les grands réseaux hospitaliers qui publient plus que vous sur chaque page de condition et de traitement.", "Les patients demandent maintenant à ChatGPT ou aux aperçus IA de Google « est-ce que ce grain de beauté est inquiétant » ou « qui traite le psoriasis près de chez moi », et vous n'avez aucun moyen de savoir si votre clinique fait partie de la réponse qu'ils obtiennent."], "exampleSearches": ["dermatologue près de chez moi qui accepte mon assurance pour un grain de beauté suspect", "meilleur endroit pour le botox et le raffermissement de la peau à [ville] avec de bons avis", "Demandez a ChatGPT : j'ai des plaques rouges et squameuses sur les coudes qui ne partent pas, qu'est-ce que ça pourrait être et quel type de dermatologue devrais-je consulter à [ville] ?"], "whatWeDo": ["Nous publions des articles de blogue répondant aux questions des patients sur les conditions et les traitements que vous voulez attirer davantage, de l'eczéma, l'acné et le dépistage du cancer de la peau jusqu'à la chirurgie de Mohs, les lasers et les injectables, rédigés dans la voix de votre clinique et révisés par vous avant toute mise en ligne.", "Nous structurons chaque article pour que Google puisse le relier à votre fiche Google Business Profile et à votre inscription sur Maps, bâtissant une autorité thématique autour de votre ville et de vos spécialités.", "Nous formatons le contenu de la façon dont les assistants IA puisent leurs réponses, avec des sections claires en questions et réponses et un contexte local, afin que votre clinique soit bien positionnée pour être nommée quand les patients interrogent ChatGPT, Gemini, Perplexity ou les aperçus IA de Google.", "Nous guidons les lecteurs vers votre lien de réservation et votre fiche Google Business Profile avec des prochaines étapes claires, pour qu'une recherche du type « devrais-je faire vérifier ça » mène naturellement à un rendez-vous planifié."], "headline": "Soyez la clinique de dermatologie que Google et l'IA recommandent", "subhead": "Nous rédigeons et publions un blogue continu et à votre image pour votre clinique, conçu pour vous aider à apparaître dans la recherche Google, dans Google Maps et dans les réponses IA auxquelles les patients se fient désormais. Ainsi, plus de bonnes personnes vous trouvent quand elles cherchent un dermatologue.", "proof": "« Une clinique de dermatologie sur laquelle nous calquons cette approche est passée de 312 à 1 847 visiteurs organiques par mois sur son blogue en quelques mois, avec une hausse parallèle des demandes de consultation esthétique. À titre indicatif seulement, et les résultats individuels ne sont pas garantis. »", "faq": [{"q": "Le contenu sera-t-il médicalement exact et conforme pour une clinique de dermatologie ?", "a": "Oui. Nous écrivons dans un langage simple et accessible aux patients, et nous gardons les affirmations prudentes et éducatives, sans jamais promettre de résultats ni donner d'avis médical individuel. Chaque article vous est envoyé pour révision et approbation avant sa publication, alors un clinicien a toujours le dernier mot."}, {"q": "Nous voulons surtout plus de patients esthétiques et au privé. Pouvez-vous mettre l'accent là-dessus ?", "a": "Absolument. Nous bâtissons votre plan de contenu autour du mélange que vous souhaitez, qu'il penche vers les injectables, les lasers, le remodelage corporel et le rajeunissement de la peau, ou vers la dermatologie médicale comme le dépistage du cancer de la peau et les conditions chroniques. Vous nous dites quelles consultations ont le plus de valeur et nous ajustons le calendrier en leur faveur."}, {"q": "En quoi est-ce différent de l'agence SEO ou de la personne au marketing que nous utilisons déjà ?", "a": "La plupart d'entre elles optimisent encore uniquement pour le classement Google classique. Nous faisons cela, et nous structurons aussi votre contenu pour la façon dont les patients cherchent maintenant à travers les assistants IA comme ChatGPT et les aperçus IA de Google. C'est de mois en mois avec une garantie de remboursement de 60 jours, alors vous pouvez voir si ça fait ses preuves avant de vous engager davantage."}]}}, {"id": "mens-health-trt", "label": "Men's health & TRT", "complianceNote": "Educational content only, not medical advice. TRT and hormone therapy require evaluation and lab work by a licensed provider. Individual results vary and are not guaranteed. We help your clinic get found by the right people. We do not make treatment claims on your behalf.", "exampleSearches": ["testosterone clinic near me accepting new patients", "always tired low sex drive belly fat at 42 is it low testosterone", "Ask ChatGPT: I'm a 41-year-old guy, exhausted all the time, low sex drive, gaining weight around the middle. Should I get my testosterone checked, and where would I go near [city] for TRT?"], "painPoints": ["National telehealth TRT brands and compounding-pharmacy ads outspend you at every turn, so your local clinic with real providers and in-person labs barely shows up, even though men in your city would rather see someone face to face.", "Men research low T privately for months before they ever pick up the phone. If your site does not answer their symptom questions, they get educated on a competitor's blog and book there, and you never even knew they were looking.", "The moment an ad mentions testosterone, hormones, or ED, the account gets throttled or disapproved, so paid traffic is fragile and expensive and you have no durable channel that keeps producing new-patient consults on its own."], "whatWeDo": ["We publish the symptom-driven articles men actually search, fatigue, low libido, brain fog, weight gain, poor sleep, and what TRT, peptides, and a full hormone lab panel really involve, written to fit medical advertising rules and your clinic's scope.", "We optimize your Google Business Profile and local pages so you surface for searches like 'testosterone clinic near me' and show up on Maps right when a man is ready to book a consult.", "We structure every post so ChatGPT, Gemini, Perplexity, and Google AI Overviews can cite your clinic when men ask where to get evaluated for low T in your area.", "We route readers from each article to your consult booking, lab order, or new-patient intake, and report which symptoms and topics bring in qualified inquiries so we double down on what works."], "proof": "In one illustrative case, a men's health clinic saw its symptom and TRT explainer pages reach 1,213 monthly visitors within roughly four months, with 187 of them clicking through to the consult booking page. Illustrative only, individual results vary.", "faq": [{"q": "Will the content stay compliant with medical advertising rules?", "a": "Yes. We write educational, scope-appropriate content with no guaranteed outcomes and no off-label treatment claims. We frame TRT and hormone therapy as something a licensed provider evaluates with proper lab work, and you review and approve every piece before it publishes."}, {"q": "How does this get men into my clinic instead of a national telehealth brand?", "a": "We target the local and symptom searches men use when they specifically want a real provider near them, and we optimize your Google Business Profile so you appear on Maps. National brands compete on ad spend. We build a content and local presence they cannot replicate in your city, then route readers straight to your booking."}, {"q": "What does AI visibility actually mean for a TRT clinic?", "a": "More men now ask ChatGPT, Gemini, and Perplexity things like where to get evaluated for low T or whether their symptoms warrant testing. We structure your content so those assistants can cite your clinic as a credible local option, which puts you in front of men at the moment they are deciding to act."}], "headline": "Be the TRT Clinic Google AND AI Send Men To", "subhead": "Most men quietly Google their symptoms or ask ChatGPT long before they ever book. We publish an ongoing, on-brand blog that helps your clinic show up in Search, on Maps, and inside AI answers, then points those men straight to your booking page.", "icon": "💪", "fr": {"label": "Santé masculine et hormonothérapie (TRT)", "complianceNote": "Contenu éducatif seulement, ne constitue pas un avis médical. La TRT et l'hormonothérapie nécessitent une évaluation et des analyses de laboratoire par un professionnel autorisé. Les résultats varient d'une personne à l'autre et ne sont pas garantis. Nous aidons votre clinique à être trouvée par les bonnes personnes. Nous ne formulons aucune promesse de traitement en votre nom.", "painPoints": ["Les marques nationales de télémédecine en TRT et les pubs de pharmacies de préparation magistrale investissent plus que vous à chaque étape; résultat, votre clinique locale avec de vrais professionnels et des analyses faites sur place apparaît à peine, même si les hommes de votre ville préféreraient consulter quelqu'un en personne.", "Les hommes se renseignent sur la baisse de testostérone en privé pendant des mois avant de décrocher le téléphone. Si votre site ne répond pas à leurs questions sur les symptômes, ils s'informent sur le blogue d'un concurrent et prennent rendez-vous chez lui, sans que vous sachiez qu'ils vous cherchaient.", "Dès qu'une pub mentionne testostérone, hormones ou dysfonction érectile, le compte est ralenti ou refusé; le trafic payant est donc fragile et coûteux, et vous n'avez aucun canal durable qui génère de lui-même de nouvelles consultations."], "exampleSearches": ["clinique de testostérone près de chez moi acceptant de nouveaux patients", "toujours fatigué libido basse bedaine à 42 ans est-ce une baisse de testostérone", "Demandez à ChatGPT : j'ai 41 ans, épuisé tout le temps, libido en baisse, je prends du poids autour de la taille. Devrais-je faire vérifier ma testostérone, et où aller près de [ville] pour de la TRT?"], "whatWeDo": ["Nous publions les articles axés sur les symptômes que les hommes recherchent vraiment, fatigue, baisse de libido, brouillard mental, prise de poids, mauvais sommeil, et ce qu'impliquent réellement la TRT, les peptides et un bilan hormonal complet, rédigés pour respecter les règles de publicité médicale et le champ de pratique de votre clinique.", "Nous optimisons votre fiche Google Business Profile et vos pages locales pour que vous ressortiez sur des recherches comme « clinique de testostérone près de chez moi » et que vous apparaissiez sur Maps au moment précis où un homme est prêt à réserver une consultation.", "Nous structurons chaque article pour que ChatGPT, Gemini, Perplexity et les aperçus IA de Google puissent citer votre clinique quand les hommes demandent où se faire évaluer pour une baisse de testostérone dans votre région.", "Nous dirigeons les lecteurs de chaque article vers votre prise de rendez-vous, votre demande d'analyses ou votre accueil de nouveaux patients, et nous rapportons quels symptômes et sujets génèrent des demandes qualifiées afin de miser davantage sur ce qui fonctionne."], "headline": "Soyez la clinique de TRT vers qui Google ET l'IA envoient les hommes", "subhead": "La plupart des hommes cherchent discrètement leurs symptômes sur Google ou demandent à ChatGPT bien avant de réserver. Nous publions un blogue continu et fidèle à votre image qui aide votre clinique à apparaître dans la recherche, sur Maps et dans les réponses de l'IA, puis dirige ces hommes droit vers votre page de réservation.", "proof": "Dans un cas présenté à titre indicatif, une clinique de santé masculine a vu ses pages explicatives sur les symptômes et la TRT atteindre 1 213 visiteurs par mois en environ quatre mois, dont 187 ont cliqué vers la page de réservation de consultation. À titre indicatif seulement, les résultats varient d'une personne à l'autre.", "faq": [{"q": "Le contenu va-t-il rester conforme aux règles de publicité médicale?", "a": "Oui. Nous rédigeons du contenu éducatif, adapté à votre champ de pratique, sans résultat garanti ni promesse de traitement hors indication. Nous présentons la TRT et l'hormonothérapie comme quelque chose qu'un professionnel autorisé évalue avec les analyses de laboratoire appropriées, et vous révisez et approuvez chaque article avant sa publication."}, {"q": "Comment cela amène-t-il les hommes dans ma clinique plutôt que vers une marque nationale de télémédecine?", "a": "Nous ciblons les recherches locales et axées sur les symptômes que les hommes utilisent quand ils veulent précisément un vrai professionnel près de chez eux, et nous optimisons votre fiche Google Business Profile pour que vous apparaissiez sur Maps. Les marques nationales se battent sur les budgets publicitaires. Nous bâtissons une présence de contenu et locale qu'elles ne peuvent pas reproduire dans votre ville, puis nous dirigeons les lecteurs droit vers votre réservation."}, {"q": "Qu'est-ce que la visibilité dans l'IA signifie concrètement pour une clinique de TRT?", "a": "De plus en plus d'hommes demandent maintenant à ChatGPT, Gemini et Perplexity des choses comme où se faire évaluer pour une baisse de testostérone ou si leurs symptômes justifient un test. Nous structurons votre contenu pour que ces assistants puissent citer votre clinique comme une option locale crédible, ce qui vous place devant les hommes au moment où ils décident d'agir."}]}}, {"id": "real-estate", "label": "Real estate teams", "headline": "Be the Real Estate Team Google and AI Point Buyers and Sellers Toward", "subhead": "We write and publish an ongoing, on-brand blog tied to your farm area so you show up when locals search Google and Maps, and so ChatGPT, Gemini, and AI Overviews name your team when someone asks who to work with. Then we route that attention to your booking link and Google Business Profile.", "painPoints": ["Zillow, Redfin, and Realtor.com outrank you for every search in your own farm area, so the leads you should own get sold back to you as referral-fee 'opportunities.'", "Your sphere and past-client referrals carry you until they slow down, and you have no system that brings in new buyers and sellers who have never heard your name.", "You know you should be posting neighborhood content, but between showings, listing prep, and closings there is no time to write, and the few posts you tried sounded generic and never ranked."], "exampleSearches": ["best real estate agent in [neighborhood] for first time buyers", "what are homes selling for in [suburb] right now", "Ask ChatGPT: We're relocating to [city] for a job and want to buy in a good school district under $675k. Which local real estate agents or teams should we reach out to, and why?"], "whatWeDo": ["Publish hyper-local content built around how your clients actually search: neighborhood guides, school-district breakdowns, 'cost of living in [area]' posts, and 'is now a good time to sell in [zip]' market updates that pull buyers and sellers in your farm.", "Structure every article so AI assistants can cite you, with clear answers to the relocation, first-time-buyer, and 'should I sell now' questions people type into ChatGPT and Gemini, plus your team's specialty, areas served, and how to reach you.", "Build topical authority around your lane, whether that's luxury, relocation, downsizing, or investment property, so you stop fighting the portals on generic terms and start owning the searches you can realistically win.", "Funnel readers straight to your Google Business Profile, home-valuation tool, and booking link, and keep a steady publishing cadence so your presence compounds month after month instead of going stale between listings."], "proof": "In one illustrative example, a relocation-focused team that had been surfacing in only a handful of local searches a month was appearing across roughly 1,247 monthly searches and AI answers within two quarters. Illustrative only. Individual results vary.", "faq": [{"q": "Can't I just keep relying on referrals and my sphere?", "a": "Keep them. They convert best. The problem is they are unpredictable and they dry up in a slow market. This adds a second channel, so when a buyer or seller who has never met you searches '[your area] real estate agent' or asks an AI who to call, your team is the answer. It is built to back up your referrals, not replace them."}, {"q": "Will this really get my team mentioned by ChatGPT and Gemini?", "a": "We write and structure content the way AI assistants pull from, with clear, citable answers to the questions buyers and sellers actually ask about your market, plus your areas served and specialty. We can't promise any assistant names you on a given day, but this is exactly the kind of local, authoritative content designed to make your team show up when it counts."}, {"q": "I'm slammed with showings and closings. How much work is this for me?", "a": "Almost none. After a short onboarding where we learn your market, your niche, and your voice, we research, write, and publish everything on your blog on an ongoing schedule. Review each post if you want to, or just watch it go live. It's month to month, cancel anytime, with a 60-day money-back guarantee."}], "complianceNote": "Month to month. Cancel anytime. 60-day money-back guarantee. Results vary and are not guaranteed.", "icon": "🏡", "fr": {"label": "Équipes immobilières", "complianceNote": "De mois en mois. Annulez en tout temps. Garantie de remboursement de 60 jours. Les résultats varient et ne sont pas garantis.", "painPoints": ["Centris, Realtor.ca et les grands portails vous devancent pour chaque recherche dans votre propre secteur, si bien que les clients potentiels qui devraient être les vôtres vous sont revendus sous forme d'« occasions » à commission de référence.", "Votre réseau et vos références d'anciens clients vous font vivre tant qu'ils roulent, mais vous n'avez aucun système pour attirer de nouveaux acheteurs et vendeurs qui n'ont jamais entendu parler de vous.", "Vous savez que vous devriez publier du contenu sur vos quartiers, mais entre les visites, la préparation des inscriptions et les clôtures, vous n'avez pas le temps d'écrire, et les quelques publications que vous avez tentées sonnaient génériques et ne se sont jamais classées."], "exampleSearches": ["meilleur courtier immobilier dans [quartier] pour premiers acheteurs", "à combien se vendent les maisons dans [banlieue] en ce moment", "Demandez a ChatGPT : Nous déménageons à [ville] pour un emploi et voulons acheter dans un bon secteur scolaire sous les 675 000 $. Quels courtiers ou équipes immobilières du coin devrions-nous contacter, et pourquoi?"], "whatWeDo": ["Nous publions du contenu hyperlocal bâti autour de la façon dont vos clients cherchent vraiment : guides de quartiers, portraits des secteurs scolaires, articles sur le « coût de la vie à [secteur] » et mises à jour du marché du type « est-ce le bon moment pour vendre dans [code postal] » qui attirent acheteurs et vendeurs dans votre territoire.", "Nous structurons chaque article pour que les assistants IA puissent vous citer, avec des réponses claires aux questions de déménagement, de premier achat et de « devrais-je vendre maintenant » que les gens tapent dans ChatGPT et Gemini, en plus de la spécialité de votre équipe, des secteurs desservis et de la façon de vous joindre.", "Nous bâtissons votre autorité thématique dans votre créneau, que ce soit le luxe, le déménagement, la réduction de taille ou l'immobilier d'investissement, pour que vous cessiez de vous battre contre les portails sur les termes génériques et que vous commenciez à dominer les recherches que vous pouvez réalistement gagner.", "Nous dirigeons les lecteurs directement vers votre fiche Google Business Profile, votre outil d'évaluation de propriété et votre lien de prise de rendez-vous, et nous maintenons une cadence de publication régulière pour que votre présence se renforce mois après mois au lieu de s'essouffler entre les inscriptions."], "headline": "Soyez l'équipe immobilière que Google et l'IA recommandent aux acheteurs et aux vendeurs", "subhead": "Nous rédigeons et publions un blogue continu, à l'image de votre marque et rattaché à votre secteur, pour que vous apparaissiez quand les gens du coin cherchent sur Google et Maps, et pour que ChatGPT, Gemini et les aperçus IA nomment votre équipe quand quelqu'un demande avec qui faire affaire. Ensuite, nous acheminons cette attention vers votre lien de prise de rendez-vous et votre fiche Google Business Profile.", "proof": "À titre indicatif, une équipe spécialisée dans le déménagement qui n'apparaissait que dans une poignée de recherches locales par mois s'est retrouvée présente dans environ 1 247 recherches mensuelles et réponses IA en l'espace de deux trimestres. À titre indicatif seulement. Les résultats individuels varient.", "faq": [{"q": "Ne puis-je pas simplement continuer à compter sur mes références et mon réseau?", "a": "Gardez-les. Ce sont eux qui convertissent le mieux. Le problème, c'est qu'ils sont imprévisibles et qu'ils se tarissent quand le marché ralentit. Ceci ajoute un deuxième canal : ainsi, quand un acheteur ou un vendeur qui ne vous connaît pas cherche « courtier immobilier [votre secteur] » ou demande à une IA qui appeler, c'est votre équipe qui ressort. C'est conçu pour appuyer vos références, pas pour les remplacer."}, {"q": "Est-ce que ça va vraiment faire mentionner mon équipe par ChatGPT et Gemini?", "a": "Nous rédigeons et structurons le contenu de la façon dont les assistants IA puisent leurs réponses, avec des réponses claires et citables aux questions que les acheteurs et les vendeurs se posent réellement sur votre marché, en plus de vos secteurs desservis et de votre spécialité. Nous ne pouvons pas promettre qu'un assistant vous nommera tel jour précis, mais c'est exactement le type de contenu local et crédible conçu pour faire ressortir votre équipe au moment qui compte."}, {"q": "Je suis débordé par les visites et les clôtures. Combien de travail ça représente pour moi?", "a": "Presque rien. Après une courte intégration où nous apprenons à connaître votre marché, votre créneau et votre voix, nous faisons la recherche, la rédaction et la publication de tout sur votre blogue selon un calendrier continu. Révisez chaque article si vous le souhaitez, ou regardez-le simplement être mis en ligne. C'est de mois en mois, annulable en tout temps, avec une garantie de remboursement de 60 jours."}]}}, {"id": "mortgage-brokers", "label": "Mortgage brokers", "headline": "Be the mortgage broker Google and AI recommend when buyers are ready to apply", "subhead": "Vanta writes and publishes an ongoing, on-brand blog that helps you get found for local rate and pre-approval searches, gets you named inside ChatGPT and Google AI answers, and points ready-to-move borrowers to your booking link.", "painPoints": ["The rate aggregators and big-bank brand pages own page one, so your name rarely shows up when someone in your area searches 'mortgage broker near me' or 'how to get pre-approved'.", "Your pipeline leans on a few realtor partners and past clients, so when rates jump or one agent goes quiet, lead flow stalls and you have nothing else feeding you.", "Borrowers are now asking ChatGPT 'should I use a broker or my bank' and 'how much can I get pre-approved for', and you have no idea how to be the broker those answers actually name."], "exampleSearches": ["mortgage broker near me first time home buyer", "how much mortgage can I qualify for self employed", "Ask ChatGPT: I'm self-employed and want to buy a house next year, how do I get a mortgage, and should I use a broker or my bank?"], "whatWeDo": ["We publish borrower-intent articles that match how people actually search, from 'fixed vs variable in today's market' to 'how a bank-statement loan works for self-employed buyers', so you get found while they're shopping.", "We structure every post so AI assistants can quote it and name you, with clear local context, FAQ formatting, and the trust signals ChatGPT and Google AI Overviews look for.", "We keep your Google Business Profile and blog working together, funneling readers toward your application or discovery-call link instead of a rate-comparison site.", "We refresh content as rates, programs, and loan limits shift, so your site never reads like it's quoting last year's market and you stay the local name that keeps coming up."], "proof": "In one illustrative case, a broker's site grew from 312 to 2,847 organic visits over a single spring buying season, with first-time-buyer and pre-approval guides driving the most discovery-call bookings. Illustrative only; your results will vary.", "faq": [{"q": "Will this actually get me leads, or just traffic?", "a": "We target the searches and AI questions that come from people preparing to buy or refinance, not idle browsers. Every article is built to move the reader toward your booking or application link. We can't promise a specific number of leads, but the intent we go after is the kind that tends to convert."}, {"q": "Do I have to write anything or track every rate change?", "a": "No. You stay focused on closing files. We handle the topic research, the writing in your voice, the publishing, and the updates when rates or loan programs move. You approve the direction and we run with it."}, {"q": "I'm in a regulated industry. Will the content stay compliant?", "a": "Yes. We write in plain, accurate terms, avoid guaranteeing rates or approvals, and keep claims defensible. You get final review on everything before it publishes, so it fits your license and your regulator's expectations."}], "complianceNote": "Educational content only, not financial or lending advice. Rates, terms, and approval are subject to qualification and lender criteria. Results vary and are not guaranteed. Month to month, cancel anytime, 60-day money-back guarantee.", "icon": "🏦", "fr": {"label": "Courtiers hypothécaires", "complianceNote": "Contenu éducatif seulement, ne constitue pas un conseil financier ni un conseil en matière de prêt. Les taux, conditions et l'approbation sont assujettis à la qualification et aux critères des prêteurs. Les résultats varient et ne sont pas garantis. De mois en mois, annulable en tout temps, garantie de remboursement de 60 jours.", "painPoints": ["Les comparateurs de taux et les pages de marque des grandes banques accaparent la première page, alors votre nom apparaît rarement quand une personne de votre région cherche « courtier hypothécaire près de moi » ou « comment obtenir une préapprobation ».", "Votre carnet de clients repose sur quelques partenaires courtiers immobiliers et d'anciens clients; quand les taux grimpent ou qu'un agent devient silencieux, le flux de prospects ralentit et rien d'autre ne vient l'alimenter.", "Les emprunteurs demandent maintenant à ChatGPT « devrais-je passer par un courtier ou par ma banque » et « quel montant puis-je obtenir en préapprobation », et vous ne savez pas comment devenir le courtier que ces réponses nomment réellement."], "exampleSearches": ["courtier hypothécaire près de moi premier acheteur", "quel montant d'hypothèque puis-je obtenir travailleur autonome", "Demandez a ChatGPT : je suis travailleur autonome et je veux acheter une maison l'an prochain, comment obtenir une hypothèque, et devrais-je passer par un courtier ou par ma banque ?"], "whatWeDo": ["Nous publions des articles axés sur l'intention des emprunteurs qui correspondent à la façon dont les gens cherchent vraiment, de « taux fixe ou variable dans le marché d'aujourd'hui » à « comment fonctionne un prêt sur relevés bancaires pour un acheteur travailleur autonome », pour qu'on vous trouve pendant qu'ils magasinent.", "Nous structurons chaque article pour que les assistants IA puissent le citer et vous nommer, avec un contexte local clair, une mise en forme en FAQ et les signaux de confiance que recherchent ChatGPT et les aperçus IA de Google.", "Nous faisons travailler ensemble votre fiche Google Business et votre blogue, dirigeant les lecteurs vers votre formulaire de demande ou votre lien d'appel-découverte plutôt que vers un site de comparaison de taux.", "Nous rafraîchissons le contenu au fil des changements de taux, de programmes et de limites de prêt, pour que votre site ne donne jamais l'impression de citer le marché de l'an dernier et que vous restiez le nom local qui revient sans cesse."], "headline": "Devenez le courtier hypothécaire que Google et l'IA recommandent quand les acheteurs sont prêts à présenter une demande", "subhead": "Vanta rédige et publie un blogue continu et fidèle à votre marque qui vous aide à être trouvé lors des recherches locales sur les taux et les préapprobations, vous fait nommer dans les réponses de ChatGPT et de l'IA de Google, et oriente les emprunteurs prêts à agir vers votre lien de réservation.", "proof": "Dans un cas à titre indicatif, le site d'un courtier est passé de 312 à 2 847 visites organiques au cours d'une seule saison d'achat printanière, les guides pour premiers acheteurs et sur la préapprobation générant le plus de réservations d'appels-découverte. À titre indicatif seulement; vos résultats varieront.", "faq": [{"q": "Est-ce que ça va vraiment m'apporter des prospects, ou juste du trafic ?", "a": "Nous ciblons les recherches et les questions posées à l'IA qui proviennent de gens en train de se préparer à acheter ou à refinancer, pas de simples curieux. Chaque article est conçu pour amener le lecteur vers votre lien de réservation ou de demande. Nous ne pouvons pas promettre un nombre précis de prospects, mais l'intention que nous visons est du type qui tend à convertir."}, {"q": "Dois-je rédiger quoi que ce soit ou suivre chaque changement de taux ?", "a": "Non. Vous restez concentré sur la conclusion de vos dossiers. Nous nous occupons de la recherche de sujets, de la rédaction dans votre voix, de la publication et des mises à jour lorsque les taux ou les programmes de prêt bougent. Vous approuvez l'orientation et nous prenons le relais."}, {"q": "Je suis dans une industrie réglementée. Le contenu restera-t-il conforme ?", "a": "Oui. Nous écrivons en termes clairs et exacts, évitons de garantir des taux ou des approbations, et gardons les affirmations défendables. Vous obtenez une révision finale de tout avant la publication, pour que ça respecte votre permis et les attentes de votre organisme de réglementation."}]}}, {"id": "roofing", "label": "Roofing & exteriors", "headline": "Be the Roofer Google and AI Send Customers To", "subhead": "We write and publish an ongoing, on-brand blog built to help your roofing and exterior business show up in Google Search, Google Maps, and inside AI answers like ChatGPT and Gemini. So when a homeowner spots a leak or storm damage and starts looking, you're the name they find.", "painPoints": ["You only get found when a storm rolls through, then you go quiet again until the next one. Between weather events the phone slows down and you're back to chasing referrals and knocking on doors.", "You're paying real money for shared and 'exclusive' leads from Angi, HomeAdvisor, and lead resellers, and half are tire-kickers or got sold to three other crews the same afternoon.", "National roofing brands and private-equity-backed outfits sit above you on every 'roof replacement near me' search, even though you do cleaner work and actually pick up the phone."], "exampleSearches": ["roof replacement cost near me", "emergency roof leak repair open now", "Ask ChatGPT: who's a reliable roofing contractor near me for a full tear-off, and what should I expect to pay?"], "whatWeDo": ["We publish local, search-ready articles on the exact questions homeowners type before they call, like 'how long does a shingle roof last in our climate,' 'signs you need a new roof, not just a repair,' and 'does insurance cover storm and hail damage.'", "We target the money jobs and your true service area: roof replacement, storm and hail damage, siding, gutters, and flat and metal roofs, across the specific towns and suburbs your crews actually drive to.", "We structure every post so AI assistants can pull from it, so when someone asks ChatGPT or Google AI Overviews for a trustworthy local roofer, your business shows up with your service area and specialties spelled out.", "We point every article at your Google Business Profile and quote-request form, so readers turn into estimate calls instead of just traffic that bounces."], "proof": "In an illustrative scenario, a roofing contractor running this through one storm season might see roughly 1,213 added local blog visits and 38 quote-form starts. Illustrative only, and individual results vary by market and season.", "faq": [{"q": "I'm a roofer, not a writer. How much of my time does this take?", "a": "Almost none. We learn your crew, your service area, the materials you install, and the jobs you actually want, then we write and publish everything for you. You stay on the roof. Most owners spend about fifteen minutes a month on this, if that."}, {"q": "My business is seasonal and storm-driven. Does content actually help?", "a": "That's exactly what it's built for. Storm spikes come and go, but homeowners research roof age, insurance claims, and material choices all year long. Steady, useful content keeps you visible between events, so when the next storm hits you're already the name people recognize and the one AI tools tend to surface."}, {"q": "How is this different from buying leads from Angi or HomeAdvisor?", "a": "Those leads are rented and resold, often to several contractors at once. This builds an asset you own. The articles, your Google presence, and your AI visibility stay yours and keep working month after month, instead of vanishing the moment you stop paying per lead."}], "complianceNote": "Month to month. Cancel anytime, backed by a 60-day money-back guarantee. Visibility outcomes vary by market, competition, and season, and are not guaranteed.", "icon": "🏠", "fr": {"label": "Toiture et revêtements extérieurs", "complianceNote": "De mois en mois. Annulez en tout temps, avec une garantie de remboursement de 60 jours. Les résultats de visibilité varient selon le marché, la concurrence et la saison, et ne sont pas garantis.", "painPoints": ["On vous trouve seulement quand une tempête frappe, puis c'est le silence radio jusqu'à la prochaine. Entre deux épisodes de mauvais temps, le téléphone arrête de sonner et vous repartez à la chasse aux références et au porte-à-porte.", "Vous payez de l'argent bien réel pour des leads partagés et soi-disant exclusifs d'Angi, de HomeAdvisor et de revendeurs de pistes, et la moitié sont des curieux qui ne signeront jamais ou ont été revendus à trois autres équipes le même après-midi.", "Les grandes bannières nationales de toiture et les entreprises financées par le capital-investissement se classent au-dessus de vous à chaque recherche de « remplacement de toiture près de moi », même si votre travail est plus soigné et que vous, vous répondez au téléphone."], "exampleSearches": ["coût remplacement de toiture près de moi", "réparation urgente fuite de toit ouvert maintenant", "Demandez a ChatGPT : quel couvreur fiable près de chez moi pour un arrachage complet de toiture, et à combien dois-je m'attendre comme prix?"], "whatWeDo": ["On publie des articles locaux, optimisés pour la recherche, sur les questions exactes que les propriétaires tapent avant d'appeler, comme « combien de temps dure une toiture en bardeaux dans notre climat », « les signes qu'il vous faut une nouvelle toiture, pas juste une réparation » et « est-ce que l'assurance couvre les dommages de tempête et de grêle ».", "On cible les contrats payants et votre véritable territoire de service : remplacement de toiture, dommages de tempête et de grêle, revêtement extérieur, gouttières et toits plats ou en métal, dans les villes et banlieues précises où vos équipes se déplacent vraiment.", "On structure chaque article pour que les assistants IA puissent y puiser, de sorte que lorsqu'une personne demande à ChatGPT ou aux aperçus IA de Google un couvreur local digne de confiance, votre entreprise ressort avec votre territoire de service et vos spécialités clairement indiqués.", "On dirige chaque article vers votre fiche Google Business et votre formulaire de demande de soumission, pour que les lecteurs deviennent des appels d'estimation au lieu d'un simple trafic qui rebondit."], "headline": "Soyez le couvreur que Google et l'IA recommandent", "subhead": "On rédige et publie un blogue continu, à l'image de votre marque, conçu pour aider votre entreprise de toiture et de revêtement extérieur à ressortir dans la recherche Google, sur Google Maps et dans les réponses IA comme ChatGPT et Gemini. Ainsi, quand un propriétaire remarque une fuite ou des dommages de tempête et se met à chercher, c'est votre nom qu'il trouve.", "proof": "À titre indicatif, un couvreur qui utiliserait ce service pendant une saison de tempêtes pourrait voir environ 1 213 visites locales de blogue supplémentaires et 38 demandes de soumission amorcées. À titre indicatif seulement; les résultats individuels varient selon le marché et la saison.", "faq": [{"q": "Je suis couvreur, pas rédacteur. Combien de temps ça va me demander?", "a": "Presque aucun. On apprend à connaître votre équipe, votre territoire de service, les matériaux que vous posez et les contrats que vous voulez vraiment, puis on rédige et on publie tout pour vous. Vous, vous restez sur les toits. La plupart des propriétaires y consacrent à peu près quinze minutes par mois, quand ce n'est pas moins."}, {"q": "Mon entreprise est saisonnière et dépend des tempêtes. Est-ce que le contenu aide vraiment?", "a": "C'est exactement pour ça que c'est conçu. Les pics liés aux tempêtes vont et viennent, mais les propriétaires se renseignent sur l'âge de leur toit, les réclamations d'assurance et le choix des matériaux toute l'année. Un contenu régulier et utile vous garde visible entre les épisodes, pour qu'à la prochaine tempête vous soyez déjà le nom que les gens reconnaissent et celui que les outils IA ont tendance à mettre de l'avant."}, {"q": "En quoi c'est différent d'acheter des leads sur Angi ou HomeAdvisor?", "a": "Ces leads sont loués et revendus, souvent à plusieurs entrepreneurs en même temps. Ici, on bâtit un actif qui vous appartient. Les articles, votre présence sur Google et votre visibilité dans l'IA restent à vous et continuent de travailler mois après mois, au lieu de disparaître dès que vous arrêtez de payer à la piste."}]}}, {"id": "solar", "label": "Solar installers", "headline": "Be the Solar Installer Homeowners Find on Google and the One AI Recommends", "subhead": "We write and publish an ongoing, on-brand blog that helps your solar company show up when homeowners search \"solar near me\" and when they ask ChatGPT who to trust. Then we point that interest straight to your booking calendar.", "painPoints": ["You're buying $40 to $80 shared leads from EnergySage, Modernize, or Angi that get sold to four other installers at once, so every consult turns into a price war before you've even shaken hands.", "Homeowners spend weeks researching panel brands, financing, payback periods, and net metering rules before they call, and your site says nothing about any of it, so they trust the installer who does.", "When someone asks ChatGPT 'is solar worth it where I live' or 'best solar installer near me,' it surfaces national brands and lead aggregators, not the local crew that actually climbs the roof and does the work."], "exampleSearches": ["solar panel installers near me", "how much do solar panels cost for a 2,000 sq ft house", "Ask ChatGPT: I'm in Phoenix and want to go solar before the tax credit changes. Who are reputable local installers and what should I ask them?"], "whatWeDo": ["Publish local buyer-intent articles like 'Solar Payback Period in [Your City]' and 'Is My Roof Right for Solar?' that match how homeowners actually research before they request a quote.", "Write the financing, net metering, and federal tax credit explainers homeowners are quietly Googling, so you become the installer who answered their questions first.", "Structure every post so AI assistants can read, trust, and name your company when someone asks about going solar in your service area.", "Tie each article to your Google Business Profile and booking link so research traffic turns into on-roof consults, not just page views."], "proof": "Illustrative example: one residential installer's blog brought in 1,827 local organic visits in a quarter and began getting named in AI answers across 14 nearby towns. Illustrative only. Results vary by market, roof, and competition.", "faq": [{"q": "We already pay for leads from EnergySage and Modernize. How is this different?", "a": "Those are rented leads sold to several installers at once, so you compete on price the second you call. This builds an asset you own: a blog that brings homeowners directly to you, already warmed up by your own content, before any aggregator gets to them."}, {"q": "Will this actually cover the tax credit and net metering questions homeowners ask?", "a": "Yes. Those are exactly the topics we write about, tailored to your state and city. When a homeowner Googles or asks AI about incentives in your area, the goal is for your company to be the source that shows up. We keep every claim accurate and never put a specific savings figure in your mouth."}, {"q": "Do I have to write or approve anything?", "a": "No writing on your end. We learn your brand, services, and service area, then write and publish on an ongoing schedule. You can review anytime, and it's month-to-month with a 60-day money-back guarantee."}], "complianceNote": "Month to month. Cancel anytime, backed by a 60-day money-back guarantee. Illustrative examples only. Results vary by market, roof, incentives, and competition. Savings and tax credit eligibility depend on your situation and are not guaranteed.", "icon": "☀️", "fr": {"label": "Installateurs de panneaux solaires", "complianceNote": "Sans engagement, de mois en mois. Annulez en tout temps, avec une garantie de remboursement de 60 jours. Exemples fournis à titre indicatif seulement. Les résultats varient selon le marché, le toit, les incitatifs et la concurrence. Les économies et l'admissibilité aux crédits d'impôt dépendent de votre situation et ne sont pas garanties.", "painPoints": ["Vous payez de 40 $ à 80 $ pour des leads partagés provenant de plateformes comme EnergySage, Modernize ou Angi, des leads revendus en même temps à quatre autres installateurs; chaque rencontre vire en guerre de prix avant même la première poignée de main.", "Les propriétaires passent des semaines à comparer les marques de panneaux, le financement, les délais de rentabilité et les règles de mesurage net avant d'appeler, et votre site ne dit rien sur tout ça; ils font donc confiance à l'installateur qui, lui, répond à leurs questions.", "Quand quelqu'un demande à ChatGPT si le solaire en vaut la peine dans sa région ou quel est le meilleur installateur près de chez lui, l'IA propose des grandes marques nationales et des agrégateurs de leads, pas l'équipe locale qui monte vraiment sur le toit et fait le travail."], "exampleSearches": ["installateurs de panneaux solaires près de chez moi", "combien coûte l'installation de panneaux solaires pour une maison de 2 000 pi2", "Demandez à ChatGPT : je suis à Montréal et je veux passer au solaire avant que le crédit d'impôt change. Quels installateurs locaux sont fiables et que devrais-je leur demander?"], "whatWeDo": ["Nous publions des articles locaux axés sur l'intention d'achat, comme Délai de rentabilité du solaire à [Votre ville] ou Mon toit est-il adapté au solaire?, qui collent à la façon dont les propriétaires font vraiment leurs recherches avant de demander une soumission.", "Nous rédigeons les guides sur le financement, le mesurage net et les crédits d'impôt que les propriétaires cherchent discrètement sur Google, pour que vous deveniez l'installateur qui a répondu à leurs questions en premier.", "Nous structurons chaque article pour que les assistants IA puissent lire, faire confiance et nommer votre entreprise quand quelqu'un s'informe sur le passage au solaire dans votre zone de service.", "Nous relions chaque article à votre fiche Google Business et à votre lien de prise de rendez-vous, afin que le trafic de recherche se transforme en rencontres sur le toit, et non juste en pages vues."], "headline": "Soyez l'installateur solaire que les propriétaires trouvent sur Google et celui que l'IA recommande", "subhead": "Nous rédigeons et publions un blogue continu, fidèle à votre image de marque, qui aide votre entreprise solaire à apparaître quand les propriétaires cherchent \"installateur solaire près de chez moi\" et quand ils demandent à ChatGPT à qui faire confiance. Ensuite, nous dirigeons cet intérêt directement vers votre calendrier de rendez-vous.", "proof": "Exemple à titre indicatif : le blogue d'un installateur résidentiel a généré 1 827 visites organiques locales en un trimestre et a commencé à être nommé dans les réponses d'IA dans 14 villes avoisinantes. À titre indicatif seulement. Les résultats varient selon le marché, le toit et la concurrence.", "faq": [{"q": "On paie déjà pour des leads d'EnergySage et de Modernize. En quoi est-ce différent?", "a": "Ces leads sont loués et vendus à plusieurs installateurs en même temps, alors vous vous battez sur le prix dès le premier appel. Ici, vous bâtissez un actif qui vous appartient : un blogue qui amène les propriétaires directement à vous, déjà réchauffés par votre propre contenu, avant qu'un agrégateur ne les rejoigne."}, {"q": "Est-ce que ça couvre vraiment les questions sur le crédit d'impôt et le mesurage net que les propriétaires posent?", "a": "Oui. Ce sont exactement les sujets que nous abordons, adaptés à votre province et à votre ville. Quand un propriétaire cherche sur Google ou interroge l'IA sur les incitatifs dans votre région, l'objectif est que votre entreprise soit la source qui ressort. Nous gardons chaque affirmation exacte et ne vous faisons jamais avancer un chiffre d'économies précis."}, {"q": "Est-ce que je dois rédiger ou approuver quelque chose?", "a": "Aucune rédaction de votre côté. Nous apprenons à connaître votre marque, vos services et votre zone de service, puis nous rédigeons et publions selon un calendrier continu. Vous pouvez tout réviser en tout temps, et c'est sans engagement, de mois en mois, avec une garantie de remboursement de 60 jours."}]}}, {"id": "custom-builders", "label": "Custom builders & remodelers", "headline": "Be the builder Google and AI recommend when someone's ready to build or remodel", "subhead": "We write and publish an ongoing, on-brand blog that gets your custom build and remodeling work found in Google Search, Google Maps, and inside AI answers from ChatGPT, Gemini, and Perplexity. So the homeowners planning their project find you while they're still deciding.", "painPoints": ["Your portfolio is gorgeous, but it's buried. The contractors ranking above you have a thinner body of work and a pile of blog posts about 'kitchen remodel cost' and 'how long does a custom home take to build,' and that's what shows up when a homeowner starts researching their project.", "Your leads come from referrals and the occasional Houzz or Angi message, so you're paying lead-gen fees, splitting every lead with three other builders, and riding a feast-or-famine pipeline where the phone goes quiet right when you need to fill the next slot in the schedule.", "You know your craft, not SEO, and you have no time to learn it. You're on site walking framing, chasing subs and inspectors, and managing allowances and change orders. Writing two posts a week about ADU rules or a design-build vs. bid-build comparison is never going to happen, so it never does."], "exampleSearches": ["custom home builders near me reviews", "cost to add a second story to a house in [city]", "Ask ChatGPT: I'm renovating a 1970s ranch and want to open up the kitchen to the living room and add a primary suite. Who are reputable design-build remodelers in my area, and what should I expect a project like this to cost and how long it takes?"], "whatWeDo": ["We publish project-intent articles your buyers actually search before they call: 'cost to build a custom home in [your area],' 'addition vs. teardown-and-rebuild,' 'what a whole-home remodel timeline really looks like,' so you show up at the research stage, not just the 'ready to sign' stage.", "We structure content so AI assistants surface your name when a homeowner asks ChatGPT or Gemini for a builder or remodeler in your service area, which is how more of these projects now start.", "We tie every article to your Google Business Profile and a clear next step, so a 'what will this cost' reader becomes a consultation request, and your profile earns more visibility on the local map.", "We match your voice and the work you want more of, whether that's high-end custom homes, kitchen-and-bath, additions and ADUs, or full design-build, so the blog reads like your shop wrote it, not a generic content mill."], "proof": "\"One design-build remodeler ran our blog for about seven months and saw organic visits to their cost and timeline articles climb to roughly 3,847 a month, with 23 of those readers requesting a consultation over that period. Illustrative only, and results vary by market, service area, and project type.\"", "faq": [{"q": "My projects run well into six figures and they're very custom. Can blog content really bring in serious clients?", "a": "That's exactly the buyer who researches the longest. Someone weighing a major build or a whole-home remodel reads for weeks before they ever pick up the phone. When your blog answers their real questions about cost ranges, timelines, permits, allowances, and design choices, you build trust early and you're a name they're far more likely to reach out to. We focus on the high-intent topics that map to your kind of work, not filler traffic."}, {"q": "How is this different from Houzz, Angi, or buying leads?", "a": "Those put you in a list next to your competitors and charge you for shared leads you don't control. This builds an asset you own. The articles keep working and ranking, the traffic comes to your site and your Google profile, and the inquiries are yours alone. No per-lead fees, no bidding against three other builders for the same homeowner."}, {"q": "I'm slammed on job sites. How much work is this for me?", "a": "Almost none. We handle the research, writing, and publishing on a steady schedule. Up front we learn your voice, your service area, and the project types you want more of, then we run with it. You review if you want to, or you just watch the inquiries come in. It's month to month, cancel anytime, with a 60-day money-back guarantee."}], "complianceNote": "Month to month. Cancel anytime. 60-day money-back guarantee. Illustrative examples only; results vary by market, service area, and project type.", "icon": "🏗️", "fr": {"label": "Constructeurs sur mesure et rénovateurs", "complianceNote": "De mois en mois. Annulez en tout temps. Garantie de remboursement de 60 jours. Exemples fournis à titre indicatif seulement; les résultats varient selon le marché, le territoire desservi et le type de projet.", "painPoints": ["Votre portfolio est magnifique, mais il est enterré. Les entrepreneurs qui se classent devant vous ont réalisé moins de projets que vous, mais ils ont une montagne d'articles de blogue sur le coût d'une rénovation de cuisine et le temps que prend la construction d'une maison sur mesure, et c'est exactement ce qui ressort quand un propriétaire commence à se renseigner sur son projet.", "Vos clients viennent du bouche-à-oreille et d'un message occasionnel sur Houzz ou Angi; vous payez donc des frais de génération de prospects, vous partagez chaque piste avec trois autres constructeurs et vous vivez au rythme des hauts et des bas, le téléphone se tait juste au moment où vous devez remplir la prochaine place à l'horaire.", "Vous maîtrisez votre métier, pas le référencement, et vous n'avez aucun temps pour l'apprendre. Vous êtes sur le chantier à inspecter la charpente, à courir après les sous-traitants et les inspecteurs, et à gérer les allocations et les ordres de changement. Rédiger deux articles par semaine sur la réglementation des unités d'habitation accessoires ou une comparaison entre conception-construction et appel d'offres, ça n'arrivera jamais, alors ça n'arrive jamais."], "exampleSearches": ["constructeurs de maisons sur mesure près de chez moi avis", "coût pour ajouter un deuxième étage à une maison à [ville]", "Demandez à ChatGPT : je rénove un bungalow des années 1970 et je veux ouvrir la cuisine sur le salon et ajouter une suite des maîtres. Quels sont les bons rénovateurs en conception-construction dans ma région, et à quel coût et à quel échéancier dois-je m'attendre pour un projet comme celui-là?"], "whatWeDo": ["Nous publions des articles axés sur l'intention de projet que vos clients cherchent vraiment avant d'appeler : coût pour construire une maison sur mesure dans [votre région], agrandissement ou démolition-reconstruction, à quoi ressemble vraiment l'échéancier d'une rénovation complète, pour que vous apparaissiez dès l'étape de la recherche, et pas seulement au moment de signer.", "Nous structurons le contenu pour que les assistants IA nomment votre entreprise quand un propriétaire demande à ChatGPT ou Gemini un constructeur ou un rénovateur dans votre territoire, ce qui est de plus en plus la façon dont ces projets commencent.", "Nous relions chaque article à votre fiche Google Business Profile et à une prochaine étape claire, pour qu'un lecteur qui se demande combien ça coûte devienne une demande de consultation, et que votre fiche gagne en visibilité sur la carte locale.", "Nous adaptons le blogue à votre voix et au type de mandats que vous voulez attirer davantage, qu'il s'agisse de maisons haut de gamme sur mesure, de cuisines et salles de bain, d'agrandissements et d'unités d'habitation accessoires, ou de conception-construction complète, pour que le blogue se lise comme si votre équipe l'avait écrit, et non comme une usine à contenu générique."], "headline": "Soyez le constructeur que Google et l'IA recommandent quand quelqu'un est prêt à bâtir ou à rénover", "subhead": "Nous rédigeons et publions un blogue continu et fidèle à votre marque qui fait découvrir vos projets de construction sur mesure et de rénovation dans la recherche Google, dans Google Maps et au cœur des réponses générées par l'IA de ChatGPT, Gemini et Perplexity. Ainsi, les propriétaires qui planifient leur projet vous trouvent pendant qu'ils sont encore en train de décider.", "proof": "\"Un rénovateur en conception-construction a utilisé notre blogue pendant environ sept mois et a vu les visites organiques vers ses articles sur les coûts et les échéanciers grimper à environ 3 847 par mois, et 23 de ces lecteurs ont demandé une consultation durant cette période. À titre indicatif seulement; les résultats varient selon le marché, le territoire desservi et le type de projet.\"", "faq": [{"q": "Mes projets se chiffrent dans les six chiffres et ils sont très personnalisés. Un blogue peut-il vraiment attirer des clients sérieux?", "a": "C'est exactement le type d'acheteur qui se renseigne le plus longtemps. Quelqu'un qui pèse une construction majeure ou une rénovation complète lit pendant des semaines avant de décrocher le téléphone. Quand votre blogue répond à ses vraies questions sur les fourchettes de prix, les échéanciers, les permis, les allocations et les choix de design, vous bâtissez la confiance tôt et vous devenez un nom qu'il est bien plus susceptible de contacter. Nous nous concentrons sur les sujets à forte intention qui correspondent à votre type de travail, pas sur du trafic de remplissage."}, {"q": "En quoi est-ce différent de Houzz, d'Angi ou de l'achat de prospects?", "a": "Ces plateformes vous placent dans une liste à côté de vos concurrents et vous facturent des prospects partagés que vous ne contrôlez pas. Ici, vous bâtissez un actif qui vous appartient. Les articles continuent de travailler et de se classer, le trafic arrive sur votre site et sur votre fiche Google, et les demandes sont à vous seul. Pas de frais par prospect, pas de surenchère contre trois autres constructeurs pour le même propriétaire."}, {"q": "Je suis débordé sur les chantiers. Combien de travail ça représente pour moi?", "a": "Presque aucun. Nous nous occupons de la recherche, de la rédaction et de la publication selon un calendrier régulier. Au départ, nous apprenons votre voix, votre territoire desservi et les types de projets que vous voulez attirer davantage, puis nous prenons le relais. Vous révisez si vous le souhaitez, ou vous regardez simplement les demandes entrer. C'est de mois en mois, annulable en tout temps, avec une garantie de remboursement de 60 jours."}]}}, {"id": "lasik-vision", "label": "LASIK & vision surgery", "complianceNote": "For educational purposes only and not medical advice. Candidacy for LASIK, PRK, SMILE, or other vision-correction procedures can only be determined by a licensed eye surgeon after a complete exam. Results, recovery, and final vision vary by individual and are not guaranteed.", "headline": "Become the LASIK practice Google AND AI recommend when someone is finally ready to ditch their glasses", "subhead": "We write and publish an ongoing, surgeon-reviewed blog that answers the exact questions vision-correction shoppers type into Google and ask ChatGPT, so more of the right candidates find your practice and book a consult.", "painPoints": ["LASIK is an irreversible, several-thousand-dollar decision people research for months. Prospects read a dozen articles and watch every \"is it safe\" and \"what are the risks\" video before they ever call, and most of that research is happening on competitors' sites, aggregators, and AI answers instead of on yours.", "When someone asks ChatGPT or Google AI Overviews \"LASIK vs PRK vs SMILE for dry eye\" or \"who's a reputable LASIK surgeon near me,\" your practice rarely comes up. National chains and review-aggregator sites get cited, while your surgeon's actual expertise stays invisible at the exact moment a candidate is choosing who to trust with their eyes.", "Your budget gets eaten by LASIK pay-per-click ads, some of the priciest keywords in all of healthcare, and you're paying premium rates for price shoppers and people who turn out not to be candidates, instead of owning content that earns trust and brings in qualified consults long after it's published."], "exampleSearches": ["\"is LASIK worth it at 45\" / \"LASIK vs PRK for dry eyes\" / \"best LASIK surgeon near me reviews\"", "\"how much does LASIK cost in [city] with financing\" / \"can I get LASIK with astigmatism and thin corneas\"", "Ask ChatGPT: \"I'm 38, wear contacts, and have mild dry eye. Should I do LASIK, PRK, or SMILE, and who are the most reputable vision-correction surgeons in my area?\""], "whatWeDo": ["Publish a steady stream of surgeon-reviewed articles on the decisions real LASIK shoppers wrestle with: LASIK vs PRK vs SMILE, candidacy with thin corneas, dry eye, high prescriptions, and astigmatism, what recovery week by week actually looks like, and honest cost and financing breakdowns.", "Structure every post so Google can rank it for local, high-intent searches like \"LASIK surgeon in [your city]\" and \"LASIK cost near me,\" and so AI assistants can quote it cleanly when a candidate asks for a procedure comparison or a recommendation.", "Connect your content to your Google Business Profile and consult booking, so a reader who lands on \"Am I a candidate for LASIK?\" has an obvious next step toward scheduling a free evaluation with your practice.", "Keep candidacy, safety, and outcome language medically responsible and on-brand, written to reassure cautious patients rather than over-promise 20/20 vision or create compliance headaches for your surgeon."], "proof": "In one illustrative case, a single vision-correction practice's blog grew to roughly 3,847 organic visits a month and started getting named in AI assistant answers for local LASIK questions within about two quarters. Illustrative only. Individual results vary.", "faq": [{"q": "Will the content actually sound like a real eye surgeon wrote it, not generic AI filler?", "a": "Yes. We write in your practice's voice and keep candidacy, safety, and recovery claims medically responsible, with no over-promising of specific vision outcomes. The aim is content a cautious patient trusts and your surgeon would be comfortable putting their name on, and you review everything before it publishes."}, {"q": "How does this get my practice into ChatGPT and Google AI answers?", "a": "AI assistants pull from clear, well-structured, authoritative content. We publish articles that directly answer the questions LASIK shoppers ask AI, like procedure comparisons, candidacy, recovery, and cost, organized so assistants can cite them and tie the answer to your practice and location. We can't guarantee any assistant names you, but this is how you become eligible to be surfaced in those answers."}, {"q": "I already spend a lot on LASIK ads. How is this different?", "a": "Ads stop the moment you stop paying, and LASIK clicks are among the most expensive in healthcare. The blog we build is an asset that keeps earning visibility in Search and AI answers over time, designed to bring in candidates who've already done their research and are closer to booking a consult. Many practices use it to become less dependent on paid clicks, not to replace their judgment about ad spend overnight."}], "icon": "👁️", "fr": {"label": "LASIK et chirurgie de la vision", "complianceNote": "À titre informatif seulement; ne constitue pas un avis médical. L'admissibilité au LASIK, à la PRK, au SMILE ou à toute autre procédure de correction de la vision ne peut être établie que par un chirurgien oculaire autorisé, après un examen complet. Les résultats, la récupération et la vision finale varient d'une personne à l'autre et ne sont pas garantis.", "painPoints": ["Le LASIK est une décision irréversible de plusieurs milliers de dollars que les gens analysent pendant des mois. Vos clients potentiels lisent une douzaine d'articles et regardent toutes les vidéos du genre \"est-ce que c'est sécuritaire\" et \"quels sont les risques\" bien avant de vous appeler, et la majorité de cette recherche se fait sur les sites de vos concurrents, sur des agrégateurs et dans les réponses d'IA plutôt que chez vous.", "Quand quelqu'un demande à ChatGPT ou aux aperçus IA de Google \"LASIK vs PRK vs SMILE pour les yeux secs\" ou \"un chirurgien LASIK reconnu près de chez moi\", votre clinique ressort rarement. Ce sont les grandes chaînes nationales et les sites d'agrégateurs d'avis qui sont cités, pendant que l'expertise réelle de votre chirurgien reste invisible au moment précis où un candidat choisit à qui confier ses yeux.", "Votre budget se fait gruger par les annonces LASIK au coût par clic, parmi les mots-clés les plus chers de tout le secteur de la santé, et vous payez le gros prix pour des chercheurs d'aubaines et des gens qui ne sont finalement pas des candidats, au lieu de posséder du contenu qui inspire confiance et amène des consultations qualifiées longtemps après sa publication."], "exampleSearches": ["\"est-ce que le lasik en vaut la peine à 45 ans\" / \"lasik vs prk pour les yeux secs\" / \"meilleur chirurgien lasik près de chez moi avis\"", "\"combien coûte le lasik à [ville] avec financement\" / \"puis-je avoir le lasik avec astigmatisme et cornées minces\"", "Demandez à ChatGPT : \"J'ai 38 ans, je porte des lentilles cornéennes et j'ai une légère sécheresse oculaire. Devrais-je faire le LASIK, la PRK ou le SMILE, et quels sont les chirurgiens en correction de la vision les plus réputés dans ma région ?\""], "whatWeDo": ["Publier un flux constant d'articles révisés par un chirurgien sur les décisions que les vrais candidats au LASIK soupèsent : LASIK vs PRK vs SMILE, l'admissibilité avec des cornées minces, la sécheresse oculaire, les fortes prescriptions et l'astigmatisme, à quoi ressemble vraiment la récupération semaine après semaine, et des explications honnêtes sur les coûts et le financement.", "Structurer chaque article pour que Google puisse le faire ressortir pour des recherches locales à forte intention comme \"chirurgien LASIK à [votre ville]\" et \"coût du LASIK près de moi\", et pour que les assistants IA puissent le citer clairement quand un candidat demande une comparaison de procédures ou une recommandation.", "Relier votre contenu à votre fiche d'établissement Google et à votre prise de rendez-vous, afin qu'un lecteur qui atterrit sur \"Suis-je un bon candidat pour le LASIK ?\" ait une étape suivante évidente vers la prise d'une évaluation gratuite avec votre clinique.", "Garder le langage sur l'admissibilité, la sécurité et les résultats médicalement responsable et fidèle à votre image, rédigé pour rassurer les patients prudents plutôt que pour surpromettre une vision 20/20 ou créer des maux de tête de conformité pour votre chirurgien."], "headline": "Devenez la clinique LASIK que Google ET l'IA recommandent quand quelqu'un est enfin prêt à se débarrasser de ses lunettes", "subhead": "Nous rédigeons et publions un blogue continu, révisé par un chirurgien, qui répond aux questions exactes que les candidats à la correction de la vision tapent dans Google et posent à ChatGPT, pour que davantage de bons candidats trouvent votre clinique et réservent une consultation.", "proof": "Dans un cas à titre indicatif, le blogue d'une seule clinique de correction de la vision a grimpé à environ 3 847 visites organiques par mois et a commencé à être nommé dans les réponses d'assistants IA pour des questions LASIK locales en l'espace d'environ deux trimestres. À titre indicatif seulement. Les résultats individuels varient.", "faq": [{"q": "Est-ce que le contenu va vraiment sonner comme s'il était écrit par un vrai chirurgien oculaire, et non comme du remplissage générique généré par IA ?", "a": "Oui. Nous écrivons dans la voix de votre clinique et gardons les affirmations sur l'admissibilité, la sécurité et la récupération médicalement responsables, sans surpromettre de résultats visuels précis. Le but : un contenu qu'un patient prudent croit et que votre chirurgien serait à l'aise de signer de son nom, et vous révisez tout avant la publication."}, {"q": "Comment est-ce que ça fait entrer ma clinique dans les réponses de ChatGPT et des aperçus IA de Google ?", "a": "Les assistants IA puisent dans du contenu clair, bien structuré et fiable. Nous publions des articles qui répondent directement aux questions que les candidats au LASIK posent à l'IA, comme les comparaisons de procédures, l'admissibilité, la récupération et les coûts, organisés pour que les assistants puissent les citer et relier la réponse à votre clinique et à votre région. Nous ne pouvons pas garantir qu'un assistant vous nommera, mais c'est ainsi que vous devenez admissible à être mis de l'avant dans ces réponses."}, {"q": "Je dépense déjà beaucoup en annonces LASIK. En quoi est-ce différent ?", "a": "Les annonces s'arrêtent dès que vous cessez de payer, et les clics LASIK comptent parmi les plus chers du secteur de la santé. Le blogue que nous bâtissons est un actif qui continue de générer de la visibilité dans la recherche et les réponses d'IA au fil du temps, conçu pour attirer des candidats qui ont déjà fait leurs recherches et sont plus près de réserver une consultation. Beaucoup de cliniques s'en servent pour devenir moins dépendantes des clics payants, sans remplacer du jour au lendemain votre propre jugement sur les dépenses publicitaires."}]}}, {"id": "hvac-plumbing-electrical", "label": "HVAC, plumbing & electrical", "headline": "Be the home-service company Google AND AI send the next emergency call to", "subhead": "We write and publish an ongoing on-brand blog that helps your HVAC, plumbing, or electrical company show up in Google Search, Google Maps, and AI answers like ChatGPT and Gemini, then funnels those homeowners straight to your phone and booking.", "painPoints": ["You're stuck buying overpriced shared leads from Angi, Thumbtack, and the aggregators, paying for the same homeowner two other contractors already called, while your own name barely shows up when someone searches your service area.", "Your Google Business Profile sits below national franchises and pay-to-play Local Services Ads, so when a furnace quits at 9pm or a water heater floods a finished basement, the homeowner panic-searching for help never scrolls far enough to see you.", "You're great with a wrench and slammed all day. The site your nephew built in 2019 has three pages, no service-area or 'near me' content, and zero time exists between calls to write about AC repair, panel upgrades, or sewer backups."], "exampleSearches": ["emergency ac repair near me open now", "why does my breaker trip every time the dryer runs", "Ask ChatGPT: my water heater is leaking from the bottom, who should I call near me and what does it cost to replace?"], "whatWeDo": ["We publish service-specific, location-targeted articles that match how homeowners actually search in a panic: 'furnace blowing cold air', 'whole-home generator install cost', 'how often to flush a tankless water heater', each one pointing back to your booking and phone.", "We build out the city and neighborhood pages that compete for 'near me' and Google Maps visibility, so your company shows up across every town you actually run trucks to, not just the one your shop sits in.", "We structure every post so AI assistants can quote you: clear, accurate answers to the real questions homeowners ask ChatGPT, Gemini, and Perplexity about repairs, replacements, permits, and price ranges in your trade.", "We keep it on-brand and on-autopilot: licensed-trade-accurate content written and published for you every week, tied to your seasonal demand, AC and heat pumps in summer, heating and frozen pipes in winter, so you're never the quiet one online."], "proof": "In one illustrative case, a regional HVAC and plumbing company saw 1,213 more organic visits from local 'repair' and 'near me' searches over a single season, and their service pages began getting cited in AI answers for 47 of the questions homeowners ask before they ever call. Illustrative only; results vary.", "faq": [{"q": "I already pay for Angi and Google Local Services Ads. Why do I need this?", "a": "Those put you in a bidding war for shared leads that ring three other contractors at the same time. This builds an asset you own: content and local pages that keep ranking and getting recommended after you stop paying, so you lean less on rented leads every month."}, {"q": "Will this actually help me show up when someone's furnace or water heater dies at night?", "a": "That's exactly the intent we write for. We target the emergency and 'near me' searches homeowners type at the worst possible moment, and we structure pages so Google Maps and AI assistants can surface you fast. We can't promise a ranking, but everything is built and designed to get you found when the call is urgent."}, {"q": "I run service calls all day and have no time to write or approve content. How hands-off is this?", "a": "Almost completely. We learn your trade, your service area, and your voice up front, then write and publish on an ongoing schedule. You keep doing jobs. It's month-to-month, cancel anytime, with a 60-day money-back guarantee if it's not a fit."}], "complianceNote": "Month to month. Cancel anytime. 60-day money-back guarantee. Illustrative examples only; visibility and results vary by market, competition, and service area.", "icon": "🔧", "fr": {"label": "CVC, plomberie et électricité", "complianceNote": "De mois en mois. Annulez en tout temps. Garantie de remboursement de 60 jours. Exemples fournis à titre indicatif seulement; la visibilité et les résultats varient selon le marché, la concurrence et le territoire desservi.", "painPoints": ["Vous êtes coincé à acheter des prospects partagés hors de prix sur Angi, Thumbtack et les agrégateurs, à payer pour le même propriétaire que deux autres entrepreneurs ont déjà appelé, pendant que votre propre nom apparaît à peine quand quelqu'un cherche dans votre secteur.", "Votre fiche Google se retrouve sous les franchises nationales et les annonces de services locaux payantes; alors quand une fournaise lâche à 21 h ou qu'un chauffe-eau inonde un sous-sol fini, le propriétaire en panique qui cherche de l'aide ne descend jamais assez loin pour vous voir.", "Vous êtes un as avec une clé à molette et débordé toute la journée. Le site que votre neveu a monté en 2019 a trois pages, aucun contenu sur les secteurs desservis ni sur le « près de chez moi », et il ne reste zéro minute entre deux appels pour écrire sur la réparation de climatiseur, la mise à niveau de panneau ou les refoulements d'égout."], "exampleSearches": ["réparation climatiseur urgence près de moi ouvert maintenant", "pourquoi mon disjoncteur saute chaque fois que la sécheuse fonctionne", "Demandez à ChatGPT : mon chauffe-eau coule par le bas, qui devrais-je appeler près de chez moi et combien coûte le remplacement ?"], "whatWeDo": ["Nous publions des articles ciblés par service et par localité qui collent à la façon dont les propriétaires cherchent vraiment quand ils paniquent : « fournaise qui souffle de l'air froid », « coût d'installation d'une génératrice pour toute la maison », « à quelle fréquence rincer un chauffe-eau sans réservoir », chacun ramenant vers votre prise de rendez-vous et votre téléphone.", "Nous bâtissons les pages de villes et de quartiers qui se battent pour la visibilité « près de chez moi » et sur Google Maps, pour que votre entreprise apparaisse partout où vos camions roulent réellement, pas seulement dans la ville où se trouve votre atelier.", "Nous structurons chaque article pour que les assistants IA puissent vous citer : des réponses claires et exactes aux vraies questions que les propriétaires posent à ChatGPT, Gemini et Perplexity sur les réparations, les remplacements, les permis et les fourchettes de prix de votre métier.", "Nous gardons le tout fidèle à votre image et en mode pilote automatique : du contenu exact et conforme aux normes de votre métier réglementé, rédigé et publié pour vous chaque semaine, arrimé à votre demande saisonnière, climatisation et thermopompes l'été, chauffage et tuyaux gelés l'hiver, pour que vous ne soyez jamais le silencieux en ligne."], "headline": "Soyez l'entreprise de services à domicile vers qui Google ET l'IA dirigent le prochain appel d'urgence", "subhead": "Nous rédigeons et publions un blogue continu, fidèle à votre image, qui aide votre entreprise de CVC, de plomberie ou d'électricité à apparaître dans la recherche Google, sur Google Maps et dans les réponses IA comme ChatGPT et Gemini, puis dirige ces propriétaires directement vers votre téléphone et votre prise de rendez-vous.", "proof": "Dans un cas à titre indicatif, une entreprise régionale de CVC et de plomberie a vu 1 213 visites organiques de plus provenant de recherches locales de « réparation » et « près de chez moi » en une seule saison, et ses pages de services ont commencé à être citées dans les réponses IA pour 47 des questions que les propriétaires se posent avant même d'appeler. À titre indicatif seulement; les résultats varient.", "faq": [{"q": "Je paie déjà pour Angi et les annonces de services locaux Google. Pourquoi en aurais-je besoin ?", "a": "Ces plateformes vous placent dans une guerre d'enchères pour des prospects partagés qui sonnent chez trois autres entrepreneurs en même temps. Ici, on bâtit un actif qui vous appartient : du contenu et des pages locales qui continuent de bien se classer et d'être recommandés après que vous cessez de payer, pour que vous dépendiez de moins en moins de prospects loués chaque mois."}, {"q": "Est-ce que ça va vraiment m'aider à apparaître quand la fournaise ou le chauffe-eau de quelqu'un lâche en pleine nuit ?", "a": "C'est exactement l'intention pour laquelle on écrit. On cible les recherches d'urgence et de « près de chez moi » que les propriétaires tapent au pire moment possible, et on structure les pages pour que Google Maps et les assistants IA puissent vous faire ressortir rapidement. On ne peut pas promettre un classement, mais tout est conçu et bâti pour vous faire trouver quand l'appel est urgent."}, {"q": "Je fais des appels de service toute la journée et je n'ai pas le temps d'écrire ou d'approuver du contenu. C'est à quel point sans intervention de ma part ?", "a": "Presque entièrement. On apprend votre métier, votre territoire et votre ton dès le départ, puis on rédige et on publie selon un calendrier continu. Vous, vous continuez vos jobs. C'est de mois en mois, annulable en tout temps, avec une garantie de remboursement de 60 jours si ça ne convient pas."}]}}, {"id": "chiropractors", "label": "Chiropractors", "complianceNote": "Educational content only, not medical advice. We help your clinic get found by people already searching. We do not promise rankings, new-patient volume, or treatment outcomes. Individual results vary.", "headline": "Be the chiropractor Google and AI recommend when someone in your town is searching for relief", "subhead": "Vanta writes and publishes an ongoing, on-brand blog for your clinic that helps you show up in Google Search and Maps, gets your name surfaced inside ChatGPT, Gemini, and AI Overviews, and funnels that traffic straight to your Google profile and booking page. Done for you, every week.", "painPoints": ["You rank below the corporate \"wellness\" chains and a directory site you have never heard of, even though your reviews are stronger and you have been adjusting patients in town for years.", "Your last agency posted three thin \"benefits of chiropractic\" articles and went quiet, so your site reads stale and none of the things people in pain actually type, like sciatica relief or whiplash after a car accident, show up anywhere on it.", "Patients now ask ChatGPT and Google's AI \"which chiropractor near me should I see for my back,\" and you have no idea whether your clinic gets named, gets skipped, or never comes up at all."], "exampleSearches": ["chiropractor near me open saturday walk in", "best chiropractor for sciatica and lower back pain [city]", "Ask ChatGPT: I have sciatica and a desk job wrecking my posture, which chiropractor near me should I see, do they take walk-ins, and do they bill auto insurance after a car accident?"], "whatWeDo": ["We publish patient-focused content around what your community actually searches: sciatica and lower-back pain, auto-accident and whiplash care, pregnancy and pediatric adjustments, posture and \"tech neck,\" sports and overuse injuries, plus near-me and walk-in intent.", "We optimize your Google Business Profile and pin every article to your real service area and neighborhoods, so you surface in the Map Pack and in \"chiropractor near me\" results, not for a clinic three towns over.", "We structure each piece so AI assistants can read, trust, and name your clinic when someone asks for a recommendation, with clear detail on the conditions you treat, your hours, walk-in and insurance info, and how to book.", "We point all of it at one action, getting the patient to your Google profile, your reviews, and your booking link, and we report which topics and which queries are actually bringing people through the door."], "proof": "In one illustrative 90-day model of a single-location clinic, the site went from being named in 0 of 17 tracked AI assistant queries to being named in 6 of them, while the new blog drew an illustrative 1,213 local search visits the clinic had not been capturing before. Illustrative example only, individual results vary.", "faq": [{"q": "We already get most of our patients from word of mouth. Why do we need this?", "a": "Referrals are great, but they cap out and you cannot grow them on demand. The person who Googles \"chiropractor near me for sciatica\" at 11pm, or asks ChatGPT who to see after a car accident, has never heard of you. This is designed to make sure your clinic is the one that shows up when someone in pain is actively looking, not only when a friend happens to remember your name."}, {"q": "Will this read like spammy AI content or create compliance problems for the practice?", "a": "No. We write educational, patient-friendly content about conditions, what to expect at a first visit, and care for your community. We avoid treatment guarantees and outcome claims, so it stays clean for a medical practice. You approve the topics and can flag anything before it publishes."}, {"q": "How is showing up in ChatGPT or Google AI Overviews different from regular SEO?", "a": "Regular SEO gets you into the list of blue links. AI assistants do something different. They read content across the web and name a few specific clinics when someone asks for a recommendation. We structure your content and your service-area and booking details so the AI has clear, current reasons to mention you, then we point that interest at your Google Business Profile and booking link."}], "icon": "🦴", "fr": {"label": "Chiropraticiens", "complianceNote": "Contenu informatif seulement, pas un avis médical. Nous aidons votre clinique à être trouvée par les gens qui cherchent déjà. Nous ne promettons aucun classement, aucun volume de nouveaux patients ni aucun résultat de traitement. Les résultats varient d'une personne à l'autre.", "painPoints": ["Vous vous classez derrière les chaînes corporatives de \"mieux-être\" et un site d'annuaire dont vous n'avez jamais entendu parler, même si vos avis sont meilleurs et que vous ajustez des patients dans votre ville depuis des années.", "Votre dernière agence a publié trois articles minces sur les \"bienfaits de la chiropratique\" puis a disparu, alors votre site paraît dépassé et aucun des termes que les gens souffrants tapent vraiment, comme soulagement de la sciatique ou coup de fouet cervical après un accident de voiture, ne s'y trouve nulle part.", "Les patients demandent maintenant à ChatGPT et à l'IA de Google \"quel chiropraticien près de chez moi consulter pour mon dos\", et vous n'avez aucune idée si votre clinique est nommée, écartée, ou ne ressort tout simplement jamais."], "exampleSearches": ["chiropraticien près de moi ouvert samedi sans rendez-vous", "meilleur chiropraticien pour sciatique et douleur bas du dos [ville]", "Demandez à ChatGPT : j'ai une sciatique et un emploi de bureau qui ruine ma posture, quel chiropraticien près de chez moi devrais-je consulter, prennent-ils les sans rendez-vous, et facturent-ils à l'assurance auto après un accident de voiture ?"], "whatWeDo": ["Nous publions du contenu axé sur les patients autour de ce que votre communauté recherche vraiment : sciatique et douleur au bas du dos, soins après un accident de voiture et coup de fouet cervical, ajustements pendant la grossesse et en pédiatrie, posture et \"cou du texto\", blessures sportives et de surutilisation, en plus de l'intention près de moi et sans rendez-vous.", "Nous optimisons votre fiche Google Business et ancrons chaque article à votre vrai secteur de service et à vos quartiers, pour que vous ressortiez dans le bloc des cartes et dans les résultats \"chiropraticien près de moi\", pas pour une clinique à trois villes de là.", "Nous structurons chaque article pour que les assistants IA puissent lire, comprendre et nommer votre clinique quand quelqu'un demande une recommandation, avec des détails clairs sur les conditions que vous traitez, vos heures, les sans rendez-vous, les infos d'assurance et la façon de prendre rendez-vous.", "Nous dirigeons tout cela vers une seule action, amener le patient vers votre fiche Google, vos avis et votre lien de réservation, et nous vous indiquons quels sujets et quelles requêtes font vraiment entrer des gens par la porte."], "headline": "Soyez le chiropraticien que Google et l'IA recommandent quand quelqu'un dans votre ville cherche du soulagement", "subhead": "Vanta rédige et publie un blogue continu et fidèle à votre image pour votre clinique, qui vous aide à apparaître dans la recherche Google et dans Maps, fait ressortir votre nom dans ChatGPT, Gemini et les Aperçus IA, et canalise ce trafic directement vers votre fiche Google et votre page de réservation. Fait pour vous, chaque semaine.", "proof": "Dans un modèle à titre indicatif sur 90 jours d'une clinique à emplacement unique, le site est passé d'être nommé dans 0 des 17 requêtes d'assistants IA suivies à être nommé dans 6 d'entre elles, tandis que le nouveau blogue a attiré à titre indicatif 1 213 visites de recherche locale que la clinique ne captait pas auparavant. Exemple à titre indicatif seulement, les résultats varient d'une personne à l'autre.", "faq": [{"q": "Nous obtenons déjà la plupart de nos patients par le bouche-à-oreille. Pourquoi avons-nous besoin de ceci ?", "a": "Les références, c'est excellent, mais ça plafonne et vous ne pouvez pas les augmenter sur demande. La personne qui cherche \"chiropraticien près de moi pour sciatique\" à 23 h, ou qui demande à ChatGPT qui consulter après un accident de voiture, n'a jamais entendu parler de vous. Ceci est conçu pour que votre clinique soit celle qui ressort quand une personne souffrante cherche activement, pas seulement quand un ami se souvient par hasard de votre nom."}, {"q": "Est-ce que ça va avoir l'air de contenu IA bâclé ou créer des problèmes de conformité pour la clinique ?", "a": "Non. Nous rédigeons du contenu informatif et convivial pour les patients sur les conditions, ce à quoi s'attendre lors d'une première visite, et les soins offerts à votre communauté. Nous évitons les garanties de traitement et les promesses de résultats, alors ça reste irréprochable pour une clinique de santé. Vous approuvez les sujets et pouvez signaler tout élément avant la publication."}, {"q": "En quoi apparaître dans ChatGPT ou les Aperçus IA de Google diffère-t-il du référencement classique ?", "a": "Le référencement classique vous fait entrer dans la liste des liens bleus. Les assistants IA font quelque chose de différent. Ils lisent du contenu partout sur le web et nomment quelques cliniques précises quand quelqu'un demande une recommandation. Nous structurons votre contenu ainsi que vos détails de secteur de service et de réservation pour que l'IA ait des raisons claires et actuelles de vous mentionner, puis nous dirigeons cet intérêt vers votre fiche Google Business et votre lien de réservation."}]}}, {"id": "veterinary", "label": "Veterinary clinics", "headline": "Be the Vet Clinic Google and AI Recommend When a Pet Owner Needs Help Now", "subhead": "We write and publish an ongoing, on-brand blog that helps your clinic show up in Google Search and Maps, and gets you named when a worried owner asks ChatGPT, Gemini, or Google AI \"where do I take my dog near me.\" Then we point that traffic straight at your booking and your Google Business Profile.", "painPoints": ["The big corporate clinics, the Banfield-style chains, and the Chewy and PetMD articles outrank your own site for nearly every symptom a local owner types in, so the pet down the street ends up somewhere else.", "Your front desk burns hours on the same calls (\"is chocolate toxic,\" \"my cat keeps throwing up,\" \"how much is a spay\") that should be answered on your site and pulling those owners onto your schedule instead.", "Owners now ask ChatGPT or Google AI \"what vet should I take my puppy to for first shots\" and your clinic never comes up, while a competitor two neighborhoods over gets named in the answer."], "exampleSearches": ["emergency vet open now near me", "how much does it cost to neuter a cat in [city]", "Ask ChatGPT: My senior dog stopped eating and seems really lethargic. Should I see a vet, and which clinic near [city] is good with older dogs?"], "whatWeDo": ["Publish a steady stream of posts answering what owners in your area actually search, from \"puppy vaccine schedule\" to \"signs my cat is in pain\" to spay, neuter, and dental cost questions, each one routing the reader to book with you.", "Structure every post with the FAQ and local detail AI engines pull from, so assistants can name your clinic when an owner asks for care advice or a nearby recommendation.", "Build local-SEO pages around your services and neighborhoods (vaccines, wellness exams, dental, senior care, urgent visits) so you surface in Google Maps and the local pack for owners close to you.", "Keep everything in your clinic's voice and wire each article to your Google Business Profile and booking flow, so reading a post turns into a booked exam."], "proof": "Illustrative: one multi-doctor clinic saw 1,287 more organic blog visits in a quarter, with 214 of those readers reaching the \"book an appointment\" page. Illustrative only, individual results vary.", "faq": [{"q": "Will this bring in real local pet owners or just random traffic?", "a": "We target the searches owners near you actually make, things like \"puppy vaccines near [city]\" and \"vet that does dental cleanings,\" plus the questions people now put to AI assistants. The aim is nearby owners ready to book, not visitors three states away."}, {"q": "I don't have time to write or approve content every week. How much do you need from me?", "a": "Almost nothing after setup. We learn your services, your voice, and the cases you want more of, then write and publish on an ongoing schedule. Review every post if you like, or let it run. It's designed to take work off your front desk, not pile more on."}, {"q": "Is the medical info safe to publish under my clinic's name?", "a": "We write general, owner-friendly education and always point people to book an exam for any diagnosis or treatment, never replacing a vet visit. Nothing is framed as guaranteed advice, and you can flag any topic you'd rather we leave alone."}], "complianceNote": "Month to month. Cancel anytime. 60-day money-back guarantee. Content is general pet-care education and is not a substitute for a veterinary exam or diagnosis. Individual results vary and are not guaranteed.", "icon": "🐾", "fr": {"label": "Cliniques vétérinaires", "complianceNote": "De mois en mois. Annulez en tout temps. Garantie de remboursement de 60 jours. Le contenu est de l'information générale sur les soins aux animaux et ne remplace pas un examen ou un diagnostic vétérinaire. Les résultats varient d'un cas à l'autre et ne sont pas garantis.", "painPoints": ["Les grandes chaînes corporatives, les franchises de type Banfield et les articles de Chewy et PetMD se classent devant votre propre site pour presque chaque symptôme qu'un propriétaire de votre quartier tape dans Google, si bien que l'animal d'à côté finit ailleurs que chez vous.", "Votre réception perd des heures sur les mêmes appels (\"est-ce que le chocolat est toxique\", \"mon chat n'arrête pas de vomir\", \"combien coûte une stérilisation\") qui devraient trouver réponse sur votre site et amener ces propriétaires directement à votre horaire.", "Les propriétaires demandent maintenant à ChatGPT ou à Google AI \"chez quel vétérinaire amener mon chiot pour ses premiers vaccins\" et votre clinique ne ressort jamais, pendant qu'un concurrent à deux quartiers de là se fait nommer dans la réponse."], "exampleSearches": ["vétérinaire d'urgence ouvert maintenant près de moi", "combien coûte la stérilisation d'un chat à [ville]", "Demandez à ChatGPT : Mon vieux chien a arrêté de manger et semble vraiment amorphe. Devrais-je consulter un vétérinaire, et quelle clinique près de [ville] est bonne avec les chiens âgés ?"], "whatWeDo": ["Publier un flux régulier d'articles qui répondent à ce que les propriétaires de votre secteur cherchent vraiment, du \"calendrier de vaccination du chiot\" aux \"signes que mon chat souffre\" jusqu'aux questions de coût de stérilisation, de castration et de soins dentaires, chacun dirigeant le lecteur vers une prise de rendez-vous chez vous.", "Structurer chaque article avec la FAQ et les détails locaux que les moteurs d'IA vont chercher, pour que les assistants puissent nommer votre clinique quand un propriétaire demande un conseil de soin ou une recommandation à proximité.", "Bâtir des pages de référencement local autour de vos services et de vos quartiers (vaccins, examens de santé, soins dentaires, soins gériatriques, visites urgentes) pour que vous ressortiez dans Google Maps et le bloc local auprès des propriétaires tout près de vous.", "Garder le tout dans la voix de votre clinique et relier chaque article à votre fiche d'établissement Google et à votre flux de réservation, pour que la lecture d'un article se transforme en examen réservé."], "headline": "Soyez la clinique vétérinaire que Google et l'IA recommandent quand un propriétaire d'animal a besoin d'aide maintenant", "subhead": "Nous rédigeons et publions un blogue continu, fidèle à votre marque, qui aide votre clinique à apparaître dans la recherche Google et dans Maps, et qui vous fait nommer quand un propriétaire inquiet demande à ChatGPT, à Gemini ou à Google AI \"où amener mon chien près de moi\". Ensuite, nous dirigeons ce trafic directement vers votre réservation et votre fiche d'établissement Google.", "proof": "À titre indicatif : une clinique à plusieurs vétérinaires a vu 1 287 visites organiques de plus sur son blogue en un trimestre, dont 214 de ces lecteurs ont atteint la page \"prendre rendez-vous\". À titre indicatif seulement, les résultats varient d'un cas à l'autre.", "faq": [{"q": "Est-ce que ça va amener de vrais propriétaires d'animaux du coin ou juste du trafic au hasard ?", "a": "Nous ciblons les recherches que les propriétaires près de chez vous font réellement, des choses comme \"vaccins de chiot près de [ville]\" et \"vétérinaire qui fait des détartrages\", en plus des questions que les gens posent maintenant aux assistants IA. L'objectif, ce sont des propriétaires du coin prêts à réserver, pas des visiteurs à trois provinces de distance."}, {"q": "Je n'ai pas le temps de rédiger ou d'approuver du contenu chaque semaine. De quoi avez-vous besoin de ma part ?", "a": "Presque rien après la mise en place. Nous apprenons vos services, votre voix et les cas que vous voulez voir plus souvent, puis nous rédigeons et publions selon un calendrier continu. Révisez chaque article si vous le souhaitez, ou laissez aller. C'est conçu pour enlever du travail à votre réception, pas pour en ajouter."}, {"q": "Est-ce que l'information médicale est sécuritaire à publier sous le nom de ma clinique ?", "a": "Nous rédigeons de l'information générale et accessible pour les propriétaires, et nous renvoyons toujours les gens à prendre rendez-vous pour tout diagnostic ou traitement, sans jamais remplacer une visite chez le vétérinaire. Rien n'est présenté comme un conseil garanti, et vous pouvez signaler tout sujet que vous préférez qu'on laisse de côté."}]}}, {"id": "restaurants", "label": "Restaurants", "headline": "Be the Restaurant Google and AI Recommend When Someone Nearby Is Deciding Where to Eat", "subhead": "We write and publish an ongoing on-brand blog that helps your restaurant show up in Google Search, Google Maps, and inside AI answers like ChatGPT and Gemini. So when a hungry person nearby is choosing a place tonight, your name is in the conversation.", "painPoints": ["You hand a cut of every order to delivery apps and third-party listings that own your customers, then watch the big chains outspend you to the top of the same results.", "Your food is better and your reviews are honest, but you still sit below places on Google Maps that are just louder online, not actually worth the drive.", "Some nights the floor is slammed and some nights it is dead, and you have no time to blog, post, or wrestle the algorithm while you are running a kitchen and a dining room."], "exampleSearches": ["best brunch near me open now", "where to eat with a big group downtown with gluten free options", "Ask ChatGPT: I'm in town one night and want a cozy Italian place near my hotel that takes reservations, where should I go?"], "whatWeDo": ["We publish posts built around how diners actually search, like \"best patio dinner in [your neighborhood]\", \"where to take a date for [your cuisine]\", and \"open late near [nearby landmark]\", so you catch people at the exact moment they are picking a spot.", "We write the clear, current content AI assistants pull from when someone asks ChatGPT, Gemini, or Perplexity where to eat nearby, so your restaurant is more likely to get named in the answer instead of skipped.", "We tie every post back to your Google Business Profile, menu, hours, and your reservation or order link, so a casual search turns into a table booked or a pickup placed directly with you.", "We keep your blog publishing consistently in your restaurant's own voice, covering new menu items, seasonal dishes, events, and your story, with effectively zero work on your end."], "proof": "In one illustrative case, a single-location neighborhood bistro saw 1,742 more annual visits to its Google Business Profile from \"near me\" and AI-driven searches after about six months of consistent publishing. Illustrative example. Individual results vary.", "faq": [{"q": "I already pay for delivery apps and run some social media. Why do I need this too?", "a": "Delivery apps rent you customers and skim a cut every time. Social posts vanish in a day. This builds something you actually own: content tied to your own Google profile and website that keeps working months later and pulls in people searching with real intent, the ones ready to book a table or place a pickup order straight with you."}, {"q": "How does the AI part actually help a restaurant?", "a": "More diners now ask ChatGPT, Gemini, and Google's AI \"where should I eat near here\" instead of scrolling a long list. Those assistants answer by pulling from clear, current content about local spots. We create that content about your restaurant, your dishes, your hours, and your neighborhood, so you are more likely to be the place the AI names."}, {"q": "I run a busy kitchen. How much work is this for me?", "a": "Almost none. After a short kickoff to capture your voice, your menu, and what makes your place yours, we handle the writing and publishing on an ongoing basis. Review every post if you like, or just let it run. It is month to month, cancel anytime, with a 60-day money-back guarantee."}], "complianceNote": "Month to month. Cancel anytime, plus a 60-day money-back guarantee. Results vary by location, cuisine, and competition, and are not guaranteed.", "icon": "🍽️", "fr": {"label": "Restaurants", "complianceNote": "De mois en mois. Annulez en tout temps, avec une garantie de remboursement de 60 jours. Les résultats varient selon l'emplacement, le type de cuisine et la concurrence, et ne sont pas garantis.", "painPoints": ["Vous cédez une part de chaque commande aux applications de livraison et aux annuaires tiers qui possèdent vos clients, puis vous regardez les grandes chaînes dépenser plus que vous pour trôner en tête des mêmes résultats.", "Votre bouffe est meilleure et vos avis sont honnêtes, mais vous vous retrouvez quand même sous des adresses qui font juste plus de bruit en ligne sur Google Maps, sans valoir le déplacement.", "Certains soirs la salle déborde et d'autres c'est mort, et vous n'avez pas une minute pour bloguer, publier ou vous battre avec l'algorithme pendant que vous gérez la cuisine et la salle à manger."], "exampleSearches": ["meilleur brunch près de moi ouvert maintenant", "où manger en grand groupe au centre-ville avec des options sans gluten", "Demandez à ChatGPT : je suis de passage en ville pour une soirée et je cherche un petit resto italien chaleureux près de mon hôtel qui prend les réservations, où devrais-je aller?"], "whatWeDo": ["On publie des articles bâtis autour de la façon dont les clients cherchent vraiment, comme \"meilleure terrasse pour souper dans [votre quartier]\", \"où aller en date pour de la [votre cuisine]\" et \"ouvert tard près de [point de repère à proximité]\", pour vous capter au moment exact où les gens choisissent une place.", "On rédige le contenu clair et à jour dans lequel les assistants IA puisent quand quelqu'un demande à ChatGPT, Gemini ou Perplexity où manger dans le coin, pour que votre restaurant ait plus de chances d'être nommé dans la réponse plutôt qu'ignoré.", "On relie chaque article à votre fiche Google Business, votre menu, vos heures et votre lien de réservation ou de commande, pour qu'une simple recherche se transforme en table réservée ou en commande pour emporter passée directement chez vous.", "On garde votre blogue actif de façon constante dans la voix propre à votre restaurant, en couvrant les nouveautés au menu, les plats de saison, les événements et votre histoire, avec pratiquement aucun effort de votre côté."], "headline": "Soyez le restaurant que Google et l'IA recommandent quand quelqu'un du coin décide où manger", "subhead": "On rédige et on publie un blogue continu, fidèle à votre marque, qui aide votre restaurant à sortir dans la recherche Google, sur Google Maps et au cœur des réponses IA comme ChatGPT et Gemini. Comme ça, quand une personne affamée du coin choisit une place ce soir, votre nom fait partie de la conversation.", "proof": "Dans un cas à titre indicatif, un bistro de quartier à emplacement unique a vu 1 742 visites annuelles de plus sur sa fiche Google Business, provenant de recherches \"près de moi\" et propulsées par l'IA, après environ six mois de publication constante. Exemple à titre indicatif. Les résultats individuels varient.", "faq": [{"q": "Je paie déjà pour des applications de livraison et je fais un peu de réseaux sociaux. Pourquoi aurais-je besoin de ça aussi?", "a": "Les applications de livraison vous louent des clients et grugent une part à chaque fois. Les publications sociales disparaissent en une journée. Ceci bâtit quelque chose que vous possédez vraiment : du contenu relié à votre propre fiche Google et à votre site web, qui continue de travailler des mois plus tard et qui attire des gens qui cherchent avec une vraie intention, ceux qui sont prêts à réserver une table ou à passer une commande pour emporter directement chez vous."}, {"q": "Concrètement, comment la partie IA aide-t-elle un restaurant?", "a": "De plus en plus de clients demandent maintenant à ChatGPT, à Gemini et à l'IA de Google \"où devrais-je manger dans le coin\" au lieu de faire défiler une longue liste. Ces assistants répondent en puisant dans du contenu clair et à jour sur les adresses locales. On crée ce contenu sur votre restaurant, vos plats, vos heures et votre quartier, pour que vous ayez plus de chances d'être la place que l'IA nomme."}, {"q": "Je gère une cuisine occupée. Combien de travail ça me demande?", "a": "Presque rien. Après un court démarrage pour capter votre voix, votre menu et ce qui rend votre place unique, on s'occupe de la rédaction et de la publication de façon continue. Révisez chaque article si vous voulez, ou laissez simplement rouler. C'est de mois en mois, annulable en tout temps, avec une garantie de remboursement de 60 jours."}]}}]};